window.MASTERY_OS = {"courseLabel":"BIO 004 Human Anatomy","units":[{"id":"m-muscle","name":"Muscle","days":["Mon","Tue"]},{"id":"m-lymphatic","name":"Lymphatic","days":["Wed"]},{"id":"m-blood","name":"Blood","days":["Thu"]}],"competencies":[{"id":"m-muscle::types","name":"The three muscle tissue types","unit":"m-muscle","day":"Mon","study":["g1","g2","g3","g4","g5","g6","g7","g8","g9","g10","g20","g21","g22","g35","g38"],"assess":["g19","g31","g32"]},{"id":"m-muscle::properties","name":"Properties of muscle tissue","unit":"m-muscle","day":"Mon","study":["g12","g13","g14","g15","g26","g29"],"assess":["g11","g25","g33"]},{"id":"m-muscle::functions","name":"Functions of muscle tissue","unit":"m-muscle","day":"Mon","study":["g16","g17","g18"],"assess":["g28","g34","g36"]},{"id":"m-muscle::terminology","name":"Muscle terminology (myo, sarco)","unit":"m-muscle","day":"Mon","study":["g24","g30","g37"],"assess":["g23","g27"]},{"id":"m-muscle::gross-anatomy","name":"Gross anatomy: nerve & blood supply","unit":"m-muscle","day":"Mon","study":["g40","g56","g65"],"assess":["g39","g73"]},{"id":"m-muscle::attachments","name":"Muscle attachments (origin, insertion)","unit":"m-muscle","day":"Tue","study":["g41","g42","g43","g44","g52","g53","g54","g55","g59","g60","g62","g63","g67","g68","g74"],"assess":["g61","g71","g75"]},{"id":"m-muscle::ct-sheaths","name":"Connective tissue sheaths","unit":"m-muscle","day":"Mon","study":["g45","g46","g47","g48","g49","g50","g51","g58","g64","g66","g72","g76"],"assess":["g57","g69","g70"]},{"id":"m-muscle::naming","name":"How muscles are named","unit":"m-muscle","day":"Tue","study":["g77","g78","g79","g80","g81","g82","g83","g84","g85","g86","g87","g101","g102","g104","g116"],"assess":["g100","g103","g112"]},{"id":"m-muscle::levers","name":"Lever systems","unit":"m-muscle","day":"Tue","study":["g88","g89","g90","g91","g92","g93","g94","g107","g109","g110","g113","g118"],"assess":["g105","g106","g117"]},{"id":"m-muscle::coordination","name":"Muscle coordination roles","unit":"m-muscle","day":"Tue","study":["g95","g96","g97","g98","g99","g111","g114"],"assess":["g108","g115","g119"]},{"id":"m-muscle::microanatomy","name":"Skeletal muscle fiber microanatomy","unit":"m-muscle","day":"Mon","study":["g120","g121","g122","g123","g124","g125","g126","g127","g137","g138","g142","g146","g153","g154","g155"],"assess":["g136","g141","g149"]},{"id":"m-muscle::sr-ttubules","name":"SR, T-tubules & the triad","unit":"m-muscle","day":"Mon","study":["g128","g129","g130","g131","g132","g133","g134","g135","g139","g140","g143","g144","g145","g147","g150"],"assess":["g148","g151","g152"]},{"id":"m-muscle::sarcomere","name":"Sarcomere bands & lines","unit":"m-muscle","day":"Mon","study":["g156","g157","g158","g159","g160","g161","g162","g163","g164","g188","g191"],"assess":["g180","g181","g192"]},{"id":"m-muscle::filaments","name":"Myofilaments (thick, thin, elastic)","unit":"m-muscle","day":"Mon","study":["g165","g167","g168","g169","g170","g186","g196"],"assess":["g166","g182","g199"]},{"id":"m-muscle::proteins","name":"Contractile & regulatory proteins","unit":"m-muscle","day":"Mon","study":["g171","g172","g173","g174","g175","g176","g177","g178","g179","g183","g185","g187","g189","g190","g193","g194","g197"],"assess":["g184","g195","g198"]},{"id":"m-lymphatic::overview","name":"Lymphatic system overview","unit":"m-lymphatic","day":"Wed","study":["g200","g205","g206","g225","g230","g238","g239"],"assess":["g223","g224","g233"]},{"id":"m-lymphatic::lymph","name":"Lymph & interstitial fluid","unit":"m-lymphatic","day":"Wed","study":["g201","g202","g240"],"assess":["g216","g217"]},{"id":"m-lymphatic::lacteals","name":"Lacteals & chyle","unit":"m-lymphatic","day":"Wed","study":["g203","g204","g210","g218","g232","g235"],"assess":["g227","g237"]},{"id":"m-lymphatic::capillaries","name":"Lymphatic capillaries","unit":"m-lymphatic","day":"Wed","study":["g207","g208","g209","g211","g212","g213","g219","g220","g221","g236"],"assess":["g226","g228","g229"]},{"id":"m-lymphatic::vessels-valves","name":"Lymphatic vessels & valves","unit":"m-lymphatic","day":"Wed","study":["g214","g215","g234"],"assess":["g222","g231"]},{"id":"m-lymphatic::trunks","name":"Lymph trunks","unit":"m-lymphatic","day":"Wed","study":["g241","g242","g243","g244","g245","g246","g257","g258","g259","g260","g261"],"assess":["g269","g271","g278"]},{"id":"m-lymphatic::ducts","name":"Thoracic & right lymphatic ducts","unit":"m-lymphatic","day":"Wed","study":["g247","g248","g249","g250","g251","g252","g253","g262","g263","g264","g272","g273","g274","g276","g277","g279","g280"],"assess":["g267","g268","g270"]},{"id":"m-lymphatic::pumps","name":"Lymph pumps","unit":"m-lymphatic","day":"Wed","study":["g254","g255","g256","g266","g281"],"assess":["g265","g275"]},{"id":"m-lymphatic::red-marrow","name":"Red bone marrow","unit":"m-lymphatic","day":"Wed","study":["g282","g283","g284","g285","g286","g321","g322"],"assess":["g299","g313","g314"]},{"id":"m-lymphatic::thymus","name":"Thymus structure","unit":"m-lymphatic","day":"Wed","study":["g287","g288","g289","g290","g291","g292","g293","g294","g295","g296","g297","g298","g300","g301","g302","g303","g304","g305","g309","g310","g311","g312","g315","g316","g317","g318","g319","g320"],"assess":["g306","g307","g308"]},{"id":"m-lymphatic::lymph-nodes","name":"Lymph node structure","unit":"m-lymphatic","day":"Wed","study":["g323","g324","g325","g326","g327","g328","g329","g330","g331","g332","g333","g341","g342","g343","g344","g349","g354","g355","g356","g360","g362"],"assess":["g350","g352","g357"]},{"id":"m-lymphatic::spleen","name":"Spleen (red & white pulp)","unit":"m-lymphatic","day":"Wed","study":["g334","g335","g336","g337","g338","g339","g340","g346","g347","g348","g358","g359","g361","g363"],"assess":["g345","g351","g353"]},{"id":"m-lymphatic::malt","name":"MALT","unit":"m-lymphatic","day":"Wed","study":["g364","g365","g366","g367","g375","g380","g384","g389","g396","g397","g400","g403"],"assess":["g383","g388","g393"]},{"id":"m-lymphatic::tonsils","name":"Tonsils","unit":"m-lymphatic","day":"Wed","study":["g368","g369","g370","g371","g372","g373","g374","g376","g377","g378","g379","g386","g387","g390","g391","g392","g394","g395","g398","g399","g401","g402","g404"],"assess":["g381","g382","g385"]},{"id":"m-blood::overview","name":"Blood as a connective tissue","unit":"m-blood","day":"Thu","study":["g405","g406","g409","g411","g412","g413","g414","g415","g416","g417","g418"],"assess":["g407","g408","g419"]},{"id":"m-blood::plasma","name":"Plasma composition","unit":"m-blood","day":"Thu","study":["g420","g421","g434","g435","g436","g437"],"assess":["g410","g438","g439"]},{"id":"m-blood::plasma-proteins","name":"Plasma proteins","unit":"m-blood","day":"Thu","study":["g422","g423","g424","g425","g426","g427","g429","g430","g431","g432","g433"],"assess":["g428","g440","g441"]},{"id":"m-blood::erythrocytes","name":"Erythrocyte structure","unit":"m-blood","day":"Thu","study":["g442","g443","g444","g446","g447","g449"],"assess":["g445","g448","g476"]},{"id":"m-blood::hemoglobin","name":"Hemoglobin structure","unit":"m-blood","day":"Thu","study":["g450","g451","g452","g453","g454","g455","g457","g458","g459","g460","g461","g462"],"assess":["g456","g477","g479"]},{"id":"m-blood::values","name":"Normal blood values","unit":"m-blood","day":"Thu","study":["g464","g465","g466","g493","g546","g550"],"assess":["g463","g467"]},{"id":"m-blood::rbc-lifecycle","name":"RBC lifecycle & iron","unit":"m-blood","day":"Thu","study":["g469","g471","g472","g473","g474","g475"],"assess":["g468","g470","g478"]},{"id":"m-blood::hematopoiesis","name":"Hematopoiesis","unit":"m-blood","day":"Thu","study":["g480","g481","g482","g483","g484","g485","g486","g487","g488","g489","g490","g491","g492","g494","g495","g496","g497","g498","g499","g500","g501","g502","g503","g504","g508","g509","g510","g511","g512","g513","g514","g515"],"assess":["g505","g506","g507"]},{"id":"m-blood::granulocytes","name":"Granulocytes","unit":"m-blood","day":"Thu","study":["g516","g517","g519","g520","g522","g523","g524","g525","g527","g528","g529","g539","g540","g541"],"assess":["g521","g526","g551"]},{"id":"m-blood::agranulocytes","name":"Agranulocytes","unit":"m-blood","day":"Thu","study":["g518","g530","g531","g532","g533","g535","g536","g537","g538","g542"],"assess":["g534","g552","g554"]},{"id":"m-blood::platelets","name":"Platelets","unit":"m-blood","day":"Thu","study":["g543","g544","g545","g547"],"assess":["g548","g549","g553"]},{"id":"m-blood::blood-groups","name":"Blood groups & typing","unit":"m-blood","day":"Thu","study":["g555","g556","g557","g558","g559","g560","g561","g562","g563","g564","g565","g566","g567","g568","g569","g570","g571","g575","g594"],"assess":["g572","g573","g574"]},{"id":"m-blood::disorders","name":"Structural blood disorders","unit":"m-blood","day":"Thu","study":["g576","g577","g578","g579","g580","g581","g582","g583","g584","g585","g586","g587","g588","g589","g590"],"assess":["g591","g592","g593"]}],"cards":[{"id":"c1","dok":1,"q":"Which three types of muscle tissue are found in the body?","a":"Skeletal, cardiac, and smooth muscle.","options":["Skeletal, cardiac, and smooth","Striated, voluntary, and involuntary","Skeletal, visceral, and connective","Fast, slow, and intermediate"],"correctIndex":0,"explanation":"The three muscle tissue types are skeletal, cardiac, and smooth. Striated/voluntary/involuntary are descriptive characteristics, not the three named tissue types. Connective tissue is not a muscle type. Fast, slow, and intermediate describe fiber speeds, not tissue types.","tags":["muscular","types"],"gid":"g1","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c2","dok":1,"q":"Which muscle tissue type covers the bony skeleton and is described as striated and voluntary?","a":"Skeletal muscle.","options":["Cardiac muscle","Smooth muscle","Skeletal muscle","Visceral muscle"],"correctIndex":2,"explanation":"Skeletal muscle covers the bony skeleton and is striated and voluntary. Cardiac muscle is striated but involuntary. Smooth muscle is nonstriated and involuntary. Visceral is another name for smooth muscle, which is not voluntary.","tags":["muscular","types"],"gid":"g2","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c3","dok":1,"q":"Name the two main structural features to remember about skeletal muscle tissue.","a":"It is striated and voluntary.","tags":["muscular","types"],"rubric":["Striated","Voluntary"],"gid":"g3","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c4","dok":1,"q":"Which muscle tissue makes up the bulk of the heart walls?","a":"Cardiac muscle.","options":["Skeletal muscle","Cardiac muscle","Smooth muscle","Elastic muscle"],"correctIndex":1,"explanation":"Cardiac muscle makes up the bulk of the heart walls. Skeletal muscle covers the bony skeleton. Smooth muscle lines hollow visceral organs. Elastic muscle is not a muscle tissue type.","tags":["muscular","types"],"gid":"g4","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c5","dok":1,"q":"What are the two cell junctions found within the intercalated discs of cardiac muscle?","a":"Desmosomes and gap junctions.","tags":["muscular","types"],"rubric":["Desmosomes","Gap junctions"],"gid":"g5","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c6","dok":1,"q":"Which structural feature is unique to cardiac muscle and joins its cells end to end?","a":"Intercalated discs.","options":["Striations","Intercalated discs","Terminal cisterns","Fascicles"],"correctIndex":1,"explanation":"Intercalated discs are unique to cardiac muscle and join its cells end to end. Striations are shared with skeletal muscle. Terminal cisterns are part of the sarcoplasmic reticulum. Fascicles are bundles of fibers found in skeletal muscle.","tags":["muscular","types"],"gid":"g6","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c7","dok":1,"q":"Which muscle tissue is found in the walls of hollow visceral organs such as the stomach, urinary bladder, and blood vessels?","a":"Smooth muscle.","options":["Skeletal muscle","Cardiac muscle","Smooth muscle","Striated muscle"],"correctIndex":2,"explanation":"Smooth muscle lines the walls of hollow visceral organs. Skeletal muscle covers the skeleton. Cardiac muscle is in the heart walls. Striated muscle refers to skeletal or cardiac, not the visceral wall muscle.","tags":["muscular","types"],"gid":"g7","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c8","dok":1,"q":"What is the characteristic cell shape of smooth muscle?","a":"Elongated and spindle shaped.","tags":["muscular","types"],"rubric":["Elongated","Spindle shaped"],"gid":"g8","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c9","dok":1,"q":"Which muscle tissue type lacks striations?","a":"Smooth muscle.","options":["Skeletal muscle","Cardiac muscle","Smooth muscle","Both skeletal and cardiac"],"correctIndex":2,"explanation":"Smooth muscle lacks striations because its filaments are not arranged in ordered sarcomeres. Skeletal muscle is striated. Cardiac muscle is striated. Skeletal and cardiac are both striated, so that pairing is wrong.","tags":["muscular","types"],"gid":"g9","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c10","dok":1,"q":"How many nuclei does a smooth muscle cell contain, and what is its shape?","a":"A single flat nucleus per cell.","tags":["muscular","types"],"rubric":["Single nucleus","Flat shape"],"gid":"g10","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c11","dok":1,"q":"Which muscle property is defined as the ability to receive and respond to a stimulus by changing the membrane potential?","a":"Excitability (responsiveness).","options":["Contractility","Excitability","Extensibility","Elasticity"],"correctIndex":1,"explanation":"Excitability, also called responsiveness, is the ability to receive and respond to a stimulus by changing the membrane potential. Contractility is the ability to shorten forcibly. Extensibility is the ability to stretch. Elasticity is the ability to recoil to resting length.","tags":["muscular","properties"],"gid":"g11","unit":"m-muscle","comp":"m-muscle::properties","assess":true},{"id":"c12","dok":1,"q":"Which muscle property is the ability to shorten forcibly when stimulated, and is the property that sets muscle apart from other tissues?","a":"Contractility.","options":["Excitability","Contractility","Extensibility","Elasticity"],"correctIndex":1,"explanation":"Contractility is the ability to shorten forcibly when stimulated and is the property that distinguishes muscle from other tissues. Excitability is responsiveness to a stimulus. Extensibility is the ability to stretch. Elasticity is the ability to recoil.","tags":["muscular","properties"],"gid":"g12","unit":"m-muscle","comp":"m-muscle::properties"},{"id":"c13","dok":1,"q":"Which muscle property is the ability to extend or stretch beyond resting length?","a":"Extensibility.","options":["Excitability","Contractility","Extensibility","Elasticity"],"correctIndex":2,"explanation":"Extensibility is the ability to stretch beyond resting length when relaxed. Excitability is responsiveness. Contractility is forcible shortening. Elasticity is recoil to resting length after stretching.","tags":["muscular","properties"],"gid":"g13","unit":"m-muscle","comp":"m-muscle::properties"},{"id":"c14","dok":1,"q":"Which muscle property lets a muscle recoil and resume its resting length after being stretched?","a":"Elasticity.","options":["Extensibility","Elasticity","Contractility","Excitability"],"correctIndex":1,"explanation":"Elasticity is the ability to recoil and return to resting length after stretching. Extensibility is the ability to stretch in the first place. Contractility is forcible shortening. Excitability is the response to a stimulus.","tags":["muscular","properties"],"gid":"g14","unit":"m-muscle","comp":"m-muscle::properties"},{"id":"c15","dok":1,"q":"Name the four functional properties of muscle tissue.","a":"Excitability, contractility, extensibility, and elasticity.","tags":["muscular","properties"],"rubric":["Excitability","Contractility","Extensibility","Elasticity"],"gid":"g15","unit":"m-muscle","comp":"m-muscle::properties"},{"id":"c16","dok":1,"q":"List the four general functions of muscle tissue.","a":"Production of movement, maintenance of posture and body position, stabilization of joints, and generation of heat.","tags":["muscular","functions"],"rubric":["Production of movement","Maintenance of posture","Stabilization of joints","Generation of heat"],"gid":"g16","unit":"m-muscle","comp":"m-muscle::functions"},{"id":"c17","dok":1,"q":"Which muscle tissue function keeps the body upright and holds body position while the muscle is continuously working?","a":"Maintenance of posture and body position.","options":["Production of movement","Maintenance of posture and body position","Generation of heat","Stabilization of joints"],"correctIndex":1,"explanation":"Maintenance of posture and body position is the function that holds the body upright through continuous low-level muscle activity. Production of movement covers locomotion and manipulation. Generation of heat is a byproduct of contraction. Stabilization of joints reinforces articulations.","tags":["muscular","functions"],"gid":"g17","unit":"m-muscle","comp":"m-muscle::functions"},{"id":"c18","dok":1,"q":"Which muscle tissue function is a byproduct of contraction that helps maintain normal body temperature?","a":"Generation of heat.","options":["Production of movement","Generation of heat","Maintenance of posture","Stabilization of joints"],"correctIndex":1,"explanation":"Generation of heat is a byproduct of contraction that helps maintain normal body temperature. Production of movement is the direct output of contraction. Maintenance of posture holds body position. Stabilization of joints reinforces articulations.","tags":["muscular","functions"],"gid":"g18","unit":"m-muscle","comp":"m-muscle::functions"},{"id":"c19","dok":2,"q":"A striated muscle tissue that contracts without conscious control and contains intercalated discs is which type?","a":"Cardiac muscle.","options":["Skeletal muscle","Cardiac muscle","Smooth muscle","Visceral striated muscle"],"correctIndex":1,"explanation":"Cardiac muscle is striated, involuntary, and uniquely contains intercalated discs. Skeletal muscle is striated but voluntary and lacks intercalated discs. Smooth muscle is nonstriated. There is no muscle type called visceral striated muscle.","tags":["muscular","types"],"gid":"g19","unit":"m-muscle","comp":"m-muscle::types","assess":true},{"id":"c20","dok":2,"q":"A muscle tissue is described as nonstriated, involuntary, with spindle-shaped cells and single flat nuclei. Which type is it?","a":"Smooth muscle.","options":["Skeletal muscle","Cardiac muscle","Smooth muscle","Striated muscle"],"correctIndex":2,"explanation":"Nonstriated, involuntary tissue with spindle-shaped cells and single flat nuclei is smooth muscle. Skeletal muscle is striated with peripheral multiple nuclei. Cardiac muscle is striated with central nuclei and intercalated discs. Striated muscle would be skeletal or cardiac, both of which are striated.","tags":["muscular","types"],"gid":"g20","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c21","dok":2,"q":"Which muscle tissue type has the longest cells?","a":"Skeletal muscle.","options":["Cardiac muscle","Smooth muscle","Skeletal muscle","All three are equal in length"],"correctIndex":2,"explanation":"Skeletal muscle has the longest cells of the three types. Cardiac cells are shorter and branched. Smooth muscle cells are short and spindle shaped. The three types are not equal in length.","tags":["muscular","types"],"gid":"g21","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c22","dok":2,"q":"Compared with skeletal muscle, how do the striation and control features of smooth muscle differ?","a":"Smooth muscle is nonstriated and involuntary, while skeletal muscle is striated and voluntary.","tags":["muscular","types"],"rubric":["Smooth: nonstriated and involuntary","Skeletal: striated and voluntary"],"gid":"g22","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c23","dok":2,"q":"The word roots myo and mys both refer to what?","a":"Muscle.","options":["Flesh","Muscle","Cell","Fiber"],"correctIndex":1,"explanation":"The prefixes myo and mys both mean muscle. The prefix sarco means flesh. Cell and fiber are not the meanings of these roots.","tags":["muscular","terminology"],"gid":"g23","unit":"m-muscle","comp":"m-muscle::terminology","assess":true},{"id":"c24","dok":2,"q":"The prefix sarco means flesh. Which two muscle-cell structures use this prefix, and what do they name?","a":"Sarcoplasm (muscle cell cytoplasm) and sarcolemma (muscle cell plasma membrane).","tags":["muscular","terminology"],"rubric":["Sarcoplasm (muscle cell cytoplasm)","Sarcolemma (muscle cell plasma membrane)"],"gid":"g24","unit":"m-muscle","comp":"m-muscle::terminology"},{"id":"c25","dok":2,"q":"Which muscle property must a muscle have first in order to sense that a stimulus has arrived before it can shorten?","a":"Excitability.","options":["Contractility","Excitability","Elasticity","Extensibility"],"correctIndex":1,"explanation":"Excitability is the ability to sense and respond to a stimulus, which must occur before contractility produces shortening. Contractility is the shortening itself. Elasticity is recoil. Extensibility is stretch. Only excitability is about sensing the stimulus.","tags":["muscular","properties"],"gid":"g25","unit":"m-muscle","comp":"m-muscle::properties","assess":true},{"id":"c26","dok":2,"q":"Which property allows a muscle to spring back after it has been stretched, and which allows it to be stretched in the first place?","a":"Elasticity allows recoil to resting length; extensibility allows stretching beyond resting length.","tags":["muscular","properties"],"rubric":["Elasticity (recoil to resting length)","Extensibility (stretch beyond resting length)"],"gid":"g26","unit":"m-muscle","comp":"m-muscle::properties"},{"id":"c27","dok":2,"q":"The term muscle fiber refers to elongated muscle cells found in which muscle types?","a":"Skeletal and smooth muscle only.","options":["Skeletal and cardiac only","Skeletal and smooth only","Cardiac and smooth only","All three types"],"correctIndex":1,"explanation":"The term muscle fiber, meaning an elongated muscle cell, applies to skeletal and smooth muscle. Cardiac cells are short and branched, so they are not described this way. The other pairings and the all-three option include cardiac muscle incorrectly.","tags":["muscular","terminology"],"gid":"g27","unit":"m-muscle","comp":"m-muscle::terminology","assess":true},{"id":"c28","dok":2,"q":"Which muscle tissue function directly enables locomotion, manipulation of objects, and movement of blood and GI contents?","a":"Production of movement.","options":["Production of movement","Stabilization of joints","Generation of heat","Maintenance of posture"],"correctIndex":0,"explanation":"Production of movement covers locomotion, manipulation, and moving blood and GI contents. Stabilization of joints reinforces articulations rather than producing motion. Generation of heat is a byproduct. Maintenance of posture holds body position rather than producing movement.","tags":["muscular","functions"],"gid":"g28","unit":"m-muscle","comp":"m-muscle::functions","assess":true},{"id":"c29","dok":2,"q":"A muscle stretched beyond its resting length returns to that length once released. This describes which two properties working in sequence?","a":"Extensibility (the stretch) then elasticity (the return).","tags":["muscular","properties"],"rubric":["Extensibility (the stretch)","Elasticity (the return)"],"gid":"g29","unit":"m-muscle","comp":"m-muscle::properties"},{"id":"c30","dok":2,"q":"Which muscle-cell membrane term is built from the sarco prefix meaning flesh?","a":"Sarcolemma.","options":["Endomysium","Sarcolemma","Perimysium","Myofibril"],"correctIndex":1,"explanation":"Sarcolemma uses the sarco prefix (flesh) and names the muscle cell plasma membrane. Endomysium and perimysium use the mys root and name connective tissue sheaths. Myofibril uses the myo prefix and names a contractile rod.","tags":["muscular","terminology"],"gid":"g30","unit":"m-muscle","comp":"m-muscle::terminology"},{"id":"c31","dok":3,"q":"A histology slide shows short, branched striated cells joined end to end by dark bands, each cell with a central nucleus. Which tissue is on the slide, and what are the dark end bands?","a":"Cardiac muscle, and the dark end bands are intercalated discs.","options":["Skeletal muscle, and the bands are Z discs","Cardiac muscle, and the dark end bands are intercalated discs","Smooth muscle, and the bands are terminal cisterns","Skeletal muscle, and the bands are intercalated discs"],"correctIndex":1,"explanation":"Short branched striated cells joined end to end by dark bands with central nuclei are cardiac muscle, and those dark end bands are intercalated discs. Skeletal muscle is long, unbranched, and multinucleated, so Z discs (internal to the sarcomere) do not join cells end to end. Smooth muscle is nonstriated. Intercalated discs belong to cardiac, not skeletal, muscle.","tags":["muscular","types"],"gid":"g31","unit":"m-muscle","comp":"m-muscle::types","assess":true},{"id":"c32","dok":3,"q":"A tissue lining the wall of a blood vessel is nonstriated, contracts slowly and in a sustained way, and is not under conscious control. Which tissue type is this?","a":"Smooth muscle.","options":["Skeletal muscle","Cardiac muscle","Smooth muscle","Striated involuntary muscle"],"correctIndex":2,"explanation":"Nonstriated tissue in a vessel wall with slow, sustained, involuntary contraction is smooth muscle. Skeletal muscle is striated and voluntary. Cardiac muscle is in the heart wall and is striated. Striated involuntary muscle describes cardiac muscle, which is not in vessel walls.","tags":["muscular","types"],"gid":"g32","unit":"m-muscle","comp":"m-muscle::types","assess":true},{"id":"c33","dok":3,"q":"A student says a certain muscle can shorten forcibly but claims that shortening is what distinguishes it from all other tissues. Which single property is the student naming, and is the claim accurate?","a":"Contractility, and the claim is accurate because contractility is the property that sets muscle apart from other tissues.","options":["Excitability, and the claim is accurate","Contractility, and the claim is accurate because contractility sets muscle apart from other tissues","Elasticity, and the claim is inaccurate","Extensibility, and the claim is accurate"],"correctIndex":1,"explanation":"Forcible shortening is contractility, and that property is what sets muscle apart from other tissues, so the claim is accurate. Excitability, elasticity, and extensibility are all shared to some degree by other excitable or stretchable tissues, so none of them is the distinguishing property.","tags":["muscular","properties"],"gid":"g33","unit":"m-muscle","comp":"m-muscle::properties","assess":true},{"id":"c34","dok":3,"q":"On exposure to cold, shivering muscles produce warmth. Which muscle tissue function does shivering illustrate?","a":"Generation of heat.","options":["Production of movement","Stabilization of joints","Generation of heat","Maintenance of posture"],"correctIndex":2,"explanation":"Shivering illustrates generation of heat, a function that maintains body temperature. Production of movement refers to purposeful motion. Stabilization of joints reinforces articulations. Maintenance of posture holds body position, not heat production.","tags":["muscular","functions"],"gid":"g34","unit":"m-muscle","comp":"m-muscle::functions","assess":true},{"id":"c35","dok":3,"q":"Two striated muscle tissues are compared. One is voluntary with peripheral nuclei, and one is involuntary with intercalated discs. Identify each tissue.","a":"The voluntary tissue with peripheral nuclei is skeletal muscle; the involuntary tissue with intercalated discs is cardiac muscle.","tags":["muscular","types"],"rubric":["Skeletal (voluntary, peripheral nuclei)","Cardiac (involuntary, intercalated discs)"],"gid":"g35","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c36","dok":3,"q":"A muscle group pulls on bones to hold a joint firm during weight bearing without producing visible motion. Which muscle function does this describe?","a":"Stabilization of joints.","options":["Production of movement","Stabilization of joints","Generation of heat","Excitability"],"correctIndex":1,"explanation":"Holding a joint firm during weight bearing without visible motion is stabilization of joints. Production of movement produces visible motion. Generation of heat is a metabolic byproduct. Excitability is a property, not a function.","tags":["muscular","functions"],"gid":"g36","unit":"m-muscle","comp":"m-muscle::functions","assess":true},{"id":"c37","dok":3,"q":"Explain why the term muscle fiber is applied to skeletal and smooth muscle but not to cardiac muscle.","a":"Muscle fiber means an elongated muscle cell; skeletal and smooth cells are elongated, while cardiac cells are short and branched rather than elongated.","tags":["muscular","terminology"],"rubric":["Muscle fiber means elongated cell","Skeletal and smooth cells are elongated","Cardiac cells are short and branched"],"gid":"g37","unit":"m-muscle","comp":"m-muscle::terminology"},{"id":"c38","dok":3,"q":"A tissue is striated, its cells are among the longest in the body, and it is under conscious control. Name the tissue and give its two hallmark features.","a":"Skeletal muscle, whose two hallmarks are striated and voluntary.","tags":["muscular","types"],"rubric":["Skeletal muscle","Striated","Voluntary"],"gid":"g38","unit":"m-muscle","comp":"m-muscle::types"},{"id":"c1","dok":1,"q":"What is the fleshy portion of a muscle called?","a":"The belly (body) of the muscle.","options":["The origin","The belly","The insertion","The tendon"],"correctIndex":1,"explanation":"The belly, also called the body, is the fleshy portion of a muscle. The origin and insertion are attachment sites. The tendon is the cord of connective tissue that attaches the muscle to bone.","tags":["muscular","gross-anatomy"],"gid":"g39","unit":"m-muscle","comp":"m-muscle::gross-anatomy","assess":true},{"id":"c2","dok":1,"q":"How many nerves and arteries in general supply a single skeletal muscle?","a":"In general one nerve and one artery, with one or more veins.","tags":["muscular","gross-anatomy"],"rubric":["One nerve","One artery","One or more veins"],"gid":"g40","unit":"m-muscle","comp":"m-muscle::gross-anatomy"},{"id":"c3","dok":1,"q":"The origin of a muscle is the attachment of its tendon to which bone?","a":"The stationary bone.","options":["The movable bone","The stationary bone","The largest bone","The most distal bone"],"correctIndex":1,"explanation":"The origin is the attachment of a muscle's tendon to the stationary bone. The insertion attaches to the movable bone. Origin and insertion are not defined by size or by being most distal.","tags":["muscular","attachments"],"gid":"g41","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c4","dok":1,"q":"The insertion of a muscle is the attachment of its tendon to which bone?","a":"The movable bone.","options":["The stationary bone","The movable bone","The proximal bone","The flat bone"],"correctIndex":1,"explanation":"The insertion is the attachment of a muscle's tendon to the movable bone, which is pulled toward the origin. The stationary bone is the origin. The proximal bone is usually the origin. Bone shape does not define the insertion.","tags":["muscular","attachments"],"gid":"g42","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c5","dok":1,"q":"By the general rule of thumb, is the origin usually proximal or distal, and is the insertion usually proximal or distal?","a":"The origin is usually proximal and the insertion is usually distal.","tags":["muscular","attachments"],"rubric":["Origin usually proximal","Insertion usually distal"],"gid":"g43","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c6","dok":1,"q":"What is the main movement produced when a muscle contracts called?","a":"The action.","options":["The origin","The insertion","The action","The lever"],"correctIndex":2,"explanation":"The action is the main movement produced by muscle contraction. The origin and insertion are attachment sites. The lever is the bone that moves, not the movement itself.","tags":["muscular","attachments"],"gid":"g44","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c7","dok":1,"q":"List the three connective tissue sheaths of a muscle from external to internal.","a":"Epimysium, then perimysium, then endomysium.","tags":["muscular","ct-sheaths"],"rubric":["Epimysium","Perimysium","Endomysium"],"gid":"g45","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c8","dok":1,"q":"Which connective tissue sheath surrounds the whole muscle?","a":"The epimysium.","options":["The perimysium","The endomysium","The epimysium","The aponeurosis"],"correctIndex":2,"explanation":"The epimysium (outside of the muscle) surrounds the whole muscle. The perimysium surrounds each fascicle. The endomysium surrounds each fiber. The aponeurosis is a flat attachment, not a sheath.","tags":["muscular","ct-sheaths"],"gid":"g46","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c9","dok":1,"q":"What tissue type makes up the epimysium?","a":"Dense irregular connective tissue.","tags":["muscular","ct-sheaths"],"rubric":["Dense irregular connective tissue"],"gid":"g47","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c10","dok":1,"q":"Which connective tissue sheath surrounds each fascicle?","a":"The perimysium.","options":["The epimysium","The perimysium","The endomysium","The periosteum"],"correctIndex":1,"explanation":"The perimysium (around the muscle) surrounds each fascicle. The epimysium surrounds the whole muscle. The endomysium surrounds each single fiber. The periosteum covers bone.","tags":["muscular","ct-sheaths"],"gid":"g48","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c11","dok":1,"q":"What is a fascicle?","a":"A grouping (bundle) of muscle fibers within a skeletal muscle.","tags":["muscular","ct-sheaths"],"rubric":["Bundle of muscle fibers"],"gid":"g49","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c12","dok":1,"q":"Which connective tissue sheath surrounds each individual muscle fiber?","a":"The endomysium.","options":["The epimysium","The perimysium","The endomysium","The sarcolemma"],"correctIndex":2,"explanation":"The endomysium (within the muscle) surrounds each single muscle fiber. The epimysium wraps the whole muscle. The perimysium wraps each fascicle. The sarcolemma is the fiber's plasma membrane, not a connective tissue sheath.","tags":["muscular","ct-sheaths"],"gid":"g50","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c13","dok":1,"q":"What connective tissue type makes up the endomysium?","a":"Fine areolar connective tissue.","options":["Dense regular connective tissue","Dense irregular connective tissue","Fine areolar connective tissue","Elastic connective tissue"],"correctIndex":2,"explanation":"The endomysium is a wispy sheath of fine areolar connective tissue. Dense regular tissue makes up tendons. Dense irregular tissue makes up the epimysium and perimysium. Elastic connective tissue is not the endomysium.","tags":["muscular","ct-sheaths"],"gid":"g51","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c14","dok":1,"q":"In a direct (fleshy) attachment, the epimysium of the muscle is fused to what?","a":"The periosteum of the bone or the perichondrium of cartilage.","tags":["muscular","attachments"],"rubric":["Periosteum of bone","Perichondrium of cartilage"],"gid":"g52","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c15","dok":1,"q":"Which type of muscle attachment uses connective tissue wrappings such as tendons and aponeuroses?","a":"Indirect attachment.","options":["Direct attachment","Indirect attachment","Fleshy attachment","Fused attachment"],"correctIndex":1,"explanation":"Indirect attachments use connective tissue wrappings such as tendons and aponeuroses. Direct (fleshy) attachments fuse the epimysium to the periosteum. Fleshy is another name for direct. Fused attachment is not a standard term.","tags":["muscular","attachments"],"gid":"g53","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c16","dok":1,"q":"What is the rope-like cord that anchors a muscle to bone called?","a":"A tendon.","options":["An aponeurosis","A tendon","A ligament","A fascia"],"correctIndex":1,"explanation":"A tendon is the rope-like cord that anchors a muscle to bone. An aponeurosis is the sheet-like version. A ligament connects bone to bone. Fascia wraps and separates muscles.","tags":["muscular","attachments"],"gid":"g54","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c17","dok":1,"q":"What is the sheet-like connective tissue muscle attachment called?","a":"An aponeurosis.","options":["A tendon","An aponeurosis","A retinaculum","A raphe"],"correctIndex":1,"explanation":"An aponeurosis is the sheet-like connective tissue attachment. A tendon is the rope-like cord version. A retinaculum holds tendons in place. A raphe is a seam of connective tissue, not the muscle attachment described.","tags":["muscular","attachments"],"gid":"g55","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c18","dok":1,"q":"Where do the nerve and blood vessels usually enter or exit a skeletal muscle?","a":"At the central part of the muscle, then branch throughout the connective tissue sheaths.","tags":["muscular","gross-anatomy"],"rubric":["Central part of the muscle","Branch through connective tissue sheaths"],"gid":"g56","unit":"m-muscle","comp":"m-muscle::gross-anatomy"},{"id":"c19","dok":2,"q":"Moving from the outside of a whole muscle inward, which sheath is encountered immediately after the epimysium?","a":"The perimysium.","options":["The endomysium","The perimysium","The sarcolemma","The deep fascia"],"correctIndex":1,"explanation":"Just inside the epimysium lies the perimysium around each fascicle. The endomysium is deeper still, around each fiber. The sarcolemma is a cell membrane, not a sheath. Deep fascia lies outside the epimysium.","tags":["muscular","ct-sheaths"],"gid":"g57","unit":"m-muscle","comp":"m-muscle::ct-sheaths","assess":true},{"id":"c20","dok":2,"q":"Which connective tissue sheath directly wraps a single muscle fiber, the deepest of the three?","a":"The endomysium.","options":["The epimysium","The perimysium","The endomysium","The periosteum"],"correctIndex":2,"explanation":"The endomysium directly wraps each single fiber and is the deepest sheath. The perimysium wraps fascicles and the epimysium wraps the whole muscle, both more superficial. The periosteum covers bone.","tags":["muscular","ct-sheaths"],"gid":"g58","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c21","dok":2,"q":"When all three connective tissue sheaths merge and continue past the muscle to attach it to bone, what structure do they form?","a":"A tendon (or an aponeurosis if the attachment is sheet-like).","tags":["muscular","attachments"],"rubric":["Tendon (cord)","Aponeurosis (sheet-like)"],"gid":"g59","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c22","dok":2,"q":"Which structure connects a muscle to bone, and which connects one bone to another?","a":"A tendon connects muscle to bone; a ligament connects bone to bone.","tags":["muscular","attachments"],"rubric":["Tendon: muscle to bone","Ligament: bone to bone"],"gid":"g60","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c23","dok":2,"q":"In the limbs, is the origin located proximal or distal to the insertion?","a":"The origin lies proximal to the insertion.","options":["Distal","Proximal","Lateral","Medial"],"correctIndex":1,"explanation":"In the limbs the origin lies proximal to the insertion, and the insertion is pulled toward the origin. Distal, lateral, and medial do not describe the standard origin-to-insertion relationship in the limbs.","tags":["muscular","attachments"],"gid":"g61","unit":"m-muscle","comp":"m-muscle::attachments","assess":true},{"id":"c24","dok":2,"q":"Why is an indirect attachment by tendon more common than a direct (fleshy) attachment?","a":"Tendons are small and durable, so more of them can pass over a bony joint and they conserve space.","tags":["muscular","attachments"],"rubric":["Small and durable","More can pass over a joint","Conserve space"],"gid":"g62","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c25","dok":2,"q":"A muscle attachment is a broad flat sheet rather than a cord, used where a muscle is wide. What is it called?","a":"An aponeurosis.","options":["A tendon","An aponeurosis","A ligament","A raphe"],"correctIndex":1,"explanation":"A broad flat sheet attachment used where a muscle is wide is an aponeurosis. A tendon is a cord. A ligament connects bone to bone. A raphe is a connective tissue seam.","tags":["muscular","attachments"],"gid":"g63","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c26","dok":2,"q":"Name two functions of the connective tissue sheaths of a muscle.","a":"They support and reinforce the muscle so it does not burst during strong contractions, and they provide routes for blood vessels and nerve fibers to enter and exit; they are also continuous with tendons and transmit pulling force to bone.","tags":["muscular","ct-sheaths"],"rubric":["Support and reinforce (prevent bursting)","Route for vessels and nerves","Continuous with tendons (transmit force)"],"gid":"g64","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c27","dok":2,"q":"Why are muscle capillaries long and winding with cross-links?","a":"So they can accommodate changes in muscle length; they straighten out when the muscle is stretched.","tags":["muscular","gross-anatomy"],"rubric":["Accommodate length changes","Straighten when muscle is stretched"],"gid":"g65","unit":"m-muscle","comp":"m-muscle::gross-anatomy"},{"id":"c28","dok":2,"q":"Which sheath can blend with the deep fascia between neighboring muscles or with the superficial fascia deep to the skin?","a":"The epimysium.","options":["The endomysium","The perimysium","The epimysium","The periosteum"],"correctIndex":2,"explanation":"The epimysium, the outermost sheath, can blend with the deep fascia between muscles or the superficial fascia deep to the skin. The endomysium and perimysium lie deeper within the muscle. The periosteum covers bone.","tags":["muscular","ct-sheaths"],"gid":"g66","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c29","dok":2,"q":"A muscle attaches by having its epimysium fused directly to the periosteum of a bone. Which type of attachment is this?","a":"A direct (fleshy) attachment.","options":["An indirect attachment","A direct (fleshy) attachment","An aponeurotic attachment","A tendinous attachment"],"correctIndex":1,"explanation":"Fusion of the epimysium directly to the periosteum is a direct (fleshy) attachment. Indirect, aponeurotic, and tendinous attachments all involve intervening connective tissue wrappings rather than direct fusion.","tags":["muscular","attachments"],"gid":"g67","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c30","dok":2,"q":"Which structure is the movable end of a muscle that is pulled toward the stationary end during contraction?","a":"The insertion.","options":["The origin","The belly","The insertion","The tendon"],"correctIndex":2,"explanation":"The insertion is the movable end pulled toward the stationary origin during contraction. The origin is the stationary end. The belly is the fleshy middle. The tendon is the connective tissue cord.","tags":["muscular","attachments"],"gid":"g68","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c31","dok":3,"q":"Trace the path of a muscle fiber's pull outward to bone through the connective tissue. Which sequence is correct?","a":"Endomysium around the fiber, perimysium around the fascicle, epimysium around the whole muscle, then the tendon to the bone.","options":["Tendon, epimysium, perimysium, endomysium, then bone","Endomysium, perimysium, epimysium, then the tendon to the bone","Epimysium, perimysium, endomysium, then the tendon to the bone","Perimysium, endomysium, epimysium, then the tendon to the bone"],"correctIndex":1,"explanation":"The pull passes outward through the endomysium around each fiber, the perimysium around each fascicle, the epimysium around the whole muscle, and then the merged tendon to the bone. The other sequences reverse the order or place the epimysium inside the perimysium, which would put the whole-muscle wrapping deeper than the fascicle wrapping.","tags":["muscular","ct-sheaths"],"gid":"g69","unit":"m-muscle","comp":"m-muscle::ct-sheaths","assess":true},{"id":"c32","dok":3,"q":"During a strong contraction a muscle bulges but does not burst. Which sheath function prevents the bursting?","a":"Support and reinforcement by the connective tissue sheaths.","options":["Providing routes for blood vessels","Support and reinforcement by the sheaths","Storing calcium","Generating heat"],"correctIndex":1,"explanation":"The sheaths support and reinforce the muscle so it does not burst when it bulges during strong contraction. Providing routes for vessels is a different sheath function. Storing calcium is a job of the sarcoplasmic reticulum. Generating heat is a function of the tissue, not the sheaths.","tags":["muscular","ct-sheaths"],"gid":"g70","unit":"m-muscle","comp":"m-muscle::ct-sheaths","assess":true},{"id":"c33","dok":3,"q":"A muscle in the forearm passes its pull across the wrist using several small cords that fit over the joint. Which attachment type and structure allow this space-saving arrangement?","a":"Indirect attachment by tendons, which are small and durable enough to pass over a bony joint.","options":["Direct attachment by fused epimysium","Indirect attachment by tendons","Direct attachment by aponeurosis","Attachment by ligaments"],"correctIndex":1,"explanation":"Small durable cords crossing a joint are tendons, an indirect attachment that conserves space. Direct (fleshy) attachment fuses epimysium to periosteum and does not use cords. An aponeurosis is a sheet, not a cord, and is not a direct attachment. Ligaments connect bone to bone, not muscle to bone.","tags":["muscular","attachments"],"gid":"g71","unit":"m-muscle","comp":"m-muscle::attachments","assess":true},{"id":"c34","dok":3,"q":"A dissector isolates a bundle of muscle fibers wrapped by a single sheath but still inside the whole muscle. Which sheath was cut to free the bundle, and what is the bundle called?","a":"The perimysium was cut, and the bundle is a fascicle.","tags":["muscular","ct-sheaths"],"rubric":["Perimysium was cut","Bundle is a fascicle"],"gid":"g72","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c35","dok":3,"q":"A muscle's nerve and vessels enter at its center and branch outward. Through which structures do these vessels and nerves travel to reach individual fibers?","a":"Through the connective tissue sheaths (epimysium, perimysium, and endomysium).","options":["Through the sarcomeres","Through the connective tissue sheaths","Through the myofibrils","Through the tendons only"],"correctIndex":1,"explanation":"Vessels and nerves travel through the connective tissue sheaths, which provide routes for their entry and exit down to individual fibers. Sarcomeres and myofibrils are contractile structures inside the fiber, not routes for vessels. Tendons attach muscle to bone and are not the branching route to fibers.","tags":["muscular","gross-anatomy"],"gid":"g73","unit":"m-muscle","comp":"m-muscle::gross-anatomy","assess":true},{"id":"c36","dok":3,"q":"Two bones articulate at a joint, and a muscle crosses it. During contraction one bone stays put and the other moves toward it. Identify the muscle attachment on each bone.","a":"The attachment to the stationary bone is the origin; the attachment to the moving bone is the insertion.","tags":["muscular","attachments"],"rubric":["Stationary bone: origin","Moving bone: insertion"],"gid":"g74","unit":"m-muscle","comp":"m-muscle::attachments"},{"id":"c37","dok":3,"q":"A wide flat abdominal muscle attaches along the midline by a broad sheet rather than a cord. Which attachment structure is used?","a":"An aponeurosis.","options":["A tendon","An aponeurosis","A direct fleshy attachment","A ligament"],"correctIndex":1,"explanation":"A broad flat sheet used by a wide muscle is an aponeurosis. A tendon is a cord, less suited to a wide flat attachment. A direct fleshy attachment fuses epimysium to periosteum. A ligament connects bone to bone, not muscle to bone.","tags":["muscular","attachments"],"gid":"g75","unit":"m-muscle","comp":"m-muscle::attachments","assess":true},{"id":"c38","dok":3,"q":"Explain how the three sheaths and the tendon work together to move a bone when a fiber shortens.","a":"The pull passes from the fiber through the endomysium, perimysium, and epimysium, which are continuous with the tendon, and the tendon transmits the pulling force to the bone so it moves.","tags":["muscular","ct-sheaths"],"rubric":["Pull passes through endomysium, perimysium, epimysium","Sheaths continuous with tendon","Tendon transmits force to bone"],"gid":"g76","unit":"m-muscle","comp":"m-muscle::ct-sheaths"},{"id":"c1","dok":1,"q":"List the characteristics used to name muscles.","a":"Direction, size, shape, action, number of origins, location, and origin and insertion.","tags":["muscular","naming"],"rubric":["Direction","Size","Shape","Action","Number of origins","Location and origin/insertion"],"gid":"g77","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c2","dok":1,"q":"In muscle naming, what does the direction term rectus mean?","a":"Fascicles run parallel to the midline.","options":["Parallel to the midline","Perpendicular to the midline","Diagonal to the midline","In concentric rings"],"correctIndex":0,"explanation":"Rectus means the fascicles run parallel to the midline. Transverse means perpendicular to the midline. Oblique means diagonal to the midline. Concentric rings describe a circular muscle, not a direction term.","tags":["muscular","naming"],"gid":"g78","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c3","dok":1,"q":"In muscle naming, what does the direction term oblique indicate?","a":"Fascicles run diagonal to the midline.","options":["Parallel to the midline","Perpendicular to the midline","Diagonal to the midline","Toward the midline"],"correctIndex":2,"explanation":"Oblique means fascicles run diagonal to the midline. Rectus is parallel and transverse is perpendicular to the midline. Toward the midline describes adduction, not a fascicle direction.","tags":["muscular","naming"],"gid":"g79","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c4","dok":1,"q":"In muscle naming, what do the size terms maximus and minimus mean?","a":"Maximus means largest and minimus means smallest.","tags":["muscular","naming"],"rubric":["Maximus means largest","Minimus means smallest"],"gid":"g80","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c5","dok":1,"q":"In muscle naming, what do the size terms longus and brevis mean?","a":"Longus means long and brevis means short.","tags":["muscular","naming"],"rubric":["Longus means long","Brevis means short"],"gid":"g81","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c6","dok":1,"q":"The shape term deltoid describes which shape?","a":"Triangular.","options":["Trapezoid","Triangular","Diamond-shaped","Circular"],"correctIndex":1,"explanation":"Deltoid means triangular. Trapezius means trapezoid. Rhomboid means diamond-shaped. Orbicularis means circular.","tags":["muscular","naming"],"gid":"g82","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c7","dok":1,"q":"The shape term orbicularis describes which shape?","a":"Circular.","options":["Saw-toothed","Diamond-shaped","Circular","Pear-shaped"],"correctIndex":2,"explanation":"Orbicularis means circular. Serratus means saw-toothed. Rhomboid means diamond-shaped. Piriformis means pear-shaped.","tags":["muscular","naming"],"gid":"g83","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c8","dok":1,"q":"In the naming criterion action, what does the term flexor indicate?","a":"It decreases a joint angle.","options":["Decreases a joint angle","Increases a joint angle","Moves a bone away from the midline","Moves a bone toward the midline"],"correctIndex":0,"explanation":"A flexor decreases a joint angle. An extensor increases a joint angle. An abductor moves a bone away from the midline. An adductor moves a bone toward the midline.","tags":["muscular","naming"],"gid":"g84","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c9","dok":1,"q":"In the naming criterion action, what do the terms abductor and adductor indicate?","a":"An abductor moves a bone away from the midline; an adductor moves a bone toward the midline.","tags":["muscular","naming"],"rubric":["Abductor: away from midline","Adductor: toward midline"],"gid":"g85","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c10","dok":1,"q":"In muscle naming, what do biceps, triceps, and quadriceps indicate?","a":"Number of origins: biceps has two origins, triceps has three, and quadriceps has four.","tags":["muscular","naming"],"rubric":["Number of origins","Biceps two","Triceps three","Quadriceps four"],"gid":"g86","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c11","dok":1,"q":"The muscle name temporalis is based on which naming criterion?","a":"Location (it lies over the temporal bone).","options":["Shape","Location","Action","Number of origins"],"correctIndex":1,"explanation":"Temporalis is named for its location over the temporal bone. Shape terms include deltoid and rhomboid. Action terms include flexor. Number of origins is signaled by biceps or triceps.","tags":["muscular","naming"],"gid":"g87","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c12","dok":1,"q":"In a lever system, what does the effort represent?","a":"The force that causes movement, supplied by muscle contraction.","options":["The weight being moved","The pivot point","The force that causes movement","The rigid bar"],"correctIndex":2,"explanation":"The effort is the force that causes movement, supplied by muscle contraction. The weight being moved is the load. The pivot point is the fulcrum. The rigid bar is the lever, a bone.","tags":["muscular","levers"],"gid":"g88","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c13","dok":1,"q":"In a lever system, what does the load (resistance) represent?","a":"The force that opposes movement, such as the weight of the body part moved or a resistance to overcome.","tags":["muscular","levers"],"rubric":["Force opposing movement","Weight of body part or resistance"],"gid":"g89","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c14","dok":1,"q":"In a body lever, what structure acts as the fulcrum?","a":"A joint.","options":["A bone","A joint","A tendon","A muscle"],"correctIndex":1,"explanation":"A joint acts as the fulcrum, the pivot point. A bone acts as the lever. A tendon transmits the pull. A muscle supplies the effort.","tags":["muscular","levers"],"gid":"g90","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c15","dok":1,"q":"In a body lever, what structure acts as the lever?","a":"A bone.","options":["A joint","A bone","A ligament","A tendon"],"correctIndex":1,"explanation":"A bone acts as the rigid lever. A joint is the fulcrum. A ligament connects bone to bone. A tendon transmits the muscle's pull.","tags":["muscular","levers"],"gid":"g91","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c16","dok":1,"q":"In a first-class lever, where is the fulcrum located relative to the effort and the load?","a":"Between the effort and the load.","options":["Between the effort and the load","Between the fulcrum and the effort","At the same point as the effort","Beyond the load"],"correctIndex":0,"explanation":"In a first-class lever the fulcrum lies between the effort and the load, like a seesaw. The load between the fulcrum and effort describes a second-class lever. The other options do not describe a first-class arrangement.","tags":["muscular","levers"],"gid":"g92","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c17","dok":1,"q":"In a second-class lever, what lies between the fulcrum and the effort?","a":"The load.","options":["The effort","The load","The fulcrum","A second fulcrum"],"correctIndex":1,"explanation":"In a second-class lever the load lies between the fulcrum and the effort, like a wheelbarrow. The effort between the fulcrum and load describes a third-class lever. There is no second fulcrum in these classes.","tags":["muscular","levers"],"gid":"g93","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c18","dok":1,"q":"In a third-class lever, what lies between the fulcrum and the load?","a":"The effort.","options":["The load","The fulcrum","The effort","A second load"],"correctIndex":2,"explanation":"In a third-class lever the effort lies between the fulcrum and the load, like forceps. The load in the middle describes a second-class lever. The fulcrum in the middle describes a first-class lever.","tags":["muscular","levers"],"gid":"g94","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c19","dok":1,"q":"Which muscle role is the prime mover that contracts to cause an action?","a":"The agonist.","options":["The antagonist","The synergist","The agonist","The fixator"],"correctIndex":2,"explanation":"The agonist is the prime mover that contracts to cause an action. The antagonist yields and stretches. The synergist assists the prime mover. The fixator stabilizes the origin.","tags":["muscular","coordination"],"gid":"g95","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c20","dok":1,"q":"Which muscle role stretches and yields to the effects of the prime mover?","a":"The antagonist.","options":["The agonist","The antagonist","The synergist","The fixator"],"correctIndex":1,"explanation":"The antagonist stretches and yields to the prime mover. The agonist is the prime mover itself. The synergist assists. The fixator steadies the origin.","tags":["muscular","coordination"],"gid":"g96","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c21","dok":1,"q":"Which muscle role prevents unwanted movements at intermediate joints or aids the prime mover?","a":"The synergist.","options":["The agonist","The antagonist","The synergist","The fixator"],"correctIndex":2,"explanation":"The synergist prevents unwanted movements at intermediate joints or aids the prime mover. The agonist is the prime mover. The antagonist opposes it. The fixator stabilizes the origin, a specialized synergist role.","tags":["muscular","coordination"],"gid":"g97","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c22","dok":1,"q":"Which muscle role stabilizes the origin of the prime mover so it can act more efficiently?","a":"The fixator.","options":["The synergist","The fixator","The antagonist","The agonist"],"correctIndex":1,"explanation":"The fixator stabilizes the origin of the prime mover, steadying the proximal end so the prime mover can act efficiently at the distal end. A synergist assists more broadly. The antagonist opposes. The agonist is the prime mover.","tags":["muscular","coordination"],"gid":"g98","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c23","dok":1,"q":"What is a muscle compartment?","a":"A group of skeletal muscles with their associated blood vessels and nerves, all sharing a common function.","tags":["muscular","coordination"],"rubric":["Group of skeletal muscles","With vessels and nerves","Sharing a common function"],"gid":"g99","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c24","dok":2,"q":"The name gluteus maximus uses which naming criterion in the word maximus?","a":"Relative size.","options":["Shape","Relative size","Action","Direction"],"correctIndex":1,"explanation":"Maximus describes relative size, meaning largest. Shape terms include deltoid. Action terms include flexor. Direction terms include rectus and oblique.","tags":["muscular","naming"],"gid":"g100","unit":"m-muscle","comp":"m-muscle::naming","assess":true},{"id":"c25","dok":2,"q":"The name sternocleidomastoid is built from which naming criterion, and what are the two points it names?","a":"Origin and insertion; it originates on the sternum and clavicle and inserts on the mastoid process of the temporal bone.","tags":["muscular","naming"],"rubric":["Criterion: origin and insertion","Origin: sternum and clavicle","Insertion: mastoid process"],"gid":"g101","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c26","dok":2,"q":"A muscle name contains the word rectus. Which naming criterion does that reflect, and what does it tell you?","a":"Direction; the fascicles run parallel to the midline.","tags":["muscular","naming"],"rubric":["Criterion: direction","Fascicles parallel to midline"],"gid":"g102","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c27","dok":2,"q":"The word transverse in a muscle name indicates fascicles running in which direction?","a":"Perpendicular to the midline.","options":["Parallel to the midline","Perpendicular to the midline","Diagonal to the midline","In a circle"],"correctIndex":1,"explanation":"Transverse means fascicles run perpendicular to the midline. Rectus is parallel and oblique is diagonal to the midline. A circular arrangement is orbicularis, not transverse.","tags":["muscular","naming"],"gid":"g103","unit":"m-muscle","comp":"m-muscle::naming","assess":true},{"id":"c28","dok":2,"q":"The shape term serratus describes what appearance?","a":"Saw-toothed.","options":["Trapezoid","Saw-toothed","Slender","Square"],"correctIndex":1,"explanation":"Serratus means saw-toothed. Trapezius means trapezoid. Gracilis means slender. Quadratus means square.","tags":["muscular","naming"],"gid":"g104","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c29","dok":2,"q":"Standing on the toes places the body's weight between the fulcrum at the ball of the foot and the upward pull of the calf. Which lever class is this?","a":"Second-class lever.","options":["First-class lever","Second-class lever","Third-class lever","Fourth-class lever"],"correctIndex":1,"explanation":"A second-class lever has the load between the fulcrum and the effort, like a wheelbarrow, and standing on the toes is the anatomical example. A first-class lever has the fulcrum in the middle. A third-class lever has the effort in the middle. There is no fourth class.","tags":["muscular","levers"],"gid":"g105","unit":"m-muscle","comp":"m-muscle::levers","assess":true},{"id":"c30","dok":2,"q":"The head balanced on the vertebral column is the anatomical example of which lever class?","a":"First-class lever.","options":["First-class lever","Second-class lever","Third-class lever","It is not a lever"],"correctIndex":0,"explanation":"The head on the vertebral column is a first-class lever, with the fulcrum between the effort and the load like a seesaw. A second-class lever has the load in the middle. A third-class lever has the effort in the middle. Every body movement is a lever.","tags":["muscular","levers"],"gid":"g106","unit":"m-muscle","comp":"m-muscle::levers","assess":true},{"id":"c31","dok":2,"q":"Elbow flexion, with the biceps brachii lifting the forearm, is the anatomical example of which lever class?","a":"Third-class lever.","options":["First-class lever","Second-class lever","Third-class lever","Fourth-class lever"],"correctIndex":2,"explanation":"Elbow flexion is a third-class lever, with the effort between the fulcrum and the load, like forceps. A first-class lever has the fulcrum in the middle. A second-class lever has the load in the middle. There is no fourth class.","tags":["muscular","levers"],"gid":"g107","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c32","dok":2,"q":"During elbow flexion the biceps brachii contracts and the triceps brachii yields and stretches. What role does the triceps play?","a":"Antagonist.","options":["Agonist","Antagonist","Synergist","Fixator"],"correctIndex":1,"explanation":"The triceps yields and stretches as the biceps contracts, so it is the antagonist. The agonist, or prime mover, is the biceps here. A synergist assists the prime mover. A fixator steadies the origin bone.","tags":["muscular","coordination"],"gid":"g108","unit":"m-muscle","comp":"m-muscle::coordination","assess":true},{"id":"c33","dok":2,"q":"In the biceps brachii lifting an object, identify the fulcrum, the load, and the effort.","a":"The fulcrum is the elbow, the load is the weight of the forearm plus the object, and the effort is the force of the biceps brachii pulling the forearm up.","tags":["muscular","levers"],"rubric":["Fulcrum: elbow","Load: forearm plus object","Effort: biceps brachii pull"],"gid":"g109","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c34","dok":2,"q":"What determines whether a lever operates at a mechanical advantage or disadvantage?","a":"The distance of the load from the fulcrum.","options":["The size of the muscle","The distance of the load from the fulcrum","The number of origins","The length of the tendon"],"correctIndex":1,"explanation":"Mechanical advantage or disadvantage is determined by the distance of the load from the fulcrum. Muscle size, number of origins, and tendon length do not define the mechanical advantage of the lever.","tags":["muscular","levers"],"gid":"g110","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c35","dok":2,"q":"Name the two examples of an upper-extremity muscle compartment given by function and position.","a":"The anterior (flexor) compartment and the posterior (extensor) compartment of the upper extremity.","tags":["muscular","coordination"],"rubric":["Anterior (flexor) compartment","Posterior (extensor) compartment"],"gid":"g111","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c36","dok":3,"q":"A muscle name reads flexor carpi radialis. Reading only the name, which three kinds of information does it supply, in order?","a":"The action (flexor), the region (wrist, carpi), and the side or position (radial).","options":["Shape, number of heads, and size","Origin, insertion, and action","Action, region, and side or position","Direction, shape, and size"],"correctIndex":2,"explanation":"Flexor names the action, carpi names the wrist region, and radialis names the radial side, so the name reads action, region, position. It carries no shape, head-count, size, direction, or attachment-point terms, which rules out the other options.","tags":["muscular","naming"],"gid":"g112","unit":"m-muscle","comp":"m-muscle::naming","assess":true},{"id":"c37","dok":3,"q":"It is easier to chew gum with the back teeth than the front teeth. Using lever principles, explain why.","a":"The back teeth are closer to the fulcrum (the jaw joint), so a smaller effort moves the load, giving a mechanical advantage; the front teeth are farther from the fulcrum, requiring more effort.","tags":["muscular","levers"],"rubric":["Back teeth closer to fulcrum (jaw joint)","Smaller effort moves load (mechanical advantage)","Front teeth farther, need more effort"],"gid":"g113","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c38","dok":3,"q":"A single muscle acts as the prime mover in one movement and as the antagonist in the opposite movement. What does this illustrate about muscle roles?","a":"A muscle's role is not fixed; it can act as prime mover, antagonist, synergist, or fixator depending on the action.","tags":["muscular","coordination"],"rubric":["Role is not fixed","Can be prime mover, antagonist, synergist, or fixator","Depends on the action"],"gid":"g114","unit":"m-muscle","comp":"m-muscle::coordination"},{"id":"c39","dok":3,"q":"While the hand moves at the wrist, certain forearm muscles hold the elbow steady so the movement is clean. What coordination role are the elbow-steadying muscles playing?","a":"Fixator.","options":["Agonist","Antagonist","Fixator","Prime mover"],"correctIndex":2,"explanation":"Muscles that steady a proximal joint so movement occurs cleanly at a distal joint are acting as fixators, stabilizing the origin. An agonist or prime mover produces the movement itself. An antagonist opposes the prime mover.","tags":["muscular","coordination"],"gid":"g115","unit":"m-muscle","comp":"m-muscle::coordination","assess":true},{"id":"c40","dok":3,"q":"A muscle is named biceps femoris. Break the name into its two criteria and state what each part tells you.","a":"Biceps is the number of origins (two heads); femoris is the location (the femur, the thigh region).","tags":["muscular","naming"],"rubric":["Biceps: number of origins (two heads)","Femoris: location (femur/thigh)"],"gid":"g116","unit":"m-muscle","comp":"m-muscle::naming"},{"id":"c41","dok":3,"q":"A load sits very close to the fulcrum so only a small effort moves a heavy load over that short distance. What is this condition called?","a":"Mechanical advantage.","options":["Mechanical disadvantage","Mechanical advantage","Antagonism","Fixation"],"correctIndex":1,"explanation":"A load close to the fulcrum needing only a small effort is mechanical advantage. Mechanical disadvantage is the opposite, with the load far from the fulcrum requiring more effort. Antagonism and fixation are coordination roles, not lever conditions.","tags":["muscular","levers"],"gid":"g117","unit":"m-muscle","comp":"m-muscle::levers","assess":true},{"id":"c42","dok":3,"q":"Three anatomical movements are the head nodding, standing on the toes, and flexing the elbow. Match each to its lever class.","a":"Head nodding is a first-class lever, standing on the toes is a second-class lever, and flexing the elbow is a third-class lever.","tags":["muscular","levers"],"rubric":["Head nodding: first class","Standing on toes: second class","Flexing elbow: third class"],"gid":"g118","unit":"m-muscle","comp":"m-muscle::levers"},{"id":"c43","dok":3,"q":"A group of anterior forearm muscles shares one nerve, one main artery, and the common function of flexion. What is this grouping called?","a":"A compartment.","options":["A fascicle","A compartment","An aponeurosis","A synergy"],"correctIndex":1,"explanation":"A group of muscles sharing blood vessels, nerves, and a common function is a compartment, such as the anterior flexor compartment. A fascicle is a bundle of fibers within one muscle. An aponeurosis is a flat attachment. Synergy is a functional relationship, not a named anatomical group.","tags":["muscular","coordination"],"gid":"g119","unit":"m-muscle","comp":"m-muscle::coordination","assess":true},{"id":"c1","dok":1,"q":"Where are the multiple nuclei of a skeletal muscle fiber located?","a":"Just under the sarcolemma (peripheral, at the edge of the fiber).","options":["In the center of the fiber","Just under the sarcolemma","Within the myofibrils","In the sarcoplasmic reticulum"],"correctIndex":1,"explanation":"The many oval nuclei of a skeletal muscle fiber lie just under the sarcolemma, at the periphery. Central nuclei are typical of cardiac muscle. Nuclei are not inside the myofibrils or the sarcoplasmic reticulum.","tags":["muscular","microanatomy"],"gid":"g120","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c2","dok":1,"q":"What is the cytoplasm of a muscle cell called?","a":"Sarcoplasm.","options":["Sarcolemma","Sarcoplasm","Sarcomere","Sarcoplasmic reticulum"],"correctIndex":1,"explanation":"Sarcoplasm is the cytoplasm of a muscle cell. Sarcolemma is its plasma membrane. A sarcomere is a contractile unit. The sarcoplasmic reticulum is the smooth endoplasmic reticulum of the fiber.","tags":["muscular","microanatomy"],"gid":"g121","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c3","dok":1,"q":"What is the plasma membrane of a muscle fiber called?","a":"The sarcolemma.","options":["The sarcoplasm","The sarcolemma","The endomysium","The sarcoplasmic reticulum"],"correctIndex":1,"explanation":"The sarcolemma is the plasma membrane of the muscle fiber. The sarcoplasm is its cytoplasm. The endomysium is the connective tissue sheath outside the fiber. The sarcoplasmic reticulum is inside the fiber.","tags":["muscular","microanatomy"],"gid":"g122","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c4","dok":1,"q":"What are glycosomes, and why are they abundant in the sarcoplasm?","a":"Granules of stored glycogen; they provide glucose during muscle activity for ATP production.","tags":["muscular","microanatomy"],"rubric":["Granules of stored glycogen","Provide glucose for ATP during activity"],"gid":"g123","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c5","dok":1,"q":"Which red pigment in the sarcoplasm stores oxygen and is similar to hemoglobin?","a":"Myoglobin.","options":["Glycogen","Myoglobin","Myosin","Melanin"],"correctIndex":1,"explanation":"Myoglobin is the red pigment that stores oxygen, similar to hemoglobin. Glycogen is stored carbohydrate. Myosin is a contractile protein. Melanin is a skin pigment, not found storing oxygen in muscle.","tags":["muscular","microanatomy"],"gid":"g124","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c6","dok":1,"q":"Name the three specialized, highly modified organelles of a skeletal muscle fiber.","a":"Myofibrils, sarcoplasmic reticulum, and T tubules.","tags":["muscular","microanatomy"],"rubric":["Myofibrils","Sarcoplasmic reticulum","T tubules"],"gid":"g125","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c7","dok":1,"q":"About what percentage of a muscle fiber's cellular volume is made up of myofibrils?","a":"About 80 percent.","options":["About 20 percent","About 50 percent","About 80 percent","About 100 percent"],"correctIndex":2,"explanation":"Myofibrils are densely packed and make up about 80 percent of the cellular volume. The other values are too low or would leave no room for other structures.","tags":["muscular","microanatomy"],"gid":"g126","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c8","dok":1,"q":"What are myofibrils?","a":"Densely packed rod-like structures within a muscle fiber that contain the contractile elements (sarcomeres).","tags":["muscular","microanatomy"],"rubric":["Densely packed rod-like structures","Contain contractile elements (sarcomeres)"],"gid":"g127","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c9","dok":1,"q":"The sarcoplasmic reticulum is a specialized form of which organelle?","a":"Smooth endoplasmic reticulum.","options":["Rough endoplasmic reticulum","Smooth endoplasmic reticulum","Golgi apparatus","Mitochondrion"],"correctIndex":1,"explanation":"The sarcoplasmic reticulum is specialized smooth endoplasmic reticulum. It is not rough endoplasmic reticulum, the Golgi apparatus, or a mitochondrion.","tags":["muscular","sr-ttubules"],"gid":"g128","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c10","dok":1,"q":"How is the sarcoplasmic reticulum arranged relative to each myofibril?","a":"As interconnecting tubules that run longitudinally around each myofibril like a sleeve.","tags":["muscular","sr-ttubules"],"rubric":["Interconnecting tubules","Run longitudinally around each myofibril (sleeve)"],"gid":"g129","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c11","dok":1,"q":"What are the enlarged end sacs of the sarcoplasmic reticulum called?","a":"Terminal cisterns.","options":["T tubules","Terminal cisterns","Myofibrils","Glycosomes"],"correctIndex":1,"explanation":"The enlarged end sacs of the sarcoplasmic reticulum are terminal cisterns. T tubules are inward extensions of the sarcolemma. Myofibrils are contractile rods. Glycosomes are glycogen granules.","tags":["muscular","sr-ttubules"],"gid":"g130","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c12","dok":1,"q":"At which junction do the terminal cisterns form perpendicular crosses?","a":"At the A band to I band junction.","options":["At the M line","At the A band to I band junction","At the Z disc center","At the H zone"],"correctIndex":1,"explanation":"Terminal cisterns form perpendicular crosses at the A band to I band junction. The M line and Z disc are internal sarcomere landmarks, not where the cisterns cross. The H zone is where the longitudinal sarcoplasmic reticulum tubules communicate, not where the cisterns cross.","tags":["muscular","sr-ttubules"],"gid":"g131","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c13","dok":1,"q":"In one line, what is the general role of the sarcoplasmic reticulum?","a":"It stores and releases calcium ions and regulates their level in the cell.","tags":["muscular","sr-ttubules"],"rubric":["Stores and releases calcium ions","Regulates calcium level in the cell"],"gid":"g132","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c14","dok":1,"q":"What is a T tubule?","a":"An elongated transverse tube that is an inward extension of the sarcolemma reaching deep into the cell interior.","tags":["muscular","sr-ttubules"],"rubric":["Transverse tube","Inward extension of the sarcolemma","Reaches deep into cell interior"],"gid":"g133","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c15","dok":1,"q":"Between which structures does a T tubule run?","a":"Between the paired terminal cisterns of the sarcoplasmic reticulum.","tags":["muscular","sr-ttubules"],"rubric":["Between paired terminal cisterns"],"gid":"g134","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c16","dok":1,"q":"What are the three components of a triad?","a":"One T tubule and two terminal cisterns.","options":["Two T tubules and one terminal cistern","One T tubule and two terminal cisterns","Three myofibrils","One myofibril and two Z discs"],"correctIndex":1,"explanation":"A triad is one T tubule flanked by two terminal cisterns. It is not two T tubules with one cistern, three myofibrils, or a myofibril with Z discs.","tags":["muscular","sr-ttubules"],"gid":"g135","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c17","dok":2,"q":"A skeletal muscle fiber is described as long, cylindrical, with many peripheral oval nuclei, and about ten times the size of an ordinary body cell. Which level of organization is this?","a":"The muscle fiber (the muscle cell).","options":["The fascicle","The myofibril","The muscle fiber","The sarcomere"],"correctIndex":2,"explanation":"Long, cylindrical, with many peripheral nuclei and a very large size describes the muscle fiber, the muscle cell. A fascicle is a bundle of fibers. A myofibril is a rod inside a fiber. A sarcomere is a short segment of a myofibril.","tags":["muscular","microanatomy"],"gid":"g136","unit":"m-muscle","comp":"m-muscle::microanatomy","assess":true},{"id":"c18","dok":2,"q":"Which muscle fiber component supplies the oxygen store, and which supplies the glucose store for ATP production?","a":"Myoglobin stores oxygen; glycosomes (glycogen granules) supply glucose.","tags":["muscular","microanatomy"],"rubric":["Myoglobin stores oxygen","Glycosomes supply glucose"],"gid":"g137","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c19","dok":2,"q":"Why do the mitochondria and other organelles look squashed in a skeletal muscle fiber?","a":"Because the myofibrils are so densely packed that they crowd the other organelles between them.","tags":["muscular","microanatomy"],"rubric":["Myofibrils densely packed","Crowd other organelles between them"],"gid":"g138","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c20","dok":2,"q":"Which structure carries the surface signal from the sarcolemma deep into the interior of the muscle fiber?","a":"The T tubule.","options":["The terminal cistern","The T tubule","The myofibril","The endomysium"],"correctIndex":1,"explanation":"The T tubule, an inward extension of the sarcolemma, carries the surface signal deep into the fiber. The terminal cistern is a sarcoplasmic reticulum sac. The myofibril is a contractile rod. The endomysium is a connective tissue sheath outside the cell.","tags":["muscular","sr-ttubules"],"gid":"g139","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c21","dok":2,"q":"Which membranous structure stores calcium ions inside the muscle fiber?","a":"The sarcoplasmic reticulum.","options":["The T tubule","The sarcoplasmic reticulum","The mitochondrion","The sarcolemma"],"correctIndex":1,"explanation":"The sarcoplasmic reticulum stores calcium ions. The T tubule carries the signal inward but does not store calcium. The mitochondrion supplies ATP. The sarcolemma is the outer membrane.","tags":["muscular","sr-ttubules"],"gid":"g140","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c22","dok":2,"q":"A muscle fiber part is named with the sarco prefix and refers to the cytoplasm. Which part is it?","a":"The sarcoplasm.","options":["The sarcolemma","The sarcoplasm","The sarcoplasmic reticulum","The sarcomere"],"correctIndex":1,"explanation":"The sarcoplasm is the cytoplasm of the fiber. The sarcolemma is the membrane. The sarcoplasmic reticulum is the smooth endoplasmic reticulum. The sarcomere is a contractile unit.","tags":["muscular","microanatomy"],"gid":"g141","unit":"m-muscle","comp":"m-muscle::microanatomy","assess":true},{"id":"c23","dok":2,"q":"Which even smaller rod-like structures are found within a myofibril?","a":"Myofilaments.","options":["Fascicles","Myofilaments","Terminal cisterns","T tubules"],"correctIndex":1,"explanation":"Myofilaments are the even smaller rod-like structures within a myofibril. Fascicles are bundles of whole fibers, much larger. Terminal cisterns and T tubules belong to the membranous system, not the myofibril interior.","tags":["muscular","microanatomy"],"gid":"g142","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c24","dok":2,"q":"The sarcoplasmic reticulum tubules communicate with each other at which region of the sarcomere?","a":"At the H zone.","options":["At the Z disc","At the H zone","At the A band to I band junction","At the M line"],"correctIndex":1,"explanation":"The longitudinal sarcoplasmic reticulum tubules communicate with each other at the H zone. The terminal cisterns cross at the A band to I band junction, not the H zone. The Z disc and M line are anchoring landmarks.","tags":["muscular","sr-ttubules"],"gid":"g143","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c25","dok":2,"q":"Which organelles and granules are found associated with the sarcoplasmic reticulum to provide energy for contraction?","a":"Large numbers of mitochondria and glycogen granules.","tags":["muscular","sr-ttubules"],"rubric":["Mitochondria","Glycogen granules"],"gid":"g144","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c26","dok":2,"q":"A muscle fiber organelle is the enlarged end sac of the sarcoplasmic reticulum set on either side of a T tubule. What is it?","a":"A terminal cistern.","options":["A terminal cistern","A myofibril","A triad","A glycosome"],"correctIndex":0,"explanation":"A terminal cistern is the enlarged end sac of the sarcoplasmic reticulum flanking a T tubule. A myofibril is a contractile rod. A triad is the whole unit of one T tubule and two cisterns. A glycosome is a glycogen granule.","tags":["muscular","sr-ttubules"],"gid":"g145","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c27","dok":2,"q":"Order the levels of organization from a whole muscle fiber down to a single myofilament.","a":"Muscle fiber, then myofibril, then myofilament.","tags":["muscular","microanatomy"],"rubric":["Muscle fiber","Myofibril","Myofilament"],"gid":"g146","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c28","dok":3,"q":"On an electron micrograph a technician finds one central tube flanked by two large sacs at the A band to I band junction. Name this structural unit and its three parts.","a":"A triad, made of one T tubule and two terminal cisterns.","tags":["muscular","sr-ttubules"],"rubric":["Triad","One T tubule","Two terminal cisterns"],"gid":"g147","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c29","dok":3,"q":"A muscle fiber is a very large cell yet still gets a rapid signal to every myofibril at once. Which structure makes this deep, simultaneous delivery possible?","a":"The T tubules.","options":["The myoglobin","The T tubules","The glycosomes","The epimysium"],"correctIndex":1,"explanation":"T tubules carry the surface signal deep into the fiber so every myofibril is reached at once. Myoglobin stores oxygen. Glycosomes store glycogen. The epimysium is a connective tissue sheath, not a signaling structure.","tags":["muscular","sr-ttubules"],"gid":"g148","unit":"m-muscle","comp":"m-muscle::sr-ttubules","assess":true},{"id":"c30","dok":3,"q":"A red muscle appears deeply colored and resists fatigue. Which sarcoplasmic component chiefly accounts for the red color and the oxygen store?","a":"Myoglobin.","options":["Glycogen","Myoglobin","Myosin","Sarcolemma"],"correctIndex":1,"explanation":"Myoglobin is the red oxygen-storing pigment that gives the muscle its color. Glycogen is a carbohydrate fuel, not a pigment. Myosin is a contractile protein. The sarcolemma is the membrane.","tags":["muscular","microanatomy"],"gid":"g149","unit":"m-muscle","comp":"m-muscle::microanatomy","assess":true},{"id":"c31","dok":3,"q":"A student confuses the T tubule with the sarcoplasmic reticulum. State the origin of each and their contrasting roles at the triad.","a":"The T tubule is an inward extension of the sarcolemma that carries the surface signal deep into the fiber; the sarcoplasmic reticulum is smooth endoplasmic reticulum that stores and releases calcium. At the triad the single T tubule sits between two terminal cisterns of the sarcoplasmic reticulum.","tags":["muscular","sr-ttubules"],"rubric":["T tubule: inward extension of sarcolemma, carries signal","SR: smooth ER, stores and releases calcium","Triad: one T tubule between two terminal cisterns"],"gid":"g150","unit":"m-muscle","comp":"m-muscle::sr-ttubules"},{"id":"c32","dok":3,"q":"At the triad, integral proteins protrude into the space between the T tubule and the sarcoplasmic reticulum. Which integral proteins act as voltage sensors?","a":"The integral proteins of the T tubule.","options":["The integral proteins of the T tubule","The integral proteins of the sarcoplasmic reticulum","The myosin heads","The Z disc proteins"],"correctIndex":0,"explanation":"The integral proteins of the T tubule act as voltage sensors at the triad. The integral proteins of the sarcoplasmic reticulum form gated channels through which the terminal cisterns release calcium. Myosin heads and Z disc proteins are contractile and structural elements, not triad voltage sensors.","tags":["muscular","sr-ttubules"],"gid":"g151","unit":"m-muscle","comp":"m-muscle::sr-ttubules","assess":true},{"id":"c33","dok":3,"q":"At the triad, which integral proteins form the gated channels that release calcium from the terminal cisterns?","a":"The integral proteins of the sarcoplasmic reticulum.","options":["The integral proteins of the T tubule","The integral proteins of the sarcoplasmic reticulum","Dystrophin","Tropomyosin"],"correctIndex":1,"explanation":"The integral proteins of the sarcoplasmic reticulum form the gated channels that release calcium from the terminal cisterns. The T tubule proteins are the voltage sensors. Dystrophin links thin filaments to the sarcolemma. Tropomyosin is a thin-filament regulatory protein.","tags":["muscular","sr-ttubules"],"gid":"g152","unit":"m-muscle","comp":"m-muscle::sr-ttubules","assess":true},{"id":"c34","dok":3,"q":"A muscle cell contains far more glycogen granules than an ordinary body cell. What is the anatomical name for these granules and their purpose?","a":"Glycosomes, which store glycogen to provide glucose for ATP production during muscle activity.","tags":["muscular","microanatomy"],"rubric":["Glycosomes","Store glycogen for glucose","For ATP during activity"],"gid":"g153","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c35","dok":3,"q":"A histologist wants to confirm a cell is a skeletal muscle fiber rather than a cardiac cell. Which nuclear feature distinguishes the skeletal fiber?","a":"The skeletal fiber has many peripheral nuclei just under the sarcolemma, whereas a cardiac cell typically has a single central nucleus.","tags":["muscular","microanatomy"],"rubric":["Skeletal: many peripheral nuclei under sarcolemma","Cardiac: single central nucleus"],"gid":"g154","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c36","dok":3,"q":"Explain why myofibrils occupying about 80 percent of the fiber volume forces the mitochondria into rows between them.","a":"Because the myofibrils are so densely packed and take up most of the volume, the mitochondria and other organelles are squeezed into the narrow spaces (rows) between the myofibrils.","tags":["muscular","microanatomy"],"rubric":["Myofibrils densely packed (about 80 percent)","Mitochondria squeezed into rows between them"],"gid":"g155","unit":"m-muscle","comp":"m-muscle::microanatomy"},{"id":"c1","dok":1,"q":"What is a sarcomere?","a":"The smallest contractile unit and functional unit of skeletal muscle, the region of a myofibril between two Z discs.","tags":["muscular","sarcomere"],"rubric":["Smallest contractile/functional unit","Region of myofibril between two Z discs"],"gid":"g156","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c2","dok":1,"q":"A sarcomere extends between which two structures?","a":"Between two Z discs.","options":["Between two M lines","Between two Z discs","Between two H zones","Between two A bands"],"correctIndex":1,"explanation":"A sarcomere is the region of a myofibril between two Z discs. The M lines, H zones, and A bands are landmarks inside the sarcomere, not its borders.","tags":["muscular","sarcomere"],"gid":"g157","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c3","dok":1,"q":"What causes the striations seen along a myofibril?","a":"A repeating series of dark and light bands (A bands and I bands) along its length.","tags":["muscular","sarcomere"],"rubric":["Repeating dark and light bands","A bands and I bands"],"gid":"g158","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c4","dok":1,"q":"Which band of the sarcomere is the dark band?","a":"The A band.","options":["The A band","The I band","The H zone","The Z disc"],"correctIndex":0,"explanation":"The A band is the dark band of the sarcomere. The I band is the light band. The H zone is the lighter region within the A band. The Z disc is a line, not a band.","tags":["muscular","sarcomere"],"gid":"g159","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c5","dok":1,"q":"Which band of the sarcomere is the light band?","a":"The I band.","options":["The A band","The I band","The H zone","The M line"],"correctIndex":1,"explanation":"The I band is the light band. The A band is the dark band. The H zone is a lighter region within the A band. The M line is a line within the H zone.","tags":["muscular","sarcomere"],"gid":"g160","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c6","dok":1,"q":"What is the lighter region found among the dark A bands called?","a":"The H zone.","options":["The I band","The H zone","The Z disc","The M line"],"correctIndex":1,"explanation":"The H zone is the lighter region within the dark A band. The I band is the light band outside the A band. The Z disc and M line are lines, not zones.","tags":["muscular","sarcomere"],"gid":"g161","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c7","dok":1,"q":"The H zone is bisected by which dark line?","a":"The M line.","options":["The Z disc","The M line","The A line","The I line"],"correctIndex":1,"explanation":"The H zone is bisected by the M line. The Z disc interrupts the I band, not the H zone. There are no structures called the A line or I line.","tags":["muscular","sarcomere"],"gid":"g162","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c8","dok":1,"q":"Which protein forms the M line?","a":"Myomesin.","options":["Titin","Myomesin","Actin","Tropomyosin"],"correctIndex":1,"explanation":"The M line is formed by molecules of the protein myomesin. Titin spans from the Z disc to the thick filament. Actin makes the thin filament. Tropomyosin is a regulatory protein on the thin filament.","tags":["muscular","sarcomere"],"gid":"g163","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c9","dok":1,"q":"The Z line (Z disc) is the middle interruption of which band?","a":"The I band.","options":["The A band","The I band","The H zone","The M line"],"correctIndex":1,"explanation":"The Z disc is the middle interruption of the I band. The A band is the dark band. The H zone is within the A band. The M line is within the H zone.","tags":["muscular","sarcomere"],"gid":"g164","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c10","dok":1,"q":"What are myofilaments made of, and what are they responsible for?","a":"Actin and myosin, which are responsible for motility and shape change in cells and are most developed in muscle fibers.","tags":["muscular","filaments"],"rubric":["Actin and myosin","Responsible for motility and shape change","Most developed in muscle fibers"],"gid":"g165","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c11","dok":1,"q":"Which protein makes up the thick filament?","a":"Myosin.","options":["Actin","Myosin","Tropomyosin","Titin"],"correctIndex":1,"explanation":"The thick filament is made of myosin. Actin makes the thin filament. Tropomyosin is a regulatory protein. Titin is a structural protein.","tags":["muscular","filaments"],"gid":"g166","unit":"m-muscle","comp":"m-muscle::filaments","assess":true},{"id":"c12","dok":1,"q":"Where are the thick filaments located within the sarcomere, and where are they connected?","a":"They are centrally located, extend the entire length of the A band, and are connected at the M line.","tags":["muscular","filaments"],"rubric":["Centrally located","Extend full length of A band","Connected at the M line"],"gid":"g167","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c13","dok":1,"q":"Which protein makes up the thin filament?","a":"Actin.","options":["Myosin","Actin","Myomesin","Dystrophin"],"correctIndex":1,"explanation":"The thin filament is made of actin. Myosin makes the thick filament. Myomesin forms the M line. Dystrophin links thin filaments to the sarcolemma.","tags":["muscular","filaments"],"gid":"g168","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c14","dok":1,"q":"Where do the thin filaments extend, and what anchors them?","a":"They extend across the I band and partway into the A band, and they are anchored by alpha-actinin at the Z disc.","tags":["muscular","filaments"],"rubric":["Extend across I band, partway into A band","Anchored by alpha-actinin at Z disc"],"gid":"g169","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c15","dok":1,"q":"Which protein forms the elastic filament that extends from the Z disc and connects each myofibril to the next?","a":"Desmin (an intermediate filament).","options":["Desmin","Myosin","Actin","Nebulin"],"correctIndex":0,"explanation":"Desmin, an intermediate filament, forms the elastic filament that extends from the Z disc and connects adjacent myofibrils. Myosin and actin form the thick and thin filaments. Nebulin is a structural protein along the thin filament.","tags":["muscular","filaments"],"gid":"g170","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c16","dok":1,"q":"How many heavy and light polypeptide chains make up a myosin molecule?","a":"Two heavy chains and four light chains.","tags":["muscular","proteins"],"rubric":["Two heavy chains","Four light chains"],"gid":"g171","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c17","dok":1,"q":"What is the function of the globular heads of myosin?","a":"During contraction they link the thick and thin filaments together, forming cross-bridges, and swivel around their point of attachment to act as motors that generate force.","tags":["muscular","proteins"],"rubric":["Link thick and thin filaments (cross-bridges)","Swivel to act as motors generating force"],"gid":"g172","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c18","dok":1,"q":"About how many myosin molecules are bundled in one thick filament?","a":"About 300.","options":["About 30","About 100","About 300","About 3000"],"correctIndex":2,"explanation":"One thick filament contains about 300 bundled myosin molecules. The other values are off by an order of magnitude.","tags":["muscular","proteins"],"gid":"g173","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c19","dok":1,"q":"What structural feature do actin subunits carry on the thin filament?","a":"Active sites to which myosin heads attach during contraction.","tags":["muscular","proteins"],"rubric":["Active sites for myosin heads"],"gid":"g174","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c20","dok":1,"q":"Which regulatory protein is rod-shaped, spirals to stiffen and stabilize actin, and blocks the myosin-binding sites in relaxed muscle?","a":"Tropomyosin.","options":["Troponin","Tropomyosin","Titin","Nebulin"],"correctIndex":1,"explanation":"Tropomyosin is the rod-shaped regulatory protein that stiffens actin and blocks myosin-binding sites in relaxed muscle. Troponin is the globular three-part complex. Titin and nebulin are structural proteins, not the site-blocking regulatory protein.","tags":["muscular","proteins"],"gid":"g175","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c21","dok":1,"q":"Troponin is a complex of how many polypeptide subunits, and what are they named?","a":"Three subunits: TnI, TnT, and TnC.","tags":["muscular","proteins"],"rubric":["Three subunits","TnI","TnT","TnC"],"gid":"g176","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c22","dok":1,"q":"Which troponin subunit binds calcium ions?","a":"TnC.","options":["TnI","TnT","TnC","TnM"],"correctIndex":2,"explanation":"TnC binds calcium ions. TnI is the inhibitory subunit that binds actin. TnT binds troponin to tropomyosin and helps position it on actin. There is no subunit named TnM.","tags":["muscular","proteins"],"gid":"g177","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c23","dok":1,"q":"Which structural protein forms the elastic filament, extends from the Z disc to the thick filament, and attaches to the M line?","a":"Titin.","options":["Titin","Dystrophin","Nebulin","Myomesin"],"correctIndex":0,"explanation":"Titin forms the elastic filament, extending from the Z disc to the thick filament and attaching at the M line. Dystrophin links thin filaments to the sarcolemma. Nebulin runs along the thin filament. Myomesin binds thick filaments at the M line.","tags":["muscular","proteins"],"gid":"g178","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c24","dok":1,"q":"Which structural protein links the thin filaments to the integral proteins of the sarcolemma?","a":"Dystrophin.","options":["Titin","Dystrophin","Nebulin","Myomesin"],"correctIndex":1,"explanation":"Dystrophin links the thin filaments to the integral proteins of the sarcolemma. Titin spans the Z disc to the M line. Nebulin runs along the thin filament. Myomesin is at the M line.","tags":["muscular","proteins"],"gid":"g179","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c25","dok":2,"q":"Which region of the sarcomere contains only thin filaments?","a":"The I band.","options":["The A band","The H zone","The I band","The M line"],"correctIndex":2,"explanation":"The I band contains only thin filaments. The A band contains thick filaments across its full width. The H zone contains only thick filaments. The M line is a protein line, not a filament region.","tags":["muscular","sarcomere"],"gid":"g180","unit":"m-muscle","comp":"m-muscle::sarcomere","assess":true},{"id":"c26","dok":2,"q":"Which region of the sarcomere contains only thick filaments?","a":"The H zone.","options":["The I band","The H zone","The Z disc","The zone of overlap"],"correctIndex":1,"explanation":"The H zone, the lighter center of the A band, contains only thick filaments. The I band contains only thin filaments. The Z disc anchors thin filaments. The zone of overlap contains both filament types.","tags":["muscular","sarcomere"],"gid":"g181","unit":"m-muscle","comp":"m-muscle::sarcomere","assess":true},{"id":"c27","dok":2,"q":"Which protein anchors the thin filament at the Z disc?","a":"Alpha-actinin.","options":["Alpha-actinin","Myomesin","Titin","Desmin"],"correctIndex":0,"explanation":"Alpha-actinin anchors the thin filament at the Z disc. Myomesin forms the M line. Titin spans from the Z disc to the thick filament. Desmin forms the elastic filament linking myofibrils.","tags":["muscular","filaments"],"gid":"g182","unit":"m-muscle","comp":"m-muscle::filaments","assess":true},{"id":"c28","dok":2,"q":"Which two proteins together are the regulatory proteins of the thin filament?","a":"Tropomyosin and troponin.","tags":["muscular","proteins"],"rubric":["Tropomyosin","Troponin"],"gid":"g183","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c29","dok":2,"q":"Which troponin subunit is the inhibitory subunit that binds to actin?","a":"TnI.","options":["TnI","TnT","TnC","TnA"],"correctIndex":0,"explanation":"TnI is the inhibitory subunit that binds to actin. TnT binds troponin to tropomyosin. TnC binds calcium ions. There is no subunit named TnA.","tags":["muscular","proteins"],"gid":"g184","unit":"m-muscle","comp":"m-muscle::proteins","assess":true},{"id":"c30","dok":2,"q":"Which troponin subunit binds troponin to tropomyosin and helps position it on actin?","a":"TnT.","options":["TnI","TnT","TnC","TnP"],"correctIndex":1,"explanation":"TnT binds troponin to tropomyosin and helps position it on actin. TnI is the inhibitory subunit that binds actin. TnC binds calcium. There is no subunit named TnP.","tags":["muscular","proteins"],"gid":"g185","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c31","dok":2,"q":"A filament is described as centrally located, extending the full length of the A band, and joined at the M line. Which filament is it, and what protein composes it?","a":"The thick filament, composed of myosin.","tags":["muscular","filaments"],"rubric":["Thick filament","Composed of myosin"],"gid":"g186","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c32","dok":2,"q":"A myosin molecule has a rod-like tail attached by a flexible hinge to two globular heads. What is the tail made of?","a":"Two intertwined helical heavy polypeptide chains.","tags":["muscular","proteins"],"rubric":["Two intertwined helical heavy chains"],"gid":"g187","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c33","dok":2,"q":"Match the sarcomere landmark to what it anchors: the Z disc and the M line.","a":"The Z disc anchors the thin filaments; the M line anchors (connects) the thick filaments.","tags":["muscular","sarcomere"],"rubric":["Z disc anchors thin filaments","M line connects thick filaments"],"gid":"g188","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c34","dok":2,"q":"Which structural protein spans from the Z disc to the M line, holds the thick filaments in place, and helps the muscle spring back after stretching?","a":"Titin.","options":["Nebulin","Titin","Dystrophin","Myomesin"],"correctIndex":1,"explanation":"Titin spans from the Z disc to the M line, holds the thick filaments in place, and provides elastic recoil after stretch. Nebulin runs along the thin filament. Dystrophin links thin filaments to the sarcolemma. Myomesin binds thick filaments at the M line.","tags":["muscular","proteins"],"gid":"g189","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c35","dok":2,"q":"Which proteins bind filaments and sarcomeres together to maintain their alignment?","a":"Nebulin, myomesin, and C proteins.","tags":["muscular","proteins"],"rubric":["Nebulin","Myomesin","C proteins"],"gid":"g190","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c36","dok":2,"q":"The thin filament is anchored at the Z disc and the thick filament is joined at the M line. Which structure sits at the border of the sarcomere?","a":"The Z disc.","options":["The M line","The Z disc","The H zone","The A band"],"correctIndex":1,"explanation":"The Z disc sits at the border of the sarcomere and anchors the thin filaments. The M line is at the center. The H zone and A band are interior regions.","tags":["muscular","sarcomere"],"gid":"g191","unit":"m-muscle","comp":"m-muscle::sarcomere"},{"id":"c37","dok":3,"q":"Across half a sarcomere from the border toward the center, order these landmarks: Z disc, I band, A band, H zone, M line.","a":"Z disc, I band, A band, H zone, M line.","options":["M line, H zone, A band, I band, Z disc","Z disc, A band, I band, H zone, M line","Z disc, I band, H zone, A band, M line","Z disc, I band, A band, H zone, M line"],"correctIndex":3,"explanation":"Starting at the Z disc border and moving to the center, the order is Z disc, then the I band, then the A band, with the H zone inside the A band, and the M line at the very center. The other sequences misplace the A band or the H zone, since the H zone lies inside the A band.","tags":["muscular","sarcomere"],"gid":"g192","unit":"m-muscle","comp":"m-muscle::sarcomere","assess":true},{"id":"c38","dok":3,"q":"A relaxed muscle cannot form cross-bridges because a rod-shaped protein covers the active sites on actin. Name that protein and describe its resting position.","a":"Tropomyosin, which spirals around actin and blocks the myosin-binding sites in relaxed muscle.","tags":["muscular","proteins"],"rubric":["Tropomyosin","Spirals around actin, blocks myosin-binding sites at rest"],"gid":"g193","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c39","dok":3,"q":"A three-part globular protein complex on the thin filament includes one subunit that binds actin, one that binds tropomyosin, and one that binds calcium. Name the complex and its three subunits with their jobs.","a":"Troponin: TnI binds actin (inhibitory), TnT binds tropomyosin and positions it on actin, and TnC binds calcium ions.","tags":["muscular","proteins"],"rubric":["Troponin","TnI binds actin (inhibitory)","TnT binds tropomyosin, positions on actin","TnC binds calcium ions"],"gid":"g194","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c40","dok":3,"q":"A structural protein links the thin filaments to the sarcolemma and, when faulty, is associated with muscular dystrophy. Which protein is described?","a":"Dystrophin.","options":["Titin","Dystrophin","Nebulin","Myomesin"],"correctIndex":1,"explanation":"Dystrophin links the thin filaments to the integral proteins of the sarcolemma and is associated with muscular dystrophy when faulty. Titin spans the Z disc to the M line. Nebulin runs along the thin filament. Myomesin forms the M line.","tags":["muscular","proteins"],"gid":"g195","unit":"m-muscle","comp":"m-muscle::proteins","assess":true},{"id":"c41","dok":3,"q":"Two filaments are compared: one is thick, centrally placed, joined at the M line, and the other is thin, extends across the I band, and is anchored at the Z disc. Name each filament and its main protein.","a":"The thick filament is myosin, joined at the M line; the thin filament is actin, anchored at the Z disc.","tags":["muscular","filaments"],"rubric":["Thick filament: myosin, joined at M line","Thin filament: actin, anchored at Z disc"],"gid":"g196","unit":"m-muscle","comp":"m-muscle::filaments"},{"id":"c42","dok":3,"q":"A student needs to tell titin from myomesin. State where each sits in the sarcomere and its role.","a":"Titin forms the elastic filament that runs from the Z disc to the thick filament and attaches at the M line, holding thick filaments in place and giving elastic recoil; myomesin sits at the M line and binds the thick filaments together there.","tags":["muscular","proteins"],"rubric":["Titin: Z disc to thick filament, attaches at M line, elastic recoil","Myomesin: at M line, binds thick filaments together"],"gid":"g197","unit":"m-muscle","comp":"m-muscle::proteins"},{"id":"c43","dok":3,"q":"A filament appears as twisted golf-club-shaped subunits, each bearing an active site for myosin. Which filament and protein are described?","a":"The thin filament, made of actin.","options":["The thick filament, made of myosin","The thin filament, made of actin","The elastic filament, made of desmin","The thin filament, made of tropomyosin"],"correctIndex":1,"explanation":"Twisted golf-club-shaped subunits bearing myosin active sites describe the actin thin filament. The thick filament is myosin with paired globular heads, not golf-club subunits. The elastic filament is desmin. Tropomyosin is a regulatory protein on the thin filament, not the filament itself.","tags":["muscular","proteins"],"gid":"g198","unit":"m-muscle","comp":"m-muscle::proteins","assess":true},{"id":"c44","dok":3,"q":"An intermediate filament extends from one Z disc to the next, tying neighboring myofibrils together. Name this filament and its protein.","a":"The elastic filament, made of desmin.","options":["The thick filament, made of myosin","The elastic filament, made of desmin","The thin filament, made of actin","The titin filament of the A band"],"correctIndex":1,"explanation":"An intermediate filament running Z disc to Z disc and tying myofibrils together is the elastic filament made of desmin. The thick filament is myosin within one sarcomere. The thin filament is actin. Titin runs from the Z disc to the M line within a sarcomere, not between adjacent myofibrils.","tags":["muscular","filaments"],"gid":"g199","unit":"m-muscle","comp":"m-muscle::filaments","assess":true},{"id":"c1","dok":1,"q":"What four components make up the lymphatic system?","a":"Lymph (fluid), lymphatic vessels, structures and organs containing lymphatic tissue, and red bone marrow.","tags":["lymphatic","overview"],"rubric":["Lymph (fluid)","Lymphatic vessels","Structures and organs with lymphatic tissue","Red bone marrow"],"gid":"g200","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c2","dok":1,"q":"What is lymph?","a":"Interstitial fluid once it has entered the lymphatic vessels; a clear, pale-yellow fluid containing plasma and white blood cells.","tags":["lymphatic","lymph"],"rubric":["Interstitial fluid inside lymphatic vessels","Clear pale-yellow fluid","Plasma and white blood cells"],"gid":"g201","unit":"m-lymphatic","comp":"m-lymphatic::lymph"},{"id":"c3","dok":1,"q":"What is the only real difference between interstitial fluid and lymph?","a":"Their location. Interstitial fluid sits between cells; lymph is the same fluid once it is inside lymphatic vessels and tissues.","tags":["lymphatic","lymph"],"rubric":["Location","Interstitial fluid sits between cells","Lymph is the same fluid inside lymphatic vessels"],"gid":"g202","unit":"m-lymphatic","comp":"m-lymphatic::lymph"},{"id":"c4","dok":1,"q":"What is chyle?","a":"A creamy-white, lipid-rich lymph that drains from the small intestine.","tags":["lymphatic","lacteals"],"rubric":["Creamy-white lipid-rich lymph","Drains from the small intestine"],"gid":"g203","unit":"m-lymphatic","comp":"m-lymphatic::lacteals"},{"id":"c5","dok":1,"q":"Which fat-soluble vitamins do lymphatic vessels help transport from the GI tract?","a":"Vitamins A, D, E, and K.","tags":["lymphatic","lacteals"],"rubric":["Vitamin A","Vitamin D","Vitamin E","Vitamin K"],"gid":"g204","unit":"m-lymphatic","comp":"m-lymphatic::lacteals"},{"id":"c6","dok":1,"q":"What specialized connective tissue forms lymphatic tissue?","a":"Reticular connective tissue containing large numbers of lymphocytes.","tags":["lymphatic","overview"],"rubric":["Reticular connective tissue","Contains many lymphocytes"],"gid":"g205","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c7","dok":1,"q":"Which two lymphocyte types are resident in lymphatic tissue?","a":"B cells and T cells.","tags":["lymphatic","overview"],"rubric":["B cells","T cells"],"gid":"g206","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c8","dok":1,"q":"Where do lymphatic capillaries begin?","a":"In the spaces between cells (tissue spaces), as blind-ended tubes closed at one end.","tags":["lymphatic","capillaries"],"rubric":["In the tissue spaces between cells","Blind-ended tubes closed at one end"],"gid":"g207","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c9","dok":1,"q":"Name three avascular or specialized tissues that lack lymphatic capillaries.","a":"Cartilage, epidermis, cornea, CNS, parts of the spleen, and red bone marrow (any three).","tags":["lymphatic","capillaries"],"rubric":["Cartilage","Epidermis","Cornea","CNS","Parts of the spleen","Red bone marrow (any three)"],"gid":"g208","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c10","dok":1,"q":"What are anchoring filaments?","a":"Elastic-fiber filaments that attach lymphatic capillaries to surrounding tissue and pull the endothelial cells apart when interstitial fluid accumulates.","tags":["lymphatic","capillaries"],"rubric":["Elastic-fiber filaments anchoring capillaries to tissue","Pull endothelial cells apart when fluid accumulates"],"gid":"g209","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c11","dok":1,"q":"What are lacteals?","a":"Specialized lymphatic capillaries in the villi of the small intestine that absorb dietary lipids.","tags":["lymphatic","lacteals"],"rubric":["Specialized lymphatic capillaries","In the villi of the small intestine","Absorb dietary lipids"],"gid":"g210","unit":"m-lymphatic","comp":"m-lymphatic::lacteals"},{"id":"c12","dok":1,"q":"What structural ending does a lymphatic capillary have?","a":"A blind ending, closed at one end.","tags":["lymphatic","capillaries"],"rubric":["A blind ending (closed at one end)"],"gid":"g211","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c13","dok":1,"q":"Compared with blood capillaries, how permeable are lymphatic capillaries?","a":"They have greater permeability and can absorb large molecules such as proteins and lipids.","tags":["lymphatic","capillaries"],"rubric":["Greater permeability","Absorb large molecules (proteins, lipids)"],"gid":"g212","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c14","dok":1,"q":"How does the diameter of a lymphatic capillary compare with that of a blood capillary?","a":"The lymphatic capillary has a larger diameter.","tags":["lymphatic","capillaries"],"rubric":["Larger diameter"],"gid":"g213","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c15","dok":1,"q":"What structural feature ensures one-way movement of lymph in lymphatic vessels?","a":"Valves.","tags":["lymphatic","vessels-valves"],"rubric":["Valves"],"gid":"g214","unit":"m-lymphatic","comp":"m-lymphatic::vessels-valves"},{"id":"c16","dok":1,"q":"In what order does lymph travel from the tissues toward the trunks?","a":"Lymphatic capillaries, then lymphatic (collecting) vessels, then lymph nodes, then lymph trunks.","tags":["lymphatic","vessels-valves"],"rubric":["Lymphatic capillaries","Lymphatic (collecting) vessels","Lymph nodes","Lymph trunks"],"gid":"g215","unit":"m-lymphatic","comp":"m-lymphatic::vessels-valves"},{"id":"c17","dok":2,"q":"Which component of the lymphatic system is lymph?","a":"The fluid.","options":["The fluid","The transport vessels","The filtering organ tissue","The site of blood cell production"],"correctIndex":0,"explanation":"Lymph is the fluid component. The transport vessels are the lymphatic vessels. Filtering organ tissue is lymphatic tissue in nodes and organs. Blood cell production is a red bone marrow function.","tags":["lymphatic","lymph"],"gid":"g216","unit":"m-lymphatic","comp":"m-lymphatic::lymph","assess":true},{"id":"c18","dok":2,"q":"Which statement best describes lymph?","a":"A clear, pale-yellow fluid of plasma and white blood cells found inside lymphatic vessels.","options":["A clear, pale-yellow fluid of plasma and white blood cells found inside lymphatic vessels","Oxygen-rich fluid pumped through arteries by the heart","Dense connective tissue that wraps a lymph node","Worn-out erythrocytes broken down in the spleen"],"correctIndex":0,"explanation":"Lymph is the clear, pale-yellow fluid of plasma and white blood cells inside lymphatic vessels. Arterial oxygen-rich fluid is blood plasma. The dense connective tissue wrapping is a node capsule. Worn-out erythrocytes are debris cleared by the spleen, not lymph.","tags":["lymphatic","lymph"],"gid":"g217","unit":"m-lymphatic","comp":"m-lymphatic::lymph","assess":true},{"id":"c19","dok":2,"q":"Which lymphatic capillaries carry chyle?","a":"Lacteals of the small intestine.","options":["Lacteals of the small intestine","Capillaries of the epidermis","Capillaries of the cornea","Capillaries of the CNS"],"correctIndex":0,"explanation":"Lacteals in the small intestine absorb dietary lipids, producing creamy chyle. The epidermis, cornea, and CNS are avascular or specialized tissues that lack lymphatic capillaries entirely, so none of them carries chyle.","tags":["lymphatic","lacteals"],"gid":"g218","unit":"m-lymphatic","comp":"m-lymphatic::lacteals"},{"id":"c20","dok":2,"q":"What lets interstitial fluid flow into a lymphatic capillary but not back out?","a":"Overlapping endothelial cells that act as one-way flap valves.","options":["Overlapping endothelial cells that act as one-way flap valves","A thick smooth muscle wall around the capillary","Anchoring filaments sealing the lumen shut","A basement membrane fused to blood capillaries"],"correctIndex":0,"explanation":"The overlapping endothelial cells form one-way mini-valves that open inward. A thick smooth muscle wall is not present on a capillary. Anchoring filaments pull the cells apart to open them, not seal the lumen. A fused basement membrane is not the mechanism.","tags":["lymphatic","capillaries"],"gid":"g219","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c21","dok":2,"q":"Which of these is a true characteristic of lymphatic capillaries?","a":"They resemble small veins but have thinner walls and more valves.","options":["They resemble small veins but have thinner walls and more valves","They are open at both ends like a continuous tube","They are less permeable than blood capillaries","They have a smaller diameter than blood capillaries"],"correctIndex":0,"explanation":"Lymphatic capillaries resemble small veins with thinner walls and more valves. They are blind-ended, not open at both ends. They are more permeable, not less. They have a larger diameter than blood capillaries, not smaller.","tags":["lymphatic","capillaries"],"gid":"g220","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c22","dok":2,"q":"What do anchoring filaments do when interstitial fluid builds up?","a":"They pull the endothelial cells apart so more fluid can enter the capillary.","options":["They pull the endothelial cells apart so more fluid can enter the capillary","They seal the capillary to stop fluid entry","They pump lymph toward the heart","They form the valves inside collecting vessels"],"correctIndex":0,"explanation":"Anchoring filaments contain elastic fibers and pull the cells apart, opening the capillary to accumulating fluid. They do not seal the capillary. They do not pump lymph. The valves of collecting vessels are separate structures.","tags":["lymphatic","capillaries"],"gid":"g221","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c23","dok":2,"q":"Which vessel class carries lymph directly out of the lymphatic capillaries?","a":"Lymphatic (collecting) vessels.","options":["Lymphatic (collecting) vessels","Lymph trunks","The thoracic duct","The subclavian veins"],"correctIndex":0,"explanation":"Collecting vessels receive lymph from capillaries first. Trunks are larger and drain whole regions further downstream. The thoracic duct is larger still. The subclavian veins are the final blood destination, not the immediate vessel.","tags":["lymphatic","vessels-valves"],"gid":"g222","unit":"m-lymphatic","comp":"m-lymphatic::vessels-valves","assess":true},{"id":"c24","dok":2,"q":"Which is NOT one of the three primary functions of the lymphatic system?","a":"Pumping oxygenated blood to the tissues.","options":["Pumping oxygenated blood to the tissues","Draining excess interstitial fluid","Transporting dietary lipids","Carrying out immune responses"],"correctIndex":0,"explanation":"Pumping oxygenated blood is a cardiovascular function, not lymphatic. Draining excess interstitial fluid, transporting dietary lipids, and carrying out immune responses are the three primary lymphatic functions.","tags":["lymphatic","overview"],"gid":"g223","unit":"m-lymphatic","comp":"m-lymphatic::overview","assess":true},{"id":"c25","dok":2,"q":"Which cell type is the lymphocyte, found throughout lymphatic tissue?","a":"An agranular white blood cell.","options":["An agranular white blood cell","A granular white blood cell","A red blood cell","A platelet"],"correctIndex":0,"explanation":"Lymphocytes are agranular white blood cells. Granular white blood cells are neutrophils, eosinophils, and basophils. Red blood cells carry oxygen. Platelets are cell fragments for clotting.","tags":["lymphatic","overview"],"gid":"g224","unit":"m-lymphatic","comp":"m-lymphatic::overview","assess":true},{"id":"c26","dok":2,"q":"Reticular connective tissue is the framework of lymphatic tissue. What kind of fibers form its meshwork?","a":"Reticular fibers.","options":["Reticular fibers","Thick collagen bundles only","Elastic fibers only","Muscle fibers"],"correctIndex":0,"explanation":"Reticular connective tissue is built of fine reticular fibers forming a supportive mesh for lymphocytes. Thick collagen bundles form dense connective tissue. Elastic fibers dominate elastic tissue. Muscle fibers are not connective tissue.","tags":["lymphatic","overview"],"gid":"g225","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c27","dok":3,"q":"A vessel is described as a blind-ended tube in the tissue spaces, more permeable than a blood capillary. Which vessel is it?","a":"A lymphatic capillary.","options":["A lymphatic capillary","A lymphatic collecting vessel","A lymph trunk","The thoracic duct"],"correctIndex":0,"explanation":"A blind-ended, highly permeable tube in the tissue spaces is a lymphatic capillary. A collecting vessel is larger and valved. A trunk drains a whole region. The thoracic duct is the largest lymphatic vessel.","tags":["lymphatic","capillaries"],"gid":"g226","unit":"m-lymphatic","comp":"m-lymphatic::capillaries","assess":true},{"id":"c28","dok":3,"q":"After a fatty meal, a gut vessel fills with creamy-white fluid. Which structure is this, and what is the fluid?","a":"A lacteal carrying chyle.","options":["A lacteal carrying chyle","A blood capillary carrying plasma","A lymph node full of lymph","A collecting vessel carrying serum"],"correctIndex":0,"explanation":"A creamy-white, lipid-rich gut vessel is a lacteal, and its fluid is chyle. A blood capillary carries red blood, not creamy fluid. A lymph node is an organ, not a vessel filling with chyle. Serum is a blood product, not the gut lymph.","tags":["lymphatic","lacteals"],"gid":"g227","unit":"m-lymphatic","comp":"m-lymphatic::lacteals","assess":true},{"id":"c29","dok":3,"q":"A patient has swelling in avascular tissue where lymphatic capillaries are absent. Which of these tissues could this be?","a":"The cornea.","options":["The cornea","The dermis of the skin","Skeletal muscle","The wall of the intestine"],"correctIndex":0,"explanation":"The cornea is avascular and lacks lymphatic capillaries. The dermis, skeletal muscle, and intestinal wall are all vascular tissues that do contain lymphatic capillaries.","tags":["lymphatic","capillaries"],"gid":"g228","unit":"m-lymphatic","comp":"m-lymphatic::capillaries","assess":true},{"id":"c30","dok":3,"q":"Which structure allows a lymphatic capillary to admit large proteins that a blood capillary cannot?","a":"Its highly permeable overlapping endothelium acting as flap valves.","options":["Its highly permeable overlapping endothelium acting as flap valves","A continuous fused basement membrane","A muscular pump in its wall","A row of one-way trunk valves"],"correctIndex":0,"explanation":"The permeable, overlapping endothelium of a lymphatic capillary admits large proteins and lipids. A continuous fused basement membrane would block them. There is no muscular pump in a capillary wall. Trunk valves are downstream and unrelated to this uptake.","tags":["lymphatic","capillaries"],"gid":"g229","unit":"m-lymphatic","comp":"m-lymphatic::capillaries","assess":true},{"id":"c31","dok":1,"q":"What is the first of the three primary functions of the lymphatic system?","a":"Draining excess interstitial fluid from tissue spaces into lymphatic vessels.","tags":["lymphatic","overview"],"rubric":["Draining excess interstitial fluid","From tissue spaces into lymphatic vessels"],"gid":"g230","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c32","dok":2,"q":"Which best describes the wall of a lymphatic collecting vessel compared with a vein?","a":"Thinner walls with more valves.","options":["Thinner walls with more valves","Thicker walls with fewer valves","No valves at all","A muscular pumping chamber"],"correctIndex":0,"explanation":"Lymphatic vessels have thinner walls and more valves than veins of similar size. They are not thicker with fewer valves, they are not valveless, and they have no pumping chamber of their own.","tags":["lymphatic","vessels-valves"],"gid":"g231","unit":"m-lymphatic","comp":"m-lymphatic::vessels-valves","assess":true},{"id":"c33","dok":1,"q":"Which vitamins absorbed by the GI tract are described as fat-soluble?","a":"A, D, E, and K.","tags":["lymphatic","lacteals"],"rubric":["Vitamin A","Vitamin D","Vitamin E","Vitamin K"],"gid":"g232","unit":"m-lymphatic","comp":"m-lymphatic::lacteals"},{"id":"c34","dok":3,"q":"A histology slide shows a fine mesh of reticular fibers packed with agranular white blood cells. What tissue is this?","a":"Lymphatic tissue.","options":["Lymphatic tissue","Dense regular connective tissue","Adipose tissue","Hyaline cartilage"],"correctIndex":0,"explanation":"A reticular-fiber mesh packed with lymphocytes is lymphatic tissue. Dense regular connective tissue is parallel collagen. Adipose tissue is fat cells. Hyaline cartilage is a firm matrix with chondrocytes.","tags":["lymphatic","overview"],"gid":"g233","unit":"m-lymphatic","comp":"m-lymphatic::overview","assess":true},{"id":"c35","dok":2,"q":"One-way valves in lymphatic vessels prevent which of the following?","a":"Backflow of lymph.","options":["Backflow of lymph","Entry of interstitial fluid","Absorption of dietary lipids","Formation of lymphocytes"],"correctIndex":0,"explanation":"Valves prevent backflow, keeping lymph moving one way. They do not block interstitial fluid entry, which happens at capillaries. They do not govern lipid absorption or lymphocyte formation.","tags":["lymphatic","vessels-valves"],"gid":"g234","unit":"m-lymphatic","comp":"m-lymphatic::vessels-valves"},{"id":"c36","dok":1,"q":"Where in the small intestine are lacteals located?","a":"In the villi (in the lining) of the small intestine.","tags":["lymphatic","lacteals"],"rubric":["In the villi (lining) of the small intestine"],"gid":"g235","unit":"m-lymphatic","comp":"m-lymphatic::lacteals"},{"id":"c37","dok":2,"q":"Which of these tissues would you expect to contain lymphatic capillaries?","a":"The dermis of the skin.","options":["The dermis of the skin","The epidermis","Hyaline cartilage","The central nervous system"],"correctIndex":0,"explanation":"The dermis is vascular and holds lymphatic capillaries. The epidermis, cartilage, and CNS lack lymphatic capillaries because they are avascular or specialized.","tags":["lymphatic","capillaries"],"gid":"g236","unit":"m-lymphatic","comp":"m-lymphatic::capillaries"},{"id":"c38","dok":3,"q":"Chyle appears creamy white rather than clear. Which of its contents explains this?","a":"Its high dietary lipid content.","options":["Its high dietary lipid content","A high red blood cell count","Dissolved oxygen","Excess platelets"],"correctIndex":0,"explanation":"Chyle is creamy because it is rich in dietary lipids absorbed by lacteals. Red blood cells would make it red. Dissolved oxygen does not color fluid. Platelets are not the source of the creamy appearance.","tags":["lymphatic","lacteals"],"gid":"g237","unit":"m-lymphatic","comp":"m-lymphatic::lacteals","assess":true},{"id":"c39","dok":1,"q":"What are the two lymphocyte types called that are involved in adaptive immune responses?","a":"B cells and T cells.","tags":["lymphatic","overview"],"rubric":["B cells","T cells"],"gid":"g238","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c40","dok":2,"q":"Which best explains why the lymphatic system is described as closely linked with the circulatory system?","a":"It drains excess interstitial fluid derived from blood and returns it to the venous blood.","options":["It drains excess interstitial fluid derived from blood and returns it to the venous blood","It pumps arterial blood in parallel with the heart","It generates red blood cells inside every vessel","It replaces the veins entirely"],"correctIndex":0,"explanation":"The lymphatic system returns interstitial fluid, which came from blood, back to venous blood, tightly linking the two. It does not pump arterial blood, does not make red blood cells in its vessels, and does not replace veins.","tags":["lymphatic","overview"],"gid":"g239","unit":"m-lymphatic","comp":"m-lymphatic::overview"},{"id":"c41","dok":1,"q":"What color and clarity is ordinary lymph (not chyle)?","a":"Clear and pale-yellow.","tags":["lymphatic","lymph"],"rubric":["Clear","Pale-yellow"],"gid":"g240","unit":"m-lymphatic","comp":"m-lymphatic::lymph"},{"id":"c1","dok":1,"q":"Name the five principal lymph trunks.","a":"Lumbar, intestinal, bronchomediastinal, subclavian, and jugular trunks.","tags":["lymphatic","trunks"],"rubric":["Lumbar trunks","Intestinal trunk","Bronchomediastinal trunks","Subclavian trunks","Jugular trunks"],"gid":"g241","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c2","dok":1,"q":"What do the lumbar trunks drain?","a":"The lower limbs, pelvic wall, and kidneys.","tags":["lymphatic","trunks"],"rubric":["Lower limbs","Pelvic wall","Kidneys"],"gid":"g242","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c3","dok":1,"q":"What does the intestinal trunk drain?","a":"The stomach, intestines, pancreas, spleen, and liver.","tags":["lymphatic","trunks"],"rubric":["Stomach","Intestines","Pancreas","Spleen","Liver"],"gid":"g243","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c4","dok":1,"q":"What do the bronchomediastinal trunks drain?","a":"The thoracic wall, lungs, and heart.","tags":["lymphatic","trunks"],"rubric":["Thoracic wall","Lungs","Heart"],"gid":"g244","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c5","dok":1,"q":"What do the subclavian trunks drain?","a":"The upper limbs.","tags":["lymphatic","trunks"],"rubric":["Upper limbs"],"gid":"g245","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c6","dok":1,"q":"What do the jugular trunks drain?","a":"The head and neck.","tags":["lymphatic","trunks"],"rubric":["Head","Neck"],"gid":"g246","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c7","dok":1,"q":"What is the cisterna chyli, and where does it lie?","a":"A dilated sac at the beginning of the thoracic duct, located anterior to the L2 vertebra.","tags":["lymphatic","ducts"],"rubric":["Dilated sac at start of thoracic duct","Anterior to L2 vertebra"],"gid":"g247","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c8","dok":1,"q":"At what vertebral level does the cisterna chyli sit?","a":"Anterior to the second lumbar (L2) vertebra.","tags":["lymphatic","ducts"],"rubric":["Anterior to the second lumbar (L2) vertebra"],"gid":"g248","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c9","dok":1,"q":"Where does the thoracic duct begin?","a":"At the cisterna chyli, anterior to the L2 vertebra.","tags":["lymphatic","ducts"],"rubric":["At the cisterna chyli","Anterior to L2 vertebra"],"gid":"g249","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c10","dok":1,"q":"What regions does the thoracic duct drain?","a":"The left side of the head, neck, and chest, the left upper limb, and all areas inferior to the ribs.","tags":["lymphatic","ducts"],"rubric":["Left side of head, neck, and chest","Left upper limb","All areas inferior to the ribs"],"gid":"g250","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c11","dok":1,"q":"Where is the right lymphatic duct located?","a":"At the junction of the right internal jugular and right subclavian veins.","tags":["lymphatic","ducts"],"rubric":["Junction of right internal jugular and right subclavian veins"],"gid":"g251","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c12","dok":1,"q":"Which three trunks empty into the right lymphatic duct?","a":"The right jugular, right subclavian, and right bronchomediastinal trunks.","tags":["lymphatic","ducts"],"rubric":["Right jugular trunk","Right subclavian trunk","Right bronchomediastinal trunk"],"gid":"g252","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c13","dok":1,"q":"Which is the larger of the two lymphatic ducts?","a":"The thoracic duct.","tags":["lymphatic","ducts"],"rubric":["The thoracic duct"],"gid":"g253","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c14","dok":1,"q":"Name the two pumps that help maintain lymph flow.","a":"The skeletal muscle pump and the respiratory pump.","tags":["lymphatic","pumps"],"rubric":["Skeletal muscle pump","Respiratory pump"],"gid":"g254","unit":"m-lymphatic","comp":"m-lymphatic::pumps"},{"id":"c15","dok":1,"q":"How does the skeletal muscle pump move lymph?","a":"Contracting skeletal muscles compress lymphatic vessels, forcing lymph toward the heart.","tags":["lymphatic","pumps"],"rubric":["Contracting skeletal muscles compress lymphatic vessels","Force lymph toward the heart"],"gid":"g255","unit":"m-lymphatic","comp":"m-lymphatic::pumps"},{"id":"c16","dok":1,"q":"How does the respiratory pump move lymph?","a":"Pressure changes during inhalation and exhalation move lymph along the vessels.","tags":["lymphatic","pumps"],"rubric":["Pressure changes during inhalation and exhalation","Move lymph along vessels"],"gid":"g256","unit":"m-lymphatic","comp":"m-lymphatic::pumps"},{"id":"c17","dok":2,"q":"Which trunk drains the upper limbs?","a":"The subclavian trunk.","options":["The subclavian trunk","The jugular trunk","The lumbar trunk","The bronchomediastinal trunk"],"correctIndex":0,"explanation":"The subclavian trunk drains the upper limbs. The jugular trunk drains the head and neck. The lumbar trunk drains the lower limbs and pelvis. The bronchomediastinal trunk drains the thoracic wall, lungs, and heart.","tags":["lymphatic","trunks"],"gid":"g257","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c18","dok":2,"q":"Which trunk drains the head and neck?","a":"The jugular trunk.","options":["The jugular trunk","The subclavian trunk","The intestinal trunk","The lumbar trunk"],"correctIndex":0,"explanation":"The jugular trunk drains the head and neck. The subclavian trunk drains the upper limbs. The intestinal trunk drains abdominal viscera. The lumbar trunk drains the lower limbs and pelvis.","tags":["lymphatic","trunks"],"gid":"g258","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c19","dok":2,"q":"Which trunk drains the lower limbs, pelvic wall, and kidneys?","a":"The lumbar trunk.","options":["The lumbar trunk","The intestinal trunk","The subclavian trunk","The bronchomediastinal trunk"],"correctIndex":0,"explanation":"The lumbar trunks drain the lower limbs, pelvic wall, and kidneys. The intestinal trunk drains digestive viscera. The subclavian trunk drains the upper limbs. The bronchomediastinal trunk drains thoracic structures.","tags":["lymphatic","trunks"],"gid":"g259","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c20","dok":2,"q":"Which trunk drains the stomach, intestines, pancreas, spleen, and liver?","a":"The intestinal trunk.","options":["The intestinal trunk","The lumbar trunk","The bronchomediastinal trunk","The jugular trunk"],"correctIndex":0,"explanation":"The intestinal trunk drains the stomach, intestines, pancreas, spleen, and liver. The lumbar trunk drains the lower limbs and pelvis. The bronchomediastinal trunk drains the thorax. The jugular trunk drains the head and neck.","tags":["lymphatic","trunks"],"gid":"g260","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c21","dok":2,"q":"Which trunk drains the thoracic wall, lungs, and heart?","a":"The bronchomediastinal trunk.","options":["The bronchomediastinal trunk","The subclavian trunk","The intestinal trunk","The lumbar trunk"],"correctIndex":0,"explanation":"The bronchomediastinal trunk drains the thoracic wall, lungs, and heart. The subclavian trunk drains the upper limbs. The intestinal trunk drains abdominal viscera. The lumbar trunk drains the lower body.","tags":["lymphatic","trunks"],"gid":"g261","unit":"m-lymphatic","comp":"m-lymphatic::trunks"},{"id":"c22","dok":2,"q":"Which duct receives the right jugular, right subclavian, and right bronchomediastinal trunks?","a":"The right lymphatic duct.","options":["The right lymphatic duct","The thoracic duct","The cisterna chyli","The intestinal trunk"],"correctIndex":0,"explanation":"The right lymphatic duct receives those three right-side trunks. The thoracic duct drains the rest of the body. The cisterna chyli is the sac at the start of the thoracic duct. The intestinal trunk is a trunk, not a duct.","tags":["lymphatic","ducts"],"gid":"g262","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c23","dok":2,"q":"Where does the cisterna chyli lie?","a":"Anterior to the L2 vertebra.","options":["Anterior to the L2 vertebra","In the mediastinum behind the sternum","In the left hypochondriac region","At the base of the tongue"],"correctIndex":0,"explanation":"The cisterna chyli lies anterior to the L2 vertebra. The mediastinum behind the sternum is the thymus location. The left hypochondriac region holds the spleen. The base of the tongue holds the lingual tonsils.","tags":["lymphatic","ducts"],"gid":"g263","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c24","dok":2,"q":"Which structure does the thoracic duct begin as?","a":"The cisterna chyli.","options":["The cisterna chyli","The right lymphatic duct","A lacteal","A jugular trunk"],"correctIndex":0,"explanation":"The thoracic duct begins at the cisterna chyli. The right lymphatic duct is the other, smaller duct. A lacteal is a gut capillary. A jugular trunk drains the head and neck.","tags":["lymphatic","ducts"],"gid":"g264","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c25","dok":2,"q":"The respiratory pump moves lymph by what mechanism?","a":"Pressure changes during inhalation and exhalation.","options":["Pressure changes during inhalation and exhalation","Compression of vessels by contracting skeletal muscle","Contraction of the heart's left ventricle","Squeezing by the spleen"],"correctIndex":0,"explanation":"The respiratory pump uses breathing pressure changes. Compression by contracting skeletal muscle is the skeletal muscle pump. The left ventricle pressurizes blood, not lymph. The spleen does not squeeze lymph vessels.","tags":["lymphatic","pumps"],"gid":"g265","unit":"m-lymphatic","comp":"m-lymphatic::pumps","assess":true},{"id":"c26","dok":2,"q":"The skeletal muscle pump aids lymph flow by doing what?","a":"Compressing lymphatic vessels to force lymph toward the heart.","options":["Compressing lymphatic vessels to force lymph toward the heart","Changing thoracic pressure with each breath","Beating like a lymphatic heart","Opening anchoring filaments"],"correctIndex":0,"explanation":"Contracting skeletal muscles compress lymphatic vessels, driving lymph toward the heart. Thoracic pressure changes are the respiratory pump. There is no lymphatic heart. Anchoring filaments open capillaries, not move lymph forward.","tags":["lymphatic","pumps"],"gid":"g266","unit":"m-lymphatic","comp":"m-lymphatic::pumps"},{"id":"c27","dok":3,"q":"Lymph from the right upper limb enters which duct?","a":"The right lymphatic duct.","options":["The right lymphatic duct","The thoracic duct","The cisterna chyli","The lumbar trunk"],"correctIndex":0,"explanation":"The right upper limb drains via the right subclavian trunk into the right lymphatic duct. The thoracic duct drains the left upper limb and the lower body. The cisterna chyli belongs to the thoracic duct. The lumbar trunk drains the lower limbs.","tags":["lymphatic","ducts"],"gid":"g267","unit":"m-lymphatic","comp":"m-lymphatic::ducts","assess":true},{"id":"c28","dok":3,"q":"Lymph from the left leg reaches the bloodstream through which duct?","a":"The thoracic duct.","options":["The thoracic duct","The right lymphatic duct","The right bronchomediastinal trunk","The jugular trunk"],"correctIndex":0,"explanation":"The left leg drains into the lumbar trunks, then the cisterna chyli, then the thoracic duct. The right lymphatic duct serves only the upper right quadrant. The bronchomediastinal and jugular trunks drain the thorax and head, not the leg.","tags":["lymphatic","ducts"],"gid":"g268","unit":"m-lymphatic","comp":"m-lymphatic::ducts","assess":true},{"id":"c29","dok":3,"q":"Lymph draining from the liver and pancreas travels through which trunk?","a":"The intestinal trunk.","options":["The intestinal trunk","The lumbar trunk","The bronchomediastinal trunk","The subclavian trunk"],"correctIndex":0,"explanation":"The intestinal trunk drains the stomach, intestines, pancreas, spleen, and liver. The lumbar trunk drains the lower body. The bronchomediastinal trunk drains the thorax. The subclavian trunk drains the upper limbs.","tags":["lymphatic","trunks"],"gid":"g269","unit":"m-lymphatic","comp":"m-lymphatic::trunks","assess":true},{"id":"c30","dok":3,"q":"A tumor blocks the thoracic duct near the cisterna chyli. Lymph from which region would still drain normally?","a":"The right side of the head and neck.","options":["The right side of the head and neck","The left leg","The left upper limb","The abdominal organs"],"correctIndex":0,"explanation":"The right head and neck drains via the right lymphatic duct, bypassing the thoracic duct. The left leg, left upper limb, and abdominal organs all drain through the thoracic duct and would be affected by the block.","tags":["lymphatic","ducts"],"gid":"g270","unit":"m-lymphatic","comp":"m-lymphatic::ducts","assess":true},{"id":"c31","dok":3,"q":"Lymph from the right side of the head enters which trunk before its duct?","a":"The right jugular trunk.","options":["The right jugular trunk","The right subclavian trunk","The lumbar trunk","The intestinal trunk"],"correctIndex":0,"explanation":"The head and neck drain via jugular trunks; the right side uses the right jugular trunk into the right lymphatic duct. The subclavian trunk drains the upper limb. The lumbar and intestinal trunks drain the lower body and viscera.","tags":["lymphatic","trunks"],"gid":"g271","unit":"m-lymphatic","comp":"m-lymphatic::trunks","assess":true},{"id":"c32","dok":2,"q":"Which of the following is a lymphatic duct rather than a trunk?","a":"The right lymphatic duct.","options":["The right lymphatic duct","The subclavian trunk","The lumbar trunk","The jugular trunk"],"correctIndex":0,"explanation":"The right lymphatic duct is one of the two ducts. The subclavian, lumbar, and jugular trunks are all trunks that empty into ducts.","tags":["lymphatic","ducts"],"gid":"g272","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c33","dok":2,"q":"Which region does the thoracic duct NOT drain?","a":"The right upper limb.","options":["The right upper limb","The left upper limb","The left side of the head and neck","Everything inferior to the ribs"],"correctIndex":0,"explanation":"The right upper limb drains into the right lymphatic duct, not the thoracic duct. The thoracic duct drains the left upper limb, the left head and neck, and all areas below the ribs.","tags":["lymphatic","ducts"],"gid":"g273","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c34","dok":1,"q":"Into which blood vessels do the lymphatic ducts return lymph to the bloodstream?","a":"The subclavian veins (at the junction with the internal jugular veins).","tags":["lymphatic","ducts"],"rubric":["The subclavian veins","At junction with internal jugular veins"],"gid":"g274","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c35","dok":3,"q":"A weightlifter's rhythmic muscle contractions speed lymph return. Which pump is at work?","a":"The skeletal muscle pump.","options":["The skeletal muscle pump","The respiratory pump","The cardiac pump","The splenic pump"],"correctIndex":0,"explanation":"Rhythmic muscle contractions compressing vessels is the skeletal muscle pump. The respiratory pump uses breathing. There is no cardiac lymph pump. There is no splenic pump.","tags":["lymphatic","pumps"],"gid":"g275","unit":"m-lymphatic","comp":"m-lymphatic::pumps","assess":true},{"id":"c36","dok":2,"q":"The thoracic duct drains roughly what fraction of the body compared with the right lymphatic duct?","a":"Most of the body; the right lymphatic duct drains only the upper right quadrant.","options":["Most of the body; the right lymphatic duct drains only the upper right quadrant","Only the lower limbs","Only the abdomen","The same small region as the right lymphatic duct"],"correctIndex":0,"explanation":"The thoracic duct drains most of the body, leaving only the upper right quadrant to the right lymphatic duct. It drains far more than just the lower limbs or abdomen, and its territory is much larger than the right duct's.","tags":["lymphatic","ducts"],"gid":"g276","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c37","dok":1,"q":"What is another way to describe where the right lymphatic duct empties?","a":"At the junction of the right internal jugular and right subclavian veins.","tags":["lymphatic","ducts"],"rubric":["Junction of right internal jugular and right subclavian veins"],"gid":"g277","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c38","dok":3,"q":"Lymph from the left lung passes through which trunk on its way to a duct?","a":"The left bronchomediastinal trunk.","options":["The left bronchomediastinal trunk","The subclavian trunk","The lumbar trunk","The intestinal trunk"],"correctIndex":0,"explanation":"The lungs drain via the bronchomediastinal trunks; the left one feeds the thoracic duct. The subclavian trunk drains the upper limb, the lumbar trunk the lower body, and the intestinal trunk the digestive viscera.","tags":["lymphatic","trunks"],"gid":"g278","unit":"m-lymphatic","comp":"m-lymphatic::trunks","assess":true},{"id":"c39","dok":2,"q":"Which structure is a dilated sac, not a duct or trunk?","a":"The cisterna chyli.","options":["The cisterna chyli","The thoracic duct","The right lymphatic duct","The jugular trunk"],"correctIndex":0,"explanation":"The cisterna chyli is a dilated sac at the start of the thoracic duct. The thoracic and right lymphatic ducts are ducts. The jugular trunk is a trunk.","tags":["lymphatic","ducts"],"gid":"g279","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c40","dok":3,"q":"Order the vessels lymph from the left foot passes: lumbar trunk, cisterna chyli, thoracic duct, subclavian vein. Which sequence is correct?","a":"Lumbar trunk, cisterna chyli, thoracic duct, subclavian vein.","options":["Lumbar trunk, cisterna chyli, thoracic duct, subclavian vein","Cisterna chyli, lumbar trunk, thoracic duct, subclavian vein","Thoracic duct, cisterna chyli, lumbar trunk, subclavian vein","Lumbar trunk, thoracic duct, cisterna chyli, subclavian vein"],"correctIndex":0,"explanation":"From the foot, lymph enters lumbar trunks, then the cisterna chyli, up the thoracic duct, and into the subclavian vein. The other options place the sac before its trunk, reverse the whole chain, or put the duct before the sac that starts it.","tags":["lymphatic","ducts"],"gid":"g280","unit":"m-lymphatic","comp":"m-lymphatic::ducts"},{"id":"c41","dok":1,"q":"Besides valves, what two mechanisms keep lymph moving despite the absence of a dedicated pump?","a":"The skeletal muscle pump and the respiratory pump.","tags":["lymphatic","pumps"],"rubric":["Skeletal muscle pump","Respiratory pump"],"gid":"g281","unit":"m-lymphatic","comp":"m-lymphatic::pumps"},{"id":"c1","dok":1,"q":"Name the two primary lymphatic organs.","a":"Red bone marrow and the thymus.","tags":["lymphatic","red-marrow"],"rubric":["Red bone marrow","Thymus"],"gid":"g282","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c2","dok":1,"q":"Where is red bone marrow found in adults?","a":"In flat bones and the epiphyses of long bones.","tags":["lymphatic","red-marrow"],"rubric":["Flat bones","Epiphyses of long bones"],"gid":"g283","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c3","dok":1,"q":"What cells in red bone marrow give rise to lymphocytes?","a":"Pluripotent stem cells.","tags":["lymphatic","red-marrow"],"rubric":["Pluripotent stem cells"],"gid":"g284","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c4","dok":1,"q":"Which mature lymphocytes and which precursors arise from red bone marrow stem cells?","a":"Mature B cells and pre-T cells (the pre-T cells migrate to the thymus).","tags":["lymphatic","red-marrow"],"rubric":["Mature B cells","Pre-T cells (migrate to thymus)"],"gid":"g285","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c5","dok":1,"q":"Where do pre-T cells go after leaving the red bone marrow?","a":"They migrate to the thymus.","tags":["lymphatic","red-marrow"],"rubric":["They migrate to the thymus"],"gid":"g286","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c6","dok":1,"q":"Where is the thymus located?","a":"In the mediastinum, between the sternum and the aorta.","tags":["lymphatic","thymus"],"rubric":["In the mediastinum","Between the sternum and the aorta"],"gid":"g287","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c7","dok":1,"q":"Describe the overall shape and subdivision of the thymus.","a":"It is bilobed, with each lobe divided into lobules by connective tissue capsules.","tags":["lymphatic","thymus"],"rubric":["Bilobed","Each lobe divided into lobules by connective tissue capsules"],"gid":"g288","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c8","dok":1,"q":"What are the two regions of each thymic lobule?","a":"An outer cortex and an inner medulla.","tags":["lymphatic","thymus"],"rubric":["Outer cortex","Inner medulla"],"gid":"g289","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c9","dok":1,"q":"Which cells populate the thymus cortex?","a":"Many (immature) T cells, dendritic cells, epithelial cells, and macrophages.","tags":["lymphatic","thymus"],"rubric":["Immature T cells","Dendritic cells","Epithelial cells","Macrophages"],"gid":"g290","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c10","dok":1,"q":"What happens to pre-T cells in the thymic cortex?","a":"They proliferate and mature, with dendritic cells assisting and epithelial cells educating them.","tags":["lymphatic","thymus"],"rubric":["Proliferate and mature","Dendritic cells assist","Epithelial cells educate them"],"gid":"g291","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c11","dok":1,"q":"What do the epithelial cells of the thymic cortex produce?","a":"Thymic hormones.","tags":["lymphatic","thymus"],"rubric":["Thymic hormones"],"gid":"g292","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c12","dok":1,"q":"About what percentage of T cells survive the thymic maturation process?","a":"Only about 2 percent; the rest undergo apoptosis.","tags":["lymphatic","thymus"],"rubric":["About 2 percent survive","Rest undergo apoptosis"],"gid":"g293","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c13","dok":1,"q":"Which cells populate the thymus medulla?","a":"Mature T cells, epithelial cells, dendritic cells, and macrophages.","tags":["lymphatic","thymus"],"rubric":["Mature T cells","Epithelial cells","Dendritic cells","Macrophages"],"gid":"g294","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c14","dok":1,"q":"What are thymic corpuscles also called?","a":"Hassall's corpuscles.","tags":["lymphatic","thymus"],"rubric":["Hassall's corpuscles"],"gid":"g295","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c15","dok":1,"q":"Describe the structure of a Hassall's corpuscle.","a":"Epithelial cells arranged in concentric layers, found in the thymic medulla.","tags":["lymphatic","thymus"],"rubric":["Epithelial cells in concentric layers","Found in the thymic medulla"],"gid":"g296","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c16","dok":1,"q":"In which region of the thymus are Hassall's corpuscles located?","a":"In the medulla.","tags":["lymphatic","thymus"],"rubric":["In the medulla"],"gid":"g297","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c17","dok":2,"q":"Which structure is a primary lymphatic organ?","a":"The thymus.","options":["The thymus","The spleen","A lymph node","A palatine tonsil"],"correctIndex":0,"explanation":"The thymus is a primary lymphatic organ where T cells mature. The spleen, lymph nodes, and tonsils are secondary lymphatic organs where mature lymphocytes encounter invaders.","tags":["lymphatic","thymus"],"gid":"g298","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c18","dok":2,"q":"Which primary organ produces both mature B cells and pre-T cells?","a":"Red bone marrow.","options":["Red bone marrow","The thymus","The spleen","The tonsils"],"correctIndex":0,"explanation":"Red bone marrow stem cells produce mature B cells and pre-T cells. The thymus only matures the pre-T cells into T cells. The spleen and tonsils are secondary organs.","tags":["lymphatic","red-marrow"],"gid":"g299","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow","assess":true},{"id":"c19","dok":2,"q":"Where is the thymus located?","a":"In the mediastinum, between the sternum and the aorta.","options":["In the mediastinum, between the sternum and the aorta","In the left hypochondriac region","Anterior to the L2 vertebra","At the base of the tongue"],"correctIndex":0,"explanation":"The thymus lies in the mediastinum between sternum and aorta. The left hypochondriac region holds the spleen. Anterior to L2 is the cisterna chyli. The base of the tongue holds the lingual tonsils.","tags":["lymphatic","thymus"],"gid":"g300","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c20","dok":2,"q":"In which thymic region do pre-T cells proliferate and mature?","a":"The cortex.","options":["The cortex","The medulla","The capsule","The hilum"],"correctIndex":0,"explanation":"Pre-T cells proliferate and mature in the thymic cortex. The medulla holds mature T cells and Hassall's corpuscles. The capsule is the covering. The hilum is a node feature, not a thymus region.","tags":["lymphatic","thymus"],"gid":"g301","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c21","dok":2,"q":"Which cells are found only in the medulla, not the cortex, in the form of concentric layers?","a":"Hassall's corpuscles (thymic corpuscles).","options":["Hassall's corpuscles (thymic corpuscles)","Pluripotent stem cells","Splenic macrophages","Plasma cells"],"correctIndex":0,"explanation":"Hassall's corpuscles are concentric epithelial cell layers in the thymic medulla. Pluripotent stem cells are in red bone marrow. Splenic macrophages are in the spleen. Plasma cells are in nodes and spleen.","tags":["lymphatic","thymus"],"gid":"g302","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c22","dok":2,"q":"Which thymic region contains mostly mature T cells?","a":"The medulla.","options":["The medulla","The cortex","The capsule","The lobule septa"],"correctIndex":0,"explanation":"The medulla contains mature T cells along with epithelial cells, dendritic cells, and macrophages. The cortex holds immature, proliferating T cells. The capsule and septa are connective tissue, not T cell regions.","tags":["lymphatic","thymus"],"gid":"g303","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c23","dok":2,"q":"Which cells in the thymic cortex educate pre-T cells and make thymic hormones?","a":"Epithelial cells.","options":["Epithelial cells","Dendritic cells","Macrophages","Plasma cells"],"correctIndex":0,"explanation":"Epithelial cells educate pre-T cells and produce thymic hormones. Dendritic cells assist in maturation but are not described as making the hormones. Macrophages clean up debris. Plasma cells are not a thymic cortex feature.","tags":["lymphatic","thymus"],"gid":"g304","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c24","dok":2,"q":"What divides the thymus into lobes and lobules?","a":"Connective tissue capsules.","options":["Connective tissue capsules","Venous sinuses","Reticular fibers only","Anchoring filaments"],"correctIndex":0,"explanation":"Connective tissue capsules divide the bilobed thymus into lobules. Venous sinuses are a spleen feature. Reticular fibers support tissue but do not form the lobule divisions here. Anchoring filaments belong to lymphatic capillaries.","tags":["lymphatic","thymus"],"gid":"g305","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c25","dok":3,"q":"A primary organ is described as large in childhood and shrinking after puberty, sitting between the sternum and aorta. Which organ is it?","a":"The thymus.","options":["The thymus","The spleen","Red bone marrow","The pharyngeal tonsil"],"correctIndex":0,"explanation":"The thymus is the mediastinal primary organ that is prominent in childhood and shrinks after puberty. The spleen and pharyngeal tonsil are secondary. Red bone marrow is primary but not located between sternum and aorta.","tags":["lymphatic","thymus"],"gid":"g306","unit":"m-lymphatic","comp":"m-lymphatic::thymus","assess":true},{"id":"c26","dok":3,"q":"A pre-T cell has just arrived at the thymus. In which region does it first proliferate and get educated?","a":"The cortex.","options":["The cortex","The medulla","The Hassall's corpuscle","The capsule"],"correctIndex":0,"explanation":"Arriving pre-T cells proliferate and are educated in the cortex before mature ones move to the medulla. The medulla holds mature T cells. Hassall's corpuscles are medullary structures. The capsule is connective tissue.","tags":["lymphatic","thymus"],"gid":"g307","unit":"m-lymphatic","comp":"m-lymphatic::thymus","assess":true},{"id":"c27","dok":3,"q":"Only about 2 percent of thymic T cells survive maturation. What happens to the rest?","a":"They undergo apoptosis.","options":["They undergo apoptosis","They migrate to red bone marrow","They become B cells","They form Hassall's corpuscles"],"correctIndex":0,"explanation":"Roughly 98 percent of developing T cells die by apoptosis in the thymus. They do not return to marrow, do not convert to B cells, and do not become Hassall's corpuscles, which are epithelial structures.","tags":["lymphatic","thymus"],"gid":"g308","unit":"m-lymphatic","comp":"m-lymphatic::thymus","assess":true},{"id":"c28","dok":3,"q":"A histology slide of the thymic medulla shows whorls of epithelial cells in concentric layers. What are these?","a":"Hassall's corpuscles.","options":["Hassall's corpuscles","Lymphatic nodules","Billroth's cords","Germinal centers"],"correctIndex":0,"explanation":"Concentric whorls of epithelial cells in the thymic medulla are Hassall's corpuscles. Lymphatic nodules are B cell clusters in nodes. Billroth's cords are in splenic red pulp. Germinal centers form in secondary nodules.","tags":["lymphatic","thymus"],"gid":"g309","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c29","dok":3,"q":"A patient with a genetic defect has no thymus. Which cell line would fail to mature normally?","a":"T cells.","options":["T cells","B cells","Erythrocytes","Platelets"],"correctIndex":0,"explanation":"The thymus matures T cells, so its absence impairs T cell maturation. B cells mature in red bone marrow. Erythrocytes and platelets are produced in marrow and do not depend on the thymus.","tags":["lymphatic","thymus"],"gid":"g310","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c30","dok":2,"q":"Which of these is NOT a resident cell type of the thymic cortex?","a":"Plasma cells.","options":["Plasma cells","Immature T cells","Dendritic cells","Epithelial cells"],"correctIndex":0,"explanation":"The thymic cortex holds immature T cells, dendritic cells, epithelial cells, and macrophages. Plasma cells are found in lymph node medulla and splenic red pulp, not the thymic cortex.","tags":["lymphatic","thymus"],"gid":"g311","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c31","dok":1,"q":"What role do dendritic cells play in the thymic cortex?","a":"They assist pre-T cells in their maturation.","tags":["lymphatic","thymus"],"rubric":["They assist pre-T cells in maturation"],"gid":"g312","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c32","dok":2,"q":"Red bone marrow is classified as a primary lymphatic organ because lymphocytes there do what?","a":"They form there, and B cells mature there.","options":["They form there, and B cells mature there","They are filtered out of passing lymph","They meet swallowed pathogens","They remove worn-out red blood cells"],"correctIndex":0,"explanation":"Red bone marrow is primary because lymphocytes form there and B cells mature there. Filtering lymph is a node role. Meeting swallowed pathogens is a tonsil role. Removing worn-out red blood cells is a splenic red pulp function.","tags":["lymphatic","red-marrow"],"gid":"g313","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow","assess":true},{"id":"c33","dok":3,"q":"In which bones would you look for red bone marrow in an adult to find lymphocyte-producing stem cells?","a":"Flat bones and the epiphyses of long bones.","options":["Flat bones and the epiphyses of long bones","The diaphyses of long bones only","The cartilage of joints","The cornea and epidermis"],"correctIndex":0,"explanation":"In adults, red bone marrow persists in flat bones and long-bone epiphyses. The diaphyses hold yellow marrow. Cartilage, cornea, and epidermis are avascular and hold no marrow at all.","tags":["lymphatic","red-marrow"],"gid":"g314","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow","assess":true},{"id":"c34","dok":2,"q":"Which primary organ is described as bilobed with each lobe divided into lobules?","a":"The thymus.","options":["The thymus","Red bone marrow","The spleen","A lymph node"],"correctIndex":0,"explanation":"The thymus is bilobed with lobules. Red bone marrow is not lobed in this way. The spleen has white and red pulp. A lymph node has cortex and medulla but is not described as bilobed.","tags":["lymphatic","thymus"],"gid":"g315","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c35","dok":1,"q":"What is the outer region of a thymic lobule called?","a":"The cortex.","tags":["lymphatic","thymus"],"rubric":["The cortex"],"gid":"g316","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c36","dok":1,"q":"What is the inner region of a thymic lobule called?","a":"The medulla.","tags":["lymphatic","thymus"],"rubric":["The medulla"],"gid":"g317","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c37","dok":3,"q":"A thymic region is described as holding mature T cells plus concentric epithelial whorls. Which region is it?","a":"The medulla.","options":["The medulla","The cortex","The capsule","The septum"],"correctIndex":0,"explanation":"Mature T cells and Hassall's corpuscles (concentric epithelial whorls) are in the medulla. The cortex holds immature T cells. The capsule and septa are connective tissue divisions.","tags":["lymphatic","thymus"],"gid":"g318","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c38","dok":2,"q":"Which cell type is present in BOTH the thymic cortex and medulla?","a":"Macrophages (and dendritic and epithelial cells).","options":["Macrophages (and dendritic and epithelial cells)","Plasma cells","Erythrocytes","Platelets"],"correctIndex":0,"explanation":"Macrophages, dendritic cells, and epithelial cells appear in both cortex and medulla. Plasma cells are not a thymic feature. Erythrocytes and platelets are marrow products, not thymic residents.","tags":["lymphatic","thymus"],"gid":"g319","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c39","dok":3,"q":"Hassall's corpuscles are thought to be involved in what event affecting T cells?","a":"T cell death (apoptosis).","options":["T cell death (apoptosis)","Red blood cell storage","Lipid absorption","Lymph filtration"],"correctIndex":0,"explanation":"Hassall's corpuscles are possibly involved in T cell death. Red blood cell storage is a splenic function. Lipid absorption is a lacteal role. Lymph filtration is a lymph node role.","tags":["lymphatic","thymus"],"gid":"g320","unit":"m-lymphatic","comp":"m-lymphatic::thymus"},{"id":"c40","dok":2,"q":"Which sequence correctly describes T cell development sites?","a":"Form in red bone marrow as pre-T cells, then mature in the thymus.","options":["Form in red bone marrow as pre-T cells, then mature in the thymus","Form in the thymus, then mature in red bone marrow","Form and mature entirely in the spleen","Form in the tonsils, then mature in nodes"],"correctIndex":0,"explanation":"Pre-T cells form in red bone marrow and mature in the thymus. The reverse is false, and neither the spleen nor tonsils are the site of T cell formation and maturation.","tags":["lymphatic","red-marrow"],"gid":"g321","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c41","dok":1,"q":"Which primary organ contains pluripotent stem cells that give rise to all blood and lymphocyte lines?","a":"Red bone marrow.","tags":["lymphatic","red-marrow"],"rubric":["Red bone marrow"],"gid":"g322","unit":"m-lymphatic","comp":"m-lymphatic::red-marrow"},{"id":"c1","dok":1,"q":"About how many lymph nodes are in the body, and what is their shape?","a":"About 600 bean-shaped structures.","tags":["lymphatic","lymph-nodes"],"rubric":["About 600","Bean-shaped"],"gid":"g323","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c2","dok":1,"q":"Where are the largest groups of lymph nodes concentrated?","a":"In the mammary glands, axillae, and groin.","tags":["lymphatic","lymph-nodes"],"rubric":["Mammary glands","Axillae","Groin"],"gid":"g324","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c3","dok":1,"q":"What forms the outer covering of a lymph node?","a":"A capsule of dense connective tissue.","tags":["lymphatic","lymph-nodes"],"rubric":["A capsule of dense connective tissue"],"gid":"g325","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c4","dok":1,"q":"What are trabeculae in a lymph node?","a":"Inward extensions of the capsule that divide the node into compartments.","tags":["lymphatic","lymph-nodes"],"rubric":["Inward extensions of the capsule","Divide the node into compartments"],"gid":"g326","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c5","dok":1,"q":"Which cells dominate the outer cortex of a lymph node?","a":"B cells.","tags":["lymphatic","lymph-nodes"],"rubric":["B cells"],"gid":"g327","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c6","dok":1,"q":"Which cells dominate the deeper cortex of a lymph node?","a":"Mostly T cells and dendritic cells.","tags":["lymphatic","lymph-nodes"],"rubric":["T cells","Dendritic cells"],"gid":"g328","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c7","dok":1,"q":"Which cells are found in the medulla of a lymph node?","a":"B cells, plasma cells, and macrophages.","tags":["lymphatic","lymph-nodes"],"rubric":["B cells","Plasma cells","Macrophages"],"gid":"g329","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c8","dok":1,"q":"Where in a lymph node are lymphatic nodules found?","a":"In the outer cortex.","tags":["lymphatic","lymph-nodes"],"rubric":["In the outer cortex"],"gid":"g330","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c9","dok":1,"q":"What are lymphatic nodules the sites of?","a":"Plasma cell and memory B cell formation.","tags":["lymphatic","lymph-nodes"],"rubric":["Plasma cell formation","Memory B cell formation"],"gid":"g331","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c10","dok":1,"q":"What does a primary lymphatic nodule mainly contain?","a":"Mainly B cells.","tags":["lymphatic","lymph-nodes"],"rubric":["Mainly B cells"],"gid":"g332","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c11","dok":1,"q":"What is a secondary lymphatic nodule?","a":"A nodule that forms in response to an antigen, where B cells proliferate into memory B cells or plasma cells.","tags":["lymphatic","lymph-nodes"],"rubric":["Forms in response to an antigen","B cells proliferate into memory B cells or plasma cells"],"gid":"g333","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c12","dok":1,"q":"In which body region is the spleen located?","a":"The left hypochondriac region.","tags":["lymphatic","spleen"],"rubric":["The left hypochondriac region"],"gid":"g334","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c13","dok":1,"q":"What is the largest mass of lymphatic tissue in the body?","a":"The spleen.","tags":["lymphatic","spleen"],"rubric":["The spleen"],"gid":"g335","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c14","dok":1,"q":"What forms the covering and internal stroma of the spleen?","a":"A capsule of dense connective tissue with inward trabeculae forming the stroma.","tags":["lymphatic","spleen"],"rubric":["Capsule of dense connective tissue","Inward trabeculae forming the stroma"],"gid":"g336","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c15","dok":1,"q":"What is white pulp?","a":"Lymphatic tissue arranged around the splenic (central) artery, where B and T cells carry out immune functions.","tags":["lymphatic","spleen"],"rubric":["Lymphatic tissue around the splenic (central) artery","B and T cells carry out immune functions"],"gid":"g337","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c16","dok":1,"q":"What is red pulp?","a":"Splenic tissue of venous sinuses and cords of splenic tissue (Billroth's cords) containing macrophages, lymphocytes, and plasma cells.","tags":["lymphatic","spleen"],"rubric":["Venous sinuses and cords (Billroth's cords)","Macrophages, lymphocytes, and plasma cells"],"gid":"g338","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c17","dok":1,"q":"What are Billroth's cords?","a":"The cords of splenic tissue within the red pulp.","tags":["lymphatic","spleen"],"rubric":["Cords of splenic tissue in the red pulp"],"gid":"g339","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c18","dok":1,"q":"List three functions of the splenic red pulp.","a":"Removing defective blood cells, storing platelets, and producing blood cells in fetal life.","tags":["lymphatic","spleen"],"rubric":["Removing defective blood cells","Storing platelets","Producing blood cells in fetal life"],"gid":"g340","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c19","dok":2,"q":"What is the dense connective tissue covering of a lymph node called?","a":"The capsule.","options":["The capsule","The cortex","The medulla","The trabecula"],"correctIndex":0,"explanation":"The capsule is the dense connective tissue covering. The cortex is the outer B cell region inside it. The medulla is the inner region. A trabecula is an inward extension of the capsule.","tags":["lymphatic","lymph-nodes"],"gid":"g341","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c20","dok":2,"q":"Which region of a lymph node contains mostly T cells and dendritic cells?","a":"The deep (inner) cortex.","options":["The deep (inner) cortex","The outer cortex","The capsule","The medullary sinus"],"correctIndex":0,"explanation":"The deep cortex holds mostly T cells and dendritic cells. The outer cortex is dominated by B cells. The capsule is connective tissue. The medulla holds B cells, plasma cells, and macrophages.","tags":["lymphatic","lymph-nodes"],"gid":"g342","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c21","dok":2,"q":"Where are plasma cells found within a lymph node?","a":"In the medulla.","options":["In the medulla","In the deep cortex","In the capsule","In the trabeculae"],"correctIndex":0,"explanation":"The medulla contains B cells, plasma cells, and macrophages. The deep cortex holds T cells and dendritic cells. The capsule and trabeculae are connective tissue, not cell-populated regions.","tags":["lymphatic","lymph-nodes"],"gid":"g343","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c22","dok":2,"q":"A lymphatic nodule that forms in response to an antigen and shows proliferating B cells is called what?","a":"A secondary nodule.","options":["A secondary nodule","A primary nodule","A Hassall's corpuscle","A Billroth's cord"],"correctIndex":0,"explanation":"A secondary nodule forms in response to an antigen with proliferating B cells. A primary nodule mainly holds resting B cells. A Hassall's corpuscle is a thymic structure. A Billroth's cord is in splenic red pulp.","tags":["lymphatic","lymph-nodes"],"gid":"g344","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c23","dok":2,"q":"Which lymphatic organ sits in the left hypochondriac region and is the largest mass of lymphatic tissue?","a":"The spleen.","options":["The spleen","The thymus","A lymph node","The pharyngeal tonsil"],"correctIndex":0,"explanation":"The spleen sits in the left hypochondriac region and is the largest lymphatic mass. The thymus is in the mediastinum. A lymph node is small and bean-shaped. The pharyngeal tonsil is in the nasopharynx.","tags":["lymphatic","spleen"],"gid":"g345","unit":"m-lymphatic","comp":"m-lymphatic::spleen","assess":true},{"id":"c24","dok":2,"q":"Which spleen tissue surrounds the splenic artery and carries out immune functions?","a":"White pulp.","options":["White pulp","Red pulp","Billroth's cords","The capsule"],"correctIndex":0,"explanation":"White pulp surrounds the splenic artery and holds B and T cells for immune functions. Red pulp filters blood. Billroth's cords are within the red pulp. The capsule is the outer covering.","tags":["lymphatic","spleen"],"gid":"g346","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c25","dok":2,"q":"Which spleen tissue contains venous sinuses and Billroth's cords?","a":"Red pulp.","options":["Red pulp","White pulp","The cortex","The medulla"],"correctIndex":0,"explanation":"Red pulp contains venous sinuses and Billroth's cords. White pulp is the lymphocyte-rich immune tissue. Cortex and medulla are lymph node regions, not spleen tissues.","tags":["lymphatic","spleen"],"gid":"g347","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c26","dok":2,"q":"Which is a function of the splenic red pulp?","a":"Removing defective blood cells.","options":["Removing defective blood cells","Maturing pre-T cells","Absorbing dietary lipids","Producing thymic hormones"],"correctIndex":0,"explanation":"Red pulp removes defective blood cells, stores platelets, and made blood cells in fetal life. Maturing pre-T cells and producing thymic hormones are thymic roles. Absorbing dietary lipids is a lacteal role.","tags":["lymphatic","spleen"],"gid":"g348","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c27","dok":2,"q":"In which three locations are lymph nodes found in large groups?","a":"Mammary glands, axillae, and groin.","options":["Mammary glands, axillae, and groin","Mediastinum, spleen, and tonsils","Cortex, medulla, and hilum","Cornea, epidermis, and CNS"],"correctIndex":0,"explanation":"Large node groups sit in the mammary glands, axillae, and groin. The mediastinum, spleen, and tonsils are organ sites, not node clusters. Cortex, medulla, and hilum are internal node regions. The cornea, epidermis, and CNS lack lymphatics.","tags":["lymphatic","lymph-nodes"],"gid":"g349","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c28","dok":3,"q":"A structure is small, bean-shaped, positioned along lymphatic vessels, and filters lymph. What is it?","a":"A lymph node.","options":["A lymph node","The spleen","The thymus","A lacteal"],"correctIndex":0,"explanation":"A small, bean-shaped organ along lymphatic vessels that filters lymph is a lymph node. The spleen filters blood. The thymus matures T cells. A lacteal absorbs dietary fat in the gut.","tags":["lymphatic","lymph-nodes"],"gid":"g350","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes","assess":true},{"id":"c29","dok":3,"q":"A spleen tissue is described as filtering blood and removing worn-out erythrocytes. Which tissue is it?","a":"Red pulp.","options":["Red pulp","White pulp","The cortex","The medulla"],"correctIndex":0,"explanation":"Red pulp filters blood and removes worn-out erythrocytes. White pulp carries out immune functions. Cortex and medulla are lymph node regions, not spleen tissues.","tags":["lymphatic","spleen"],"gid":"g351","unit":"m-lymphatic","comp":"m-lymphatic::spleen","assess":true},{"id":"c30","dok":3,"q":"A biopsy of a node's outer cortex shows a rounded cluster of B cells that formed after an antigen appeared, with a pale proliferating center. What is this?","a":"A secondary lymphatic nodule.","options":["A secondary lymphatic nodule","A primary lymphatic nodule","A trabecula","A Hassall's corpuscle"],"correctIndex":0,"explanation":"A rounded B cell cluster that formed after antigen exposure with a proliferating center is a secondary nodule. A primary nodule lacks that antigen-driven center. A trabecula is a connective tissue extension. A Hassall's corpuscle is thymic.","tags":["lymphatic","lymph-nodes"],"gid":"g352","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes","assess":true},{"id":"c31","dok":3,"q":"A patient suffers a blow to the left upper abdomen and has heavy internal bleeding from a ruptured lymphatic organ. Which organ is it?","a":"The spleen.","options":["The spleen","The thymus","A cervical lymph node","A palatine tonsil"],"correctIndex":0,"explanation":"The spleen sits in the left hypochondriac region, is highly vascular, and bleeds heavily when ruptured. The thymus, a cervical node, and a tonsil are not the blood-filled, easily ruptured left upper abdominal organ.","tags":["lymphatic","spleen"],"gid":"g353","unit":"m-lymphatic","comp":"m-lymphatic::spleen","assess":true},{"id":"c32","dok":2,"q":"Which structure divides a lymph node into compartments?","a":"Trabeculae.","options":["Trabeculae","Billroth's cords","Hassall's corpuscles","Anchoring filaments"],"correctIndex":0,"explanation":"Trabeculae extend inward from the capsule and divide a node into compartments. Billroth's cords are in the spleen. Hassall's corpuscles are in the thymus. Anchoring filaments are on lymphatic capillaries.","tags":["lymphatic","lymph-nodes"],"gid":"g354","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c33","dok":2,"q":"Which cells make up a primary lymphatic nodule?","a":"Mainly B cells.","options":["Mainly B cells","Mainly T cells","Mainly plasma cells","Mainly macrophages"],"correctIndex":0,"explanation":"A primary nodule is mainly B cells. T cells dominate the deep cortex. Plasma cells are in the medulla. Macrophages are scattered but do not define the nodule.","tags":["lymphatic","lymph-nodes"],"gid":"g355","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c34","dok":1,"q":"What is the inner region of a lymph node, containing B cells, plasma cells, and macrophages, called?","a":"The medulla.","tags":["lymphatic","lymph-nodes"],"rubric":["The medulla"],"gid":"g356","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c35","dok":3,"q":"A node region is described as the outer layer packed with B cells and rounded nodules. Which region is it?","a":"The (outer) cortex.","options":["The (outer) cortex","The medulla","The capsule","The deep cortex"],"correctIndex":0,"explanation":"The outer cortex holds B cells and the lymphatic nodules. The medulla is the inner region. The capsule is the connective tissue covering. The deep cortex holds mostly T cells.","tags":["lymphatic","lymph-nodes"],"gid":"g357","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes","assess":true},{"id":"c36","dok":2,"q":"Which of these is a spleen structure, not a lymph node structure?","a":"Billroth's cords.","options":["Billroth's cords","The deep cortex","A trabecula of the node","The medullary cords of the node"],"correctIndex":0,"explanation":"Billroth's cords are in the splenic red pulp. The deep cortex and medullary cords are lymph node features. A node trabecula belongs to the node, not the spleen.","tags":["lymphatic","spleen"],"gid":"g358","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c37","dok":1,"q":"Where is the splenic white pulp arranged relative to blood vessels?","a":"Around the splenic (central) artery.","tags":["lymphatic","spleen"],"rubric":["Around the splenic (central) artery"],"gid":"g359","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c38","dok":3,"q":"A lymph node region rich in T cells sits between the B cell-rich outer cortex and the medulla. What is this region?","a":"The deep cortex.","options":["The deep cortex","The subcapsular sinus","The trabecula","The white pulp"],"correctIndex":0,"explanation":"The deep cortex, rich in T cells and dendritic cells, lies between the outer cortex and medulla. The subcapsular sinus is a lymph space. A trabecula is connective tissue. White pulp is a spleen tissue.","tags":["lymphatic","lymph-nodes"],"gid":"g360","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c39","dok":2,"q":"Which lymphatic organ filters lymph, and which filters blood?","a":"Lymph nodes filter lymph; the spleen filters blood.","options":["Lymph nodes filter lymph; the spleen filters blood","Lymph nodes filter blood; the spleen filters lymph","Both filter blood","Both filter lymph"],"correctIndex":0,"explanation":"Lymph nodes sit along lymphatic vessels and filter lymph, while the spleen sits in the bloodstream and filters blood. The roles are not reversed, and the two organs do not filter the same fluid.","tags":["lymphatic","spleen"],"gid":"g361","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c40","dok":3,"q":"A secondary nodule develops a pale center of proliferating B cells. Which cells can these B cells become there?","a":"Memory B cells or plasma cells.","options":["Memory B cells or plasma cells","T cells or dendritic cells","Erythrocytes or platelets","Epithelial cells or macrophages"],"correctIndex":0,"explanation":"In a secondary nodule, proliferating B cells develop into memory B cells or plasma cells. They do not become T cells, blood cells, or epithelial cells, which arise elsewhere.","tags":["lymphatic","lymph-nodes"],"gid":"g362","unit":"m-lymphatic","comp":"m-lymphatic::lymph-nodes"},{"id":"c41","dok":1,"q":"What cells are found in the splenic red pulp along with macrophages?","a":"Lymphocytes and plasma cells.","tags":["lymphatic","spleen"],"rubric":["Lymphocytes","Plasma cells"],"gid":"g363","unit":"m-lymphatic","comp":"m-lymphatic::spleen"},{"id":"c1","dok":1,"q":"What does MALT stand for?","a":"Mucosa-associated lymphatic tissue.","tags":["lymphatic","malt"],"rubric":["Mucosa-associated lymphatic tissue"],"gid":"g364","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c2","dok":1,"q":"In which layer of mucous membranes is MALT scattered?","a":"In the lamina propria.","tags":["lymphatic","malt"],"rubric":["In the lamina propria"],"gid":"g365","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c3","dok":1,"q":"Which tracts have MALT lining their mucous membranes?","a":"The gastrointestinal, respiratory, urinary, and reproductive tracts.","tags":["lymphatic","malt"],"rubric":["Gastrointestinal tract","Respiratory tract","Urinary tract","Reproductive tract"],"gid":"g366","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c4","dok":1,"q":"What is another name for lymphatic nodules scattered in mucous membranes?","a":"MALT (mucosa-associated lymphatic tissue).","tags":["lymphatic","malt"],"rubric":["MALT (mucosa-associated lymphatic tissue)"],"gid":"g367","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c5","dok":1,"q":"How many tonsils are there, and what arrangement do they form?","a":"Five tonsils forming a ring at the junctions of the oral cavity, oropharynx, nasal cavity, and nasopharynx.","tags":["lymphatic","tonsils"],"rubric":["Five tonsils","Form a ring at junctions of oral cavity, oropharynx, nasal cavity, nasopharynx"],"gid":"g368","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c6","dok":1,"q":"What is the pharyngeal tonsil also called?","a":"The adenoid.","tags":["lymphatic","tonsils"],"rubric":["The adenoid"],"gid":"g369","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c7","dok":1,"q":"Where is the pharyngeal tonsil (adenoid) located?","a":"In the posterior wall of the nasopharynx.","tags":["lymphatic","tonsils"],"rubric":["Posterior wall of the nasopharynx"],"gid":"g370","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c8","dok":1,"q":"Where are the palatine tonsils located?","a":"In the posterior region of the oral cavity.","tags":["lymphatic","tonsils"],"rubric":["Posterior region of the oral cavity"],"gid":"g371","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c9","dok":1,"q":"Where are the lingual tonsils located?","a":"At the base of the tongue.","tags":["lymphatic","tonsils"],"rubric":["At the base of the tongue"],"gid":"g372","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c10","dok":1,"q":"How many pharyngeal tonsils (adenoids) are there?","a":"One (a single pharyngeal tonsil).","tags":["lymphatic","tonsils"],"rubric":["One (a single pharyngeal tonsil)"],"gid":"g373","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c11","dok":1,"q":"How many palatine tonsils are there?","a":"Two (they are paired).","tags":["lymphatic","tonsils"],"rubric":["Two (paired)"],"gid":"g374","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c12","dok":2,"q":"MALT is found in which location?","a":"The mucous membranes of the digestive, respiratory, urinary, and reproductive tracts.","options":["The mucous membranes of the digestive, respiratory, urinary, and reproductive tracts","The spongy bone of the axial skeleton","The mediastinum behind the sternum","The left hypochondriac region"],"correctIndex":0,"explanation":"MALT lines the mucous membranes of the digestive, respiratory, urinary, and reproductive tracts. Spongy axial bone holds red marrow. The mediastinum holds the thymus. The left hypochondriac region holds the spleen.","tags":["lymphatic","malt"],"gid":"g375","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c13","dok":2,"q":"Which tonsil lies on the posterior wall of the nasopharynx?","a":"The pharyngeal tonsil (adenoid).","options":["The pharyngeal tonsil (adenoid)","A palatine tonsil","A lingual tonsil","The cisterna chyli"],"correctIndex":0,"explanation":"The pharyngeal tonsil, or adenoid, sits on the posterior wall of the nasopharynx. The palatine tonsils are in the oral cavity. The lingual tonsils are at the base of the tongue. The cisterna chyli is not a tonsil.","tags":["lymphatic","tonsils"],"gid":"g376","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c14","dok":2,"q":"Which tonsils sit in the posterior region of the oral cavity?","a":"The palatine tonsils.","options":["The palatine tonsils","The lingual tonsils","The pharyngeal tonsil","The tubal tonsils"],"correctIndex":0,"explanation":"The palatine tonsils are in the posterior oral cavity. The lingual tonsils are at the tongue base. The pharyngeal tonsil is in the nasopharynx. Tubal tonsils sit near the auditory tube openings, not the oral cavity.","tags":["lymphatic","tonsils"],"gid":"g377","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c15","dok":2,"q":"Which tonsils lie at the base of the tongue?","a":"The lingual tonsils.","options":["The lingual tonsils","The palatine tonsils","The pharyngeal tonsil","The adenoid"],"correctIndex":0,"explanation":"The lingual tonsils are at the base of the tongue. The palatine tonsils are in the oral cavity. The pharyngeal tonsil, also the adenoid, is in the nasopharynx.","tags":["lymphatic","tonsils"],"gid":"g378","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c16","dok":2,"q":"The five tonsils together form what?","a":"A ring of lymphatic tissue guarding the entrances to the throat.","options":["A ring of lymphatic tissue guarding the entrances to the throat","A chain of nodes along the thoracic duct","A cluster of organs in the left upper abdomen","A pair of lobes in the mediastinum"],"correctIndex":0,"explanation":"The tonsils form a protective ring at the throat openings. A chain along the thoracic duct describes trunks and nodes. An abdominal cluster is not the tonsils. Lobes in the mediastinum describe the thymus.","tags":["lymphatic","tonsils"],"gid":"g379","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c17","dok":2,"q":"Which term names the mucosal lymphatic tissue found in the lamina propria?","a":"MALT.","options":["MALT","Red pulp","White pulp","Cisterna chyli"],"correctIndex":0,"explanation":"MALT is the mucosal lymphatic tissue in the lamina propria. Red and white pulp are spleen tissues. The cisterna chyli is the sac at the start of the thoracic duct.","tags":["lymphatic","malt"],"gid":"g380","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c18","dok":3,"q":"A single tonsil is described on the posterior nasopharyngeal wall, sometimes enlarged in children causing nasal blockage. Which tonsil is it?","a":"The pharyngeal tonsil (adenoid).","options":["The pharyngeal tonsil (adenoid)","A palatine tonsil","A lingual tonsil","A tubal tonsil"],"correctIndex":0,"explanation":"The pharyngeal tonsil (adenoid) on the posterior nasopharyngeal wall can enlarge and block nasal airflow in children. Palatine, lingual, and tubal tonsils sit in the oral cavity, tongue base, and near the auditory tubes respectively.","tags":["lymphatic","tonsils"],"gid":"g381","unit":"m-lymphatic","comp":"m-lymphatic::tonsils","assess":true},{"id":"c19","dok":3,"q":"A pair of tonsils is described as commonly removed in a tonsillectomy, sitting at the back of the mouth. Which tonsils are they?","a":"The palatine tonsils.","options":["The palatine tonsils","The lingual tonsils","The pharyngeal tonsil","The tubal tonsils"],"correctIndex":0,"explanation":"The palatine tonsils at the back of the oral cavity are the ones usually removed in a tonsillectomy. The lingual tonsils are at the tongue base, the pharyngeal tonsil is in the nasopharynx, and tubal tonsils sit near the auditory tubes.","tags":["lymphatic","tonsils"],"gid":"g382","unit":"m-lymphatic","comp":"m-lymphatic::tonsils","assess":true},{"id":"c20","dok":3,"q":"Lymphatic tissue is described as scattered in the lining of the intestine to guard against swallowed pathogens. What is this tissue?","a":"MALT.","options":["MALT","The thymic cortex","The splenic white pulp","Billroth's cords"],"correctIndex":0,"explanation":"Scattered lymphatic tissue in the gut lining guarding against swallowed pathogens is MALT. The thymic cortex matures T cells. Splenic white pulp is in the spleen. Billroth's cords are in splenic red pulp.","tags":["lymphatic","malt"],"gid":"g383","unit":"m-lymphatic","comp":"m-lymphatic::malt","assess":true},{"id":"c21","dok":2,"q":"Which of these is NOT one of the tracts lined by MALT?","a":"The cardiovascular (blood vessel) system.","options":["The cardiovascular (blood vessel) system","The gastrointestinal tract","The respiratory tract","The urinary tract"],"correctIndex":0,"explanation":"MALT lines the gastrointestinal, respiratory, urinary, and reproductive tracts, all mucosal surfaces. The cardiovascular system is not a mucosal tract lined by MALT.","tags":["lymphatic","malt"],"gid":"g384","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c22","dok":3,"q":"A child breathes through the mouth because enlarged tissue blocks the back of the nasal passage. Which tonsil is most likely enlarged?","a":"The pharyngeal tonsil (adenoid).","options":["The pharyngeal tonsil (adenoid)","The lingual tonsil","A palatine tonsil","A tubal tonsil"],"correctIndex":0,"explanation":"The pharyngeal tonsil sits on the posterior nasopharyngeal wall, so its enlargement blocks nasal airflow. The lingual tonsil is at the tongue base, the palatine tonsils are in the oral cavity, and tubal tonsils are near the auditory tubes.","tags":["lymphatic","tonsils"],"gid":"g385","unit":"m-lymphatic","comp":"m-lymphatic::tonsils","assess":true},{"id":"c23","dok":2,"q":"Where does the tonsillar ring guard the body?","a":"At the junction of the oral cavity and oropharynx, and the nasal cavity and nasopharynx.","options":["At the junction of the oral cavity and oropharynx, and the nasal cavity and nasopharynx","At the junction of the small and large intestines","Around the splenic artery","At the cisterna chyli"],"correctIndex":0,"explanation":"The tonsillar ring guards the openings where the oral and nasal cavities meet the pharynx. The intestinal junction, the splenic artery, and the cisterna chyli are unrelated locations.","tags":["lymphatic","tonsils"],"gid":"g386","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c24","dok":1,"q":"Which tonsil is single rather than paired: pharyngeal, palatine, or lingual?","a":"The pharyngeal tonsil (adenoid) is single.","tags":["lymphatic","tonsils"],"rubric":["The pharyngeal tonsil (adenoid) is single"],"gid":"g387","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c25","dok":3,"q":"A slide of the intestinal lamina propria shows clusters of lymphocytes with no capsule around them. What are these clusters?","a":"MALT (mucosa-associated lymphatic tissue).","options":["MALT (mucosa-associated lymphatic tissue)","Lymph nodes","Splenic white pulp","Thymic lobules"],"correctIndex":0,"explanation":"Unencapsulated lymphocyte clusters in the lamina propria are MALT. Lymph nodes are encapsulated. Splenic white pulp is in the spleen. Thymic lobules are in the thymus.","tags":["lymphatic","malt"],"gid":"g388","unit":"m-lymphatic","comp":"m-lymphatic::malt","assess":true},{"id":"c26","dok":2,"q":"Which structure is unencapsulated diffuse lymphatic tissue rather than an encapsulated organ?","a":"MALT.","options":["MALT","A lymph node","The spleen","The thymus"],"correctIndex":0,"explanation":"MALT is diffuse, unencapsulated lymphatic tissue. Lymph nodes, the spleen, and the thymus are all encapsulated organs.","tags":["lymphatic","malt"],"gid":"g389","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c27","dok":1,"q":"The tonsils are located at the junction of which two body openings and the pharynx?","a":"The oral cavity (with the oropharynx) and the nasal cavity (with the nasopharynx).","tags":["lymphatic","tonsils"],"rubric":["Oral cavity (with oropharynx)","Nasal cavity (with nasopharynx)"],"gid":"g390","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c28","dok":3,"q":"During a throat exam, a clinician sees paired masses of lymphatic tissue on either side at the back of the mouth. Which tonsils are these?","a":"The palatine tonsils.","options":["The palatine tonsils","The lingual tonsils","The pharyngeal tonsil","The adenoid"],"correctIndex":0,"explanation":"Paired masses at the back of the mouth on either side are the palatine tonsils. The lingual tonsils are at the tongue base. The pharyngeal tonsil, or adenoid, is a single mass in the nasopharynx.","tags":["lymphatic","tonsils"],"gid":"g391","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c29","dok":2,"q":"Which tonsils would you inspect by looking at the base of the tongue?","a":"The lingual tonsils.","options":["The lingual tonsils","The palatine tonsils","The pharyngeal tonsil","The tubal tonsils"],"correctIndex":0,"explanation":"The lingual tonsils are at the base of the tongue. The palatine tonsils are at the back of the oral cavity, the pharyngeal tonsil is in the nasopharynx, and tubal tonsils are near the auditory tubes.","tags":["lymphatic","tonsils"],"gid":"g392","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c30","dok":3,"q":"MALT and the tonsils are grouped as secondary lymphatic tissue. What do they have in common structurally?","a":"Both are lymphatic tissue positioned at mucosal surfaces to guard entry points into the body.","options":["Both are lymphatic tissue positioned at mucosal surfaces to guard entry points into the body","Both mature T cells like the thymus","Both filter blood like the spleen","Both are primary lymphatic organs"],"correctIndex":0,"explanation":"MALT and tonsils are lymphatic tissue at mucosal surfaces guarding body entry points. They do not mature T cells (a thymic role) or filter blood (a splenic role), and both are secondary, not primary, lymphatic tissue.","tags":["lymphatic","malt"],"gid":"g393","unit":"m-lymphatic","comp":"m-lymphatic::malt","assess":true},{"id":"c31","dok":1,"q":"Name the three tonsils identified by location in the notes.","a":"The pharyngeal tonsil (adenoid), the palatine tonsils, and the lingual tonsils.","tags":["lymphatic","tonsils"],"rubric":["Pharyngeal tonsil (adenoid)","Palatine tonsils","Lingual tonsils"],"gid":"g394","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c32","dok":2,"q":"Which of these correctly pairs a tonsil with its location?","a":"Lingual tonsil at the base of the tongue.","options":["Lingual tonsil at the base of the tongue","Palatine tonsil in the nasopharynx","Pharyngeal tonsil in the oral cavity","Lingual tonsil on the nasopharyngeal wall"],"correctIndex":0,"explanation":"The lingual tonsil is at the base of the tongue. The palatine tonsils are in the oral cavity, not the nasopharynx. The pharyngeal tonsil is in the nasopharynx, not the oral cavity, and the lingual tonsil is not on the nasopharyngeal wall.","tags":["lymphatic","tonsils"],"gid":"g395","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c33","dok":3,"q":"A histologist wants an example of lymphatic tissue that has no surrounding capsule and lies in the wall of a hollow organ. Which should she choose?","a":"MALT.","options":["MALT","A lymph node","The spleen","The thymus"],"correctIndex":0,"explanation":"MALT is unencapsulated and lies in the walls of hollow mucosal organs. Lymph nodes, the spleen, and the thymus are all encapsulated organs.","tags":["lymphatic","malt"],"gid":"g396","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c34","dok":1,"q":"In which mucosal tissue layer does MALT sit within the wall of the gut and airways?","a":"The lamina propria.","tags":["lymphatic","malt"],"rubric":["The lamina propria"],"gid":"g397","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c35","dok":2,"q":"Which best describes the function of the tonsillar ring by position?","a":"It positions lymphatic tissue to guard the openings into the throat.","options":["It positions lymphatic tissue to guard the openings into the throat","It filters all the blood leaving the heart","It matures every pre-T cell","It stores platelets"],"correctIndex":0,"explanation":"The tonsillar ring places lymphatic tissue at the throat openings. Filtering blood from the heart is not a tonsil role, maturing pre-T cells is a thymic role, and storing platelets is a splenic red pulp role.","tags":["lymphatic","tonsils"],"gid":"g398","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c36","dok":3,"q":"A patient has recurrent infections of the paired masses at the back of the oral cavity. Which tonsils are involved?","a":"The palatine tonsils.","options":["The palatine tonsils","The pharyngeal tonsil","The lingual tonsils","The tubal tonsils"],"correctIndex":0,"explanation":"The paired masses at the back of the oral cavity are the palatine tonsils. The pharyngeal tonsil is a single mass in the nasopharynx, the lingual tonsils are at the tongue base, and tubal tonsils sit near the auditory tubes.","tags":["lymphatic","tonsils"],"gid":"g399","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c37","dok":2,"q":"Which of the following is diffuse lymphatic tissue lining the reproductive tract?","a":"MALT.","options":["MALT","White pulp","The thymic medulla","A germinal center of a node"],"correctIndex":0,"explanation":"MALT lines mucosal surfaces including the reproductive tract. White pulp is in the spleen, the thymic medulla is in the thymus, and a germinal center is inside a lymph node nodule.","tags":["lymphatic","malt"],"gid":"g400","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c38","dok":1,"q":"Which single tonsil, when enlarged, is specifically called the adenoid?","a":"The pharyngeal tonsil.","tags":["lymphatic","tonsils"],"rubric":["The pharyngeal tonsil"],"gid":"g401","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c39","dok":3,"q":"Order these from the nasal end to the mouth end of the tonsillar ring: pharyngeal tonsil, palatine tonsils, lingual tonsils.","a":"Pharyngeal tonsil (nasopharynx), then palatine tonsils (oral cavity), then lingual tonsils (base of tongue).","options":["Pharyngeal tonsil (nasopharynx), then palatine tonsils (oral cavity), then lingual tonsils (base of tongue)","Lingual tonsils, then palatine tonsils, then pharyngeal tonsil","Palatine tonsils, then pharyngeal tonsil, then lingual tonsils","Pharyngeal tonsil, then lingual tonsils, then palatine tonsils"],"correctIndex":0,"explanation":"From the nasal end down, the order is pharyngeal tonsil in the nasopharynx, palatine tonsils in the oral cavity, then lingual tonsils at the tongue base. The other options reverse or scramble this superior-to-inferior arrangement.","tags":["lymphatic","tonsils"],"gid":"g402","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c40","dok":2,"q":"Which term describes lymphatic nodules scattered throughout mucous membranes rather than gathered into an encapsulated organ?","a":"MALT.","options":["MALT","Lymph node","Spleen","Thymus"],"correctIndex":0,"explanation":"Scattered mucosal nodules are MALT. A lymph node, the spleen, and the thymus are all discrete, encapsulated structures rather than scattered nodules.","tags":["lymphatic","malt"],"gid":"g403","unit":"m-lymphatic","comp":"m-lymphatic::malt"},{"id":"c41","dok":1,"q":"How many tonsils in total form the tonsillar ring?","a":"Five.","tags":["lymphatic","tonsils"],"rubric":["Five"],"gid":"g404","unit":"m-lymphatic","comp":"m-lymphatic::tonsils"},{"id":"c1","dok":1,"q":"To which of the four primary tissue types does blood belong?","a":"Connective tissue.","rubric":["Connective tissue"],"tags":["blood","overview"],"gid":"g405","unit":"m-blood","comp":"m-blood::overview"},{"id":"c2","dok":1,"q":"Blood is classified as which specific category of connective tissue?","a":"Fluid connective tissue.","rubric":["Fluid connective tissue"],"tags":["blood","overview"],"gid":"g406","unit":"m-blood","comp":"m-blood::overview"},{"id":"c3","dok":1,"q":"What percentage of whole blood is formed elements?","a":"About 45 percent.","tags":["blood","overview"],"options":["About 45 percent","About 55 percent","About 7 percent","About 92 percent"],"correctIndex":0,"explanation":"Formed elements make up about 45 percent of whole blood. About 55 percent is plasma. About 92 percent is the water content of plasma, and about 7 percent is the plasma protein content.","gid":"g407","unit":"m-blood","comp":"m-blood::overview","assess":true},{"id":"c4","dok":1,"q":"What percentage of whole blood is plasma?","a":"About 55 percent.","tags":["blood","overview"],"options":["About 55 percent","About 45 percent","About 92 percent","About 8 percent"],"correctIndex":0,"explanation":"Plasma is about 55 percent of whole blood. About 45 percent is the formed-element fraction. About 92 percent is water within plasma, and about 8 percent is the dissolved-solute content of plasma.","gid":"g408","unit":"m-blood","comp":"m-blood::overview","assess":true},{"id":"c5","dok":2,"q":"State the two major fractions of whole blood and their approximate percentages.","a":"Formed elements about 45 percent and plasma about 55 percent.","rubric":["Formed elements (about 45 percent)","Plasma (about 55 percent)"],"tags":["blood","overview"],"gid":"g409","unit":"m-blood","comp":"m-blood::overview"},{"id":"c6","dok":1,"q":"What structural role does plasma play relative to the formed elements?","a":"Plasma is the extracellular matrix of the blood.","options":["Plasma is the extracellular matrix of the blood","Plasma is the cellular fraction of the blood","Plasma is the layer of clotting cells","Plasma is a type of leukocyte"],"correctIndex":0,"explanation":"Plasma is the fluid extracellular matrix in which the formed elements are suspended. The formed elements are the cellular fraction, not plasma. Plasma is a fluid, not cells, so it is neither a clotting cell layer nor a leukocyte.","tags":["blood","plasma"],"gid":"g410","unit":"m-blood","comp":"m-blood::plasma","assess":true},{"id":"c7","dok":1,"q":"What is the approximate blood volume of an average adult?","a":"About 5 liters.","tags":["blood","overview"],"options":["About 5 liters","About 1 liter","About 10 liters","About 20 liters"],"correctIndex":0,"explanation":"An average adult has about 5 liters of blood. One liter is far too little. Ten and twenty liters far exceed normal adult blood volume.","gid":"g411","unit":"m-blood","comp":"m-blood::overview"},{"id":"c8","dok":1,"q":"Blood makes up approximately what percentage of total body weight?","a":"About 7 to 8 percent of total body weight.","rubric":["About 7 to 8 percent of body weight"],"tags":["blood","overview"],"gid":"g412","unit":"m-blood","comp":"m-blood::overview"},{"id":"c9","dok":1,"q":"What is the normal pH range of blood?","a":"7.35 to 7.45.","tags":["blood","overview"],"options":["7.35 to 7.45","6.8 to 7.0","7.0 to 7.2","7.8 to 8.2"],"correctIndex":0,"explanation":"Blood pH is held between 7.35 and 7.45, slightly alkaline. A range of 6.8 to 7.0 or 7.0 to 7.2 would be acidic relative to blood, and 7.8 to 8.2 would be too alkaline for survival.","gid":"g413","unit":"m-blood","comp":"m-blood::overview"},{"id":"c10","dok":1,"q":"Is normal blood slightly acidic or slightly alkaline?","a":"Slightly alkaline, at pH 7.35 to 7.45.","rubric":["Slightly alkaline","pH 7.35 to 7.45"],"tags":["blood","overview"],"gid":"g414","unit":"m-blood","comp":"m-blood::overview"},{"id":"c11","dok":1,"q":"What is the normal temperature of blood?","a":"About 38 degrees C (100.4 degrees F).","tags":["blood","overview"],"options":["About 38 degrees C","About 30 degrees C","About 42 degrees C","About 35 degrees C"],"correctIndex":0,"explanation":"Blood runs at about 38 degrees C, slightly warmer than core temperature. About 30 and 35 degrees C are too cool, and about 42 degrees C would be dangerously hyperthermic.","gid":"g415","unit":"m-blood","comp":"m-blood::overview"},{"id":"c12","dok":1,"q":"Blood is approximately how many times more viscous than water?","a":"About 5 times more viscous than water.","options":["About 5 times","About 2 times","About 20 times","The same as water"],"correctIndex":0,"explanation":"Blood is about 5 times more viscous than water because of its proteins and formed elements. Two times understates its thickness. Twenty times overstates it, and blood is clearly thicker than plain water.","tags":["blood","overview"],"gid":"g416","unit":"m-blood","comp":"m-blood::overview"},{"id":"c13","dok":1,"q":"What two components of blood are chiefly responsible for its high viscosity?","a":"Its protein content and its formed elements.","rubric":["Protein content","Formed elements"],"tags":["blood","overview"],"gid":"g417","unit":"m-blood","comp":"m-blood::overview"},{"id":"c14","dok":2,"q":"Oxygen-rich blood appears which color?","a":"Bright red.","rubric":["Bright red"],"tags":["blood","overview"],"gid":"g418","unit":"m-blood","comp":"m-blood::overview"},{"id":"c15","dok":2,"q":"Oxygen-poor blood appears which color?","a":"Dark red to purple.","options":["Dark red to purple","Bright red","Blue","Yellow"],"correctIndex":0,"explanation":"Oxygen-poor blood is dark red to purple. Bright red is the oxygen-rich color. Blood is not blue, and yellow describes plasma, not whole oxygen-poor blood.","tags":["blood","overview"],"gid":"g419","unit":"m-blood","comp":"m-blood::overview","assess":true},{"id":"c16","dok":2,"q":"What is the most abundant component of plasma?","a":"Water, making up 91 to 92 percent of plasma.","rubric":["Water","91 to 92 percent of plasma"],"tags":["blood","plasma"],"gid":"g420","unit":"m-blood","comp":"m-blood::plasma"},{"id":"c17","dok":1,"q":"Approximately what percentage of plasma is water?","a":"About 91 to 92 percent.","tags":["blood","plasma"],"options":["About 91 to 92 percent","About 55 percent","About 8 percent","About 45 percent"],"correctIndex":0,"explanation":"Plasma is about 91 to 92 percent water. About 55 percent and 45 percent describe plasma and formed elements as fractions of whole blood, and about 8 percent is the dissolved-solute content of plasma.","gid":"g421","unit":"m-blood","comp":"m-blood::plasma"},{"id":"c18","dok":1,"q":"Plasma proteins make up approximately what percentage of plasma?","a":"About 7 to 8 percent of plasma.","tags":["blood","plasma-proteins"],"options":["About 7 to 8 percent","About 55 percent","About 45 percent","About 92 percent"],"correctIndex":0,"explanation":"Plasma proteins are 7 to 8 percent of plasma. About 92 percent is the water content, and about 55 and 45 percent describe plasma and formed elements as fractions of whole blood.","gid":"g422","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c19","dok":1,"q":"Which is the most abundant plasma protein?","a":"Albumin.","rubric":["Albumin"],"tags":["blood","plasma-proteins"],"gid":"g423","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c20","dok":2,"q":"Name the most abundant plasma protein and the approximate fraction of plasma proteins it represents.","a":"Albumin, about 60 percent of plasma proteins.","rubric":["Albumin","About 60 percent of plasma proteins"],"tags":["blood","plasma-proteins"],"gid":"g424","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c21","dok":1,"q":"Which plasma protein group includes the antibodies, also called immunoglobulins?","a":"Gamma globulins.","options":["Gamma globulins","Albumin","Fibrinogen","Alpha globulins"],"correctIndex":0,"explanation":"Gamma globulins are the antibodies (immunoglobulins). Albumin is a carrier and osmotic protein, not an antibody. Fibrinogen is a clotting protein. Alpha globulins are transport proteins, not antibodies.","tags":["blood","plasma-proteins"],"gid":"g425","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c22","dok":1,"q":"Which plasma protein is the largest and is converted to fibrin during clotting?","a":"Fibrinogen.","options":["Fibrinogen","Albumin","Gamma globulin","Transferrin"],"correctIndex":0,"explanation":"Fibrinogen is the largest plasma protein and the precursor converted to fibrin. Albumin is the most abundant but not the largest clotting precursor. Gamma globulin is an antibody, and transferrin is an iron-transport globulin.","tags":["blood","plasma-proteins"],"gid":"g426","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c23","dok":2,"q":"Name the three major classes of plasma proteins in order of abundance.","a":"Albumin, globulins, then fibrinogen.","rubric":["Albumin","Globulins","Fibrinogen"],"tags":["blood","plasma-proteins"],"gid":"g427","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c24","dok":2,"q":"Fibrinogen makes up approximately what fraction of the plasma proteins?","a":"About 4 percent of plasma proteins.","options":["About 4 percent","About 60 percent","About 35 percent","About 92 percent"],"correctIndex":0,"explanation":"Fibrinogen is about 4 percent of plasma proteins. About 60 percent is albumin. About 35 percent is the globulins. About 92 percent describes water content of plasma, not a protein fraction.","tags":["blood","plasma-proteins"],"gid":"g428","unit":"m-blood","comp":"m-blood::plasma-proteins","assess":true},{"id":"c25","dok":1,"q":"Globulins make up approximately what fraction of the plasma proteins?","a":"About 35 percent of plasma proteins.","rubric":["About 35 percent of plasma proteins"],"tags":["blood","plasma-proteins"],"gid":"g429","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c26","dok":2,"q":"Where are all plasma proteins synthesized, except for the gamma globulins?","a":"In the liver.","rubric":["The liver"],"tags":["blood","plasma-proteins"],"gid":"g430","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c27","dok":2,"q":"Which plasma proteins are NOT made in the liver, and what cells produce them?","a":"Gamma globulins (antibodies), produced by plasma cells.","rubric":["Gamma globulins (antibodies)","Made by plasma cells"],"tags":["blood","plasma-proteins"],"gid":"g431","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c28","dok":2,"q":"Which globulin subgroups act as transport proteins such as transferrin and lipoproteins?","a":"Alpha and beta globulins.","options":["Alpha and beta globulins","Gamma globulins","Albumin fractions","Fibrinogen fractions"],"correctIndex":0,"explanation":"Alpha and beta globulins are the transport globulins, carrying substances such as transferrin and lipoproteins. Gamma globulins are the antibodies. Albumin and fibrinogen are separate protein classes, not globulin transport subgroups.","tags":["blood","plasma-proteins"],"gid":"g432","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c29","dok":2,"q":"Which plasma protein is described as the chief carrier for hormones, fatty acids, and many drugs, and the main protein maintaining blood osmotic (oncotic) pressure?","a":"Albumin.","options":["Albumin","Fibrinogen","Gamma globulin","Transferrin"],"correctIndex":0,"explanation":"Albumin is the main carrier protein and the chief contributor to oncotic pressure. Fibrinogen is the clotting precursor. Gamma globulin is an antibody, and transferrin carries iron specifically, not the broad carrier and osmotic role of albumin.","tags":["blood","plasma-proteins"],"gid":"g433","unit":"m-blood","comp":"m-blood::plasma-proteins"},{"id":"c30","dok":3,"q":"Name a nutrient solute and a nitrogenous waste solute normally dissolved in plasma.","a":"A nutrient such as glucose or amino acids; a waste such as urea or creatinine.","rubric":["A nutrient (glucose or amino acids)","A waste (urea or creatinine)"],"tags":["blood","plasma"],"gid":"g434","unit":"m-blood","comp":"m-blood::plasma"},{"id":"c31","dok":1,"q":"Which of the following is a major electrolyte dissolved in plasma?","a":"Na+.","rubric":["Na+"],"tags":["blood","plasma"],"gid":"g435","unit":"m-blood","comp":"m-blood::plasma"},{"id":"c32","dok":2,"q":"List four electrolytes normally dissolved in plasma using ASCII ion notation.","a":"Na+, K+, Ca2+, Cl- (and HCO3-).","rubric":["Na+","K+","Ca2+","Cl-","HCO3-"],"tags":["blood","plasma"],"gid":"g436","unit":"m-blood","comp":"m-blood::plasma"},{"id":"c33","dok":1,"q":"What is the liquid extracellular matrix of blood called?","a":"Plasma.","rubric":["Plasma"],"tags":["blood","plasma"],"gid":"g437","unit":"m-blood","comp":"m-blood::plasma"},{"id":"c34","dok":2,"q":"Which nitrogenous waste in plasma is carried bound to albumin on its way to the liver?","a":"Bilirubin.","options":["Bilirubin","Glucose","Transferrin","Fibrinogen"],"correctIndex":0,"explanation":"Unconjugated bilirubin is carried through plasma bound to albumin toward the liver. Glucose is a nutrient, not a waste bound to albumin in this way. Transferrin is an iron carrier, and fibrinogen is a clotting protein.","tags":["blood","plasma"],"gid":"g438","unit":"m-blood","comp":"m-blood::plasma","assess":true},{"id":"c35","dok":3,"q":"A blood component is described as a fluid, forms roughly 55 percent of whole blood, is about 92 percent water, and carries dissolved proteins, nutrients, and electrolytes. What is it?","a":"Plasma.","options":["Plasma","Serum","Buffy coat","Formed elements"],"correctIndex":0,"explanation":"A fluid that is 55 percent of blood and 92 percent water with dissolved solutes is plasma. Serum is plasma minus clotting proteins, not defined by these fractions. The buffy coat is a cell layer, and the formed elements are the 45 percent cellular fraction.","tags":["blood","plasma"],"gid":"g439","unit":"m-blood","comp":"m-blood::plasma","assess":true},{"id":"c36","dok":3,"q":"A plasma protein is described as the most abundant of its group, made by the liver, serving as a carrier and the chief contributor to osmotic pressure. Name it.","a":"Albumin.","options":["Albumin","Fibrinogen","Gamma globulin","Alpha globulin"],"correctIndex":0,"explanation":"The most abundant, liver-made carrier and osmotic protein is albumin. Fibrinogen is the largest and is a clotting precursor. Gamma globulin is an antibody, and alpha globulin is a transport globulin, not the most abundant protein.","tags":["blood","plasma-proteins"],"gid":"g440","unit":"m-blood","comp":"m-blood::plasma-proteins","assess":true},{"id":"c37","dok":3,"q":"A protein group makes up about 35 percent of plasma proteins and includes both transport proteins and the antibodies. Name the group.","a":"The globulins.","options":["The globulins","Albumin","Fibrinogen","The formed elements"],"correctIndex":0,"explanation":"The globulins, about 35 percent of plasma proteins, include transport globulins and antibody globulins. Albumin is a single abundant protein, not this mixed group. Fibrinogen is the clotting protein, and the formed elements are cells, not proteins.","tags":["blood","plasma-proteins"],"gid":"g441","unit":"m-blood","comp":"m-blood::plasma-proteins","assess":true},{"id":"c1","dok":1,"q":"What is the characteristic shape of a mature erythrocyte?","a":"A biconcave disc.","rubric":["Biconcave disc"],"tags":["blood","erythrocytes"],"gid":"g442","unit":"m-blood","comp":"m-blood::erythrocytes"},{"id":"c2","dok":1,"q":"What is the approximate diameter of an erythrocyte?","a":"About 7.5 um.","tags":["blood","erythrocytes"],"options":["About 7.5 um","About 2 um","About 20 um","About 50 um"],"correctIndex":0,"explanation":"An erythrocyte is about 7.5 um in diameter. About 2 um is closer to a platelet, and about 20 um and 50 um are far too large for a red cell.","gid":"g443","unit":"m-blood","comp":"m-blood::erythrocytes"},{"id":"c3","dok":2,"q":"Give the approximate thickness of an erythrocyte at its edge and at its center.","a":"About 2.5 um at the edge and about 1 um at the center.","rubric":["About 2.5 um at the edge","About 1 um at the center"],"tags":["blood","erythrocytes"],"gid":"g444","unit":"m-blood","comp":"m-blood::erythrocytes"},{"id":"c4","dok":2,"q":"What structural advantage does the biconcave disc shape give the erythrocyte?","a":"Greater surface area for gas exchange and flexibility to bend through capillaries.","options":["Greater surface area and flexibility for capillary passage","The ability to synthesize proteins","A place to store a nucleus","The ability to divide"],"correctIndex":0,"explanation":"The biconcave shape gives about 30 percent more surface area than a sphere and lets the cell bend through narrow capillaries. It does not enable protein synthesis, nucleus storage, or division, since the mature cell lacks a nucleus and organelles.","tags":["blood","erythrocytes"],"gid":"g445","unit":"m-blood","comp":"m-blood::erythrocytes","assess":true},{"id":"c5","dok":1,"q":"Does a mature erythrocyte contain a nucleus?","a":"No, it is anucleate; the nucleus is ejected during maturation.","tags":["blood","erythrocytes"],"options":["No, it is anucleate","Yes, one round nucleus","Yes, a multi-lobed nucleus","Yes, a kidney-shaped nucleus"],"correctIndex":0,"explanation":"A mature erythrocyte is anucleate, having ejected its nucleus. A round nucleus fits a lymphocyte, a multi-lobed nucleus fits a neutrophil, and a kidney-shaped nucleus fits a monocyte.","gid":"g446","unit":"m-blood","comp":"m-blood::erythrocytes"},{"id":"c6","dok":1,"q":"Besides a nucleus, what other cellular structures does a mature erythrocyte lack?","a":"Organelles such as mitochondria, endoplasmic reticulum, and Golgi apparatus.","rubric":["Mitochondria","Endoplasmic reticulum","Golgi apparatus"],"tags":["blood","erythrocytes"],"gid":"g447","unit":"m-blood","comp":"m-blood::erythrocytes"},{"id":"c7","dok":2,"q":"Because it lacks a nucleus and organelles, a mature erythrocyte cannot do which of the following?","a":"Reproduce or synthesize new proteins.","options":["Reproduce or synthesize new proteins","Carry oxygen","Bend through capillaries","Contain hemoglobin"],"correctIndex":0,"explanation":"Without a nucleus and organelles the erythrocyte cannot divide or make proteins. It still carries oxygen, bends through capillaries, and holds hemoglobin, all of which do not require a nucleus.","tags":["blood","erythrocytes"],"gid":"g448","unit":"m-blood","comp":"m-blood::erythrocytes","assess":true},{"id":"c8","dok":1,"q":"What is the average lifespan of an erythrocyte?","a":"About 120 days (roughly 4 months).","rubric":["About 120 days (4 months)"],"tags":["blood","erythrocytes"],"gid":"g449","unit":"m-blood","comp":"m-blood::erythrocytes"},{"id":"c9","dok":1,"q":"What red, iron-containing protein fills the erythrocyte?","a":"Hemoglobin.","rubric":["Hemoglobin"],"tags":["blood","hemoglobin"],"gid":"g450","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c10","dok":1,"q":"Hemoglobin is described as which level of protein structure?","a":"Quaternary structure (four polypeptide subunits).","options":["Quaternary structure","Primary structure","Secondary structure","Tertiary structure"],"correctIndex":0,"explanation":"Hemoglobin is a quaternary protein, built of four polypeptide subunits. Primary structure is the amino acid sequence, secondary is local folding, and tertiary is a single folded chain, none of which describe a four-subunit assembly.","tags":["blood","hemoglobin"],"gid":"g451","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c11","dok":2,"q":"How many and which polypeptide chains make up one hemoglobin molecule?","a":"Four chains: 2 alpha chains and 2 beta chains.","rubric":["Four chains total","2 alpha chains","2 beta chains"],"tags":["blood","hemoglobin"],"gid":"g452","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c12","dok":1,"q":"How many heme groups does one hemoglobin molecule contain?","a":"Four heme groups.","tags":["blood","hemoglobin"],"options":["Four","One","Two","Six"],"correctIndex":0,"explanation":"One hemoglobin molecule has four heme groups, one per polypeptide subunit. One, two, and six do not match the four-subunit structure.","gid":"g453","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c13","dok":1,"q":"Each heme group is a porphyrin ring holding what single ion?","a":"One iron ion in the Fe2+ (ferrous) state.","rubric":["One iron ion","Fe2+ (ferrous) state"],"tags":["blood","hemoglobin"],"gid":"g454","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c14","dok":1,"q":"In which oxidation state must the iron of heme be to bind oxygen?","a":"Fe2+ (ferrous).","rubric":["Fe2+ (ferrous)"],"tags":["blood","hemoglobin"],"gid":"g455","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c15","dok":2,"q":"Given its structure, what is the maximum number of oxygen-binding sites on one hemoglobin molecule?","a":"Four, one per heme group.","options":["Four","One","Two","Eight"],"correctIndex":0,"explanation":"With four heme groups, hemoglobin has four oxygen-binding sites. One, two, and eight do not match the four-heme structure.","tags":["blood","hemoglobin"],"gid":"g456","unit":"m-blood","comp":"m-blood::hemoglobin","assess":true},{"id":"c16","dok":1,"q":"What is the name of the hemoglobin form that is bound to oxygen?","a":"Oxyhemoglobin (HbO2).","rubric":["Oxyhemoglobin (HbO2)"],"tags":["blood","hemoglobin"],"gid":"g457","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c17","dok":2,"q":"What is the name of the hemoglobin form that has released its oxygen?","a":"Deoxyhemoglobin.","rubric":["Deoxyhemoglobin"],"tags":["blood","hemoglobin"],"gid":"g458","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c18","dok":1,"q":"Which hemoglobin form is bound to carbon monoxide?","a":"Carboxyhemoglobin (HbCO).","options":["Carboxyhemoglobin","Oxyhemoglobin","Deoxyhemoglobin","Methemoglobin"],"correctIndex":0,"explanation":"Carboxyhemoglobin is the carbon monoxide-bound, toxic form. Oxyhemoglobin is oxygen-bound, deoxyhemoglobin has released oxygen, and methemoglobin is the Fe3+ form.","tags":["blood","hemoglobin"],"gid":"g459","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c19","dok":1,"q":"Which hemoglobin form contains iron in the Fe3+ state and cannot carry oxygen?","a":"Methemoglobin (MetHb).","options":["Methemoglobin","Oxyhemoglobin","Carboxyhemoglobin","Deoxyhemoglobin"],"correctIndex":0,"explanation":"Methemoglobin holds oxidized Fe3+ iron and cannot bind oxygen. Oxyhemoglobin and deoxyhemoglobin both contain Fe2+, and carboxyhemoglobin is defined by carbon monoxide binding, not Fe3+.","tags":["blood","hemoglobin"],"gid":"g460","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c20","dok":3,"q":"Name the four structural forms of hemoglobin covered in this unit.","a":"Oxyhemoglobin, deoxyhemoglobin, carboxyhemoglobin, and methemoglobin.","rubric":["Oxyhemoglobin","Deoxyhemoglobin","Carboxyhemoglobin","Methemoglobin"],"tags":["blood","hemoglobin"],"gid":"g461","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c21","dok":2,"q":"Which two hemoglobin forms differ from each other only by whether oxygen is bound, both keeping Fe2+ iron?","a":"Oxyhemoglobin and deoxyhemoglobin.","options":["Oxyhemoglobin and deoxyhemoglobin","Carboxyhemoglobin and methemoglobin","Methemoglobin and oxyhemoglobin","Carboxyhemoglobin and deoxyhemoglobin"],"correctIndex":0,"explanation":"Oxyhemoglobin and deoxyhemoglobin both keep Fe2+ and differ only by oxygen binding. Methemoglobin has Fe3+, and carboxyhemoglobin is defined by carbon monoxide, so the other pairings differ by more than oxygen alone.","tags":["blood","hemoglobin"],"gid":"g462","unit":"m-blood","comp":"m-blood::hemoglobin"},{"id":"c22","dok":1,"q":"What is the normal hemoglobin range for adult men?","a":"About 13 to 18 g/dL.","tags":["blood","values"],"options":["13 to 18 g/dL","12 to 16 g/dL","5 to 9 g/dL","20 to 25 g/dL"],"correctIndex":0,"explanation":"Adult men run about 13 to 18 g/dL hemoglobin. About 12 to 16 g/dL is the female range, about 5 to 9 g/dL is anemic, and 20 to 25 g/dL is far above normal.","gid":"g463","unit":"m-blood","comp":"m-blood::values","assess":true},{"id":"c23","dok":1,"q":"What is the normal hemoglobin range for adult women?","a":"About 12 to 16 g/dL.","options":["12 to 16 g/dL","13 to 18 g/dL","6 to 10 g/dL","18 to 22 g/dL"],"correctIndex":0,"explanation":"Adult women run about 12 to 16 g/dL. About 13 to 18 g/dL is the male range. About 6 to 10 g/dL is anemic, and 18 to 22 g/dL is above normal.","tags":["blood","values"],"gid":"g464","unit":"m-blood","comp":"m-blood::values"},{"id":"c24","dok":1,"q":"What is the normal hematocrit range for men?","a":"About 42 to 52 percent.","rubric":["About 42 to 52 percent"],"tags":["blood","values"],"gid":"g465","unit":"m-blood","comp":"m-blood::values"},{"id":"c25","dok":1,"q":"What is the normal hematocrit range for women?","a":"About 37 to 47 percent.","rubric":["About 37 to 47 percent"],"tags":["blood","values"],"gid":"g466","unit":"m-blood","comp":"m-blood::values"},{"id":"c26","dok":2,"q":"The hematocrit measures the percentage of blood volume made up of which component?","a":"Erythrocytes.","options":["Erythrocytes","Plasma","Leukocytes","Platelets"],"correctIndex":0,"explanation":"Hematocrit is the percentage of blood volume that is erythrocytes. Plasma is the remaining volume but is not what hematocrit reports. Leukocytes and platelets form only the thin buffy coat.","tags":["blood","values"],"gid":"g467","unit":"m-blood","comp":"m-blood::values","assess":true},{"id":"c27","dok":2,"q":"Where is the iron of aged erythrocytes stored, and by what protein?","a":"In the liver, spleen, and bone marrow, stored bound to ferritin.","options":["Ferritin, in liver, spleen, and marrow","Transferrin, in the plasma","Albumin, in the plasma","Fibrinogen, in the marrow"],"correctIndex":0,"explanation":"Ferritin stores iron in the liver, spleen, and bone marrow. Transferrin transports iron in plasma rather than storing it. Albumin is a general carrier protein, and fibrinogen is a clotting protein.","tags":["blood","rbc-lifecycle"],"gid":"g468","unit":"m-blood","comp":"m-blood::rbc-lifecycle","assess":true},{"id":"c28","dok":2,"q":"Which protein transports iron through the plasma?","a":"Transferrin.","rubric":["Transferrin"],"tags":["blood","rbc-lifecycle"],"gid":"g469","unit":"m-blood","comp":"m-blood::rbc-lifecycle"},{"id":"c29","dok":2,"q":"Ferritin and transferrin differ in function how?","a":"Ferritin is the iron storage protein in tissues; transferrin is the iron transport protein in plasma.","options":["Ferritin stores iron; transferrin transports iron","Ferritin transports iron; transferrin stores iron","Both store iron only","Both transport iron only"],"correctIndex":0,"explanation":"Ferritin stores iron in liver, spleen, and marrow while transferrin carries iron in plasma. Reversing the two is incorrect, and neither pairing where both share a single role is correct because their roles are distinct.","tags":["blood","rbc-lifecycle"],"gid":"g470","unit":"m-blood","comp":"m-blood::rbc-lifecycle","assess":true},{"id":"c30","dok":2,"q":"At what three sites are worn-out erythrocytes primarily removed?","a":"The spleen, liver, and bone marrow.","rubric":["Spleen","Liver","Bone marrow"],"tags":["blood","rbc-lifecycle"],"gid":"g471","unit":"m-blood","comp":"m-blood::rbc-lifecycle"},{"id":"c31","dok":2,"q":"By what cell type are aged erythrocytes engulfed during their removal?","a":"Macrophages, by phagocytosis.","rubric":["Macrophages","By phagocytosis"],"tags":["blood","rbc-lifecycle"],"gid":"g472","unit":"m-blood","comp":"m-blood::rbc-lifecycle"},{"id":"c32","dok":2,"q":"When hemoglobin is broken down, into which two main parts is it first split?","a":"Into heme and globin.","options":["Heme and globin","Iron and albumin","Ferritin and transferrin","Alpha chains and heme only"],"correctIndex":0,"explanation":"Hemoglobin first splits into heme and globin. Iron and albumin are not the two halves of hemoglobin. Ferritin and transferrin are iron-handling proteins, not hemoglobin parts, and globin includes both alpha and beta chains.","tags":["blood","rbc-lifecycle"],"gid":"g473","unit":"m-blood","comp":"m-blood::rbc-lifecycle"},{"id":"c33","dok":2,"q":"After hemoglobin breakdown, what happens to the globin chains?","a":"They are broken into amino acids that are recycled.","options":["Recycled into amino acids","Stored as ferritin","Converted to bilirubin","Excreted unchanged in urine"],"correctIndex":0,"explanation":"Globin chains are broken into recycled amino acids. Ferritin stores iron, not globin. Bilirubin comes from the heme portion, not globin, and globin is not excreted unchanged.","tags":["blood","rbc-lifecycle"],"gid":"g474","unit":"m-blood","comp":"m-blood::rbc-lifecycle"},{"id":"c34","dok":3,"q":"Breakdown of the heme protoporphyrin ring produces which yellow pigment carried to the liver?","a":"Bilirubin.","rubric":["Bilirubin"],"tags":["blood","rbc-lifecycle"],"gid":"g475","unit":"m-blood","comp":"m-blood::rbc-lifecycle"},{"id":"c35","dok":3,"q":"A blood cell is described as an anucleate biconcave disc, about 7.5 um across, with no organelles and a lifespan near 120 days. Name it.","a":"An erythrocyte.","options":["An erythrocyte","A neutrophil","A platelet","A lymphocyte"],"correctIndex":0,"explanation":"An anucleate biconcave disc about 7.5 um across with a 120-day lifespan is an erythrocyte. A neutrophil is a nucleated granulocyte, a platelet is a small fragment, and a lymphocyte is a nucleated agranulocyte.","tags":["blood","erythrocytes"],"gid":"g476","unit":"m-blood","comp":"m-blood::erythrocytes","assess":true},{"id":"c36","dok":3,"q":"A hemoglobin molecule is described as holding oxidized iron in the Fe3+ state so it cannot carry oxygen. Name this form.","a":"Methemoglobin.","options":["Methemoglobin","Oxyhemoglobin","Carboxyhemoglobin","Deoxyhemoglobin"],"correctIndex":0,"explanation":"Fe3+ iron that cannot carry oxygen defines methemoglobin. Oxyhemoglobin and deoxyhemoglobin keep Fe2+, and carboxyhemoglobin is bound to carbon monoxide while its iron stays Fe2+.","tags":["blood","hemoglobin"],"gid":"g477","unit":"m-blood","comp":"m-blood::hemoglobin","assess":true},{"id":"c37","dok":3,"q":"A protein is described as carrying iron through the plasma toward developing red cells in the marrow. Name it, and contrast it with the protein that stores that iron.","a":"Transferrin transports the iron; ferritin stores it.","options":["Transferrin transports, ferritin stores","Ferritin transports, transferrin stores","Albumin transports, hemoglobin stores","Hemoglobin transports, albumin stores"],"correctIndex":0,"explanation":"Transferrin carries iron in plasma while ferritin stores it in tissues. Reversing the two is wrong. Albumin is a general carrier and hemoglobin holds iron inside red cells, so neither of those pairings describes plasma iron transport and storage.","tags":["blood","rbc-lifecycle"],"gid":"g478","unit":"m-blood","comp":"m-blood::rbc-lifecycle","assess":true},{"id":"c38","dok":3,"q":"A hemoglobin molecule is described as four polypeptide subunits, two alpha and two beta, each cradling a heme group with one Fe2+ ion. How many oxygen molecules can it carry at full saturation?","a":"Four, one per heme.","options":["Four","Two","One","Eight"],"correctIndex":0,"explanation":"Four heme groups mean four oxygen-binding sites, so four oxygen molecules at full saturation. Two, one, and eight do not match the four-heme quaternary structure.","tags":["blood","hemoglobin"],"gid":"g479","unit":"m-blood","comp":"m-blood::hemoglobin","assess":true},{"id":"c1","dok":1,"q":"What is the general name for the process that forms all blood cells?","a":"Hematopoiesis.","tags":["blood","hematopoiesis"],"options":["Hematopoiesis","Erythropoiesis","Hemostasis","Phagocytosis"],"correctIndex":0,"explanation":"Hematopoiesis is the formation of all blood cells. Erythropoiesis is red-cell formation specifically. Hemostasis stops bleeding, and phagocytosis is cellular engulfment.","gid":"g480","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c2","dok":1,"q":"Where does hematopoiesis occur in an adult?","a":"In red bone marrow.","tags":["blood","hematopoiesis"],"options":["In red bone marrow","In yellow bone marrow","In the spleen","In the liver"],"correctIndex":0,"explanation":"Adult hematopoiesis occurs in red bone marrow. Yellow marrow is largely fat, and the spleen and liver break down old red cells rather than forming blood cells.","gid":"g481","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c3","dok":1,"q":"What is the name of the pluripotent stem cell from which every formed element arises?","a":"The hemocytoblast.","rubric":["The hemocytoblast"],"tags":["blood","hematopoiesis"],"gid":"g482","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c4","dok":2,"q":"The hemocytoblast divides into which two committed stem cell lines?","a":"The myeloid stem cell and the lymphoid stem cell.","rubric":["Myeloid stem cell","Lymphoid stem cell"],"tags":["blood","hematopoiesis"],"gid":"g483","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c5","dok":1,"q":"Which stem cell line gives rise to the lymphocytes?","a":"The lymphoid stem cell.","rubric":["The lymphoid stem cell"],"tags":["blood","hematopoiesis"],"gid":"g484","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c6","dok":2,"q":"The myeloid stem cell gives rise to every formed element except which one?","a":"The lymphocyte.","options":["The lymphocyte","The erythrocyte","The platelet","The neutrophil"],"correctIndex":0,"explanation":"The myeloid line produces erythrocytes, platelets, and all leukocytes except lymphocytes. Erythrocytes, platelets, and neutrophils are all myeloid products, so the exception is the lymphocyte, which comes from the lymphoid line.","tags":["blood","hematopoiesis"],"gid":"g485","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c7","dok":2,"q":"Name the four myeloid lineages that branch from the myeloid stem cell.","a":"The erythroid, granulocyte, monocyte, and megakaryocyte lineages.","rubric":["Erythroid","Granulocyte","Monocyte","Megakaryocyte"],"tags":["blood","hematopoiesis"],"gid":"g486","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c8","dok":1,"q":"What is the specific name for the formation of red blood cells?","a":"Erythropoiesis.","tags":["blood","hematopoiesis"],"options":["Erythropoiesis","Leukopoiesis","Thrombopoiesis","Hematopoiesis"],"correctIndex":0,"explanation":"Erythropoiesis is red-cell formation. Leukopoiesis forms white cells, thrombopoiesis forms platelets, and hematopoiesis is the general term.","gid":"g487","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c9","dok":1,"q":"In erythropoiesis, which committed cell comes immediately after the myeloid stem cell?","a":"The proerythroblast.","rubric":["The proerythroblast"],"tags":["blood","hematopoiesis"],"gid":"g488","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c10","dok":2,"q":"List the erythropoiesis stages in order from hemocytoblast to mature red cell.","a":"Hemocytoblast, myeloid stem cell, proerythroblast, erythroblast, normoblast, reticulocyte, erythrocyte.","rubric":["Hemocytoblast","Myeloid stem cell","Proerythroblast","Erythroblast","Normoblast","Reticulocyte, then erythrocyte"],"tags":["blood","hematopoiesis"],"gid":"g489","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c11","dok":2,"q":"At which erythropoiesis stage is the nucleus ejected as hemoglobin accumulates?","a":"The normoblast stage.","options":["The normoblast","The proerythroblast","The reticulocyte","The hemocytoblast"],"correctIndex":0,"explanation":"The normoblast ejects its nucleus as hemoglobin fills the cell. The proerythroblast is earlier and still nucleated. The reticulocyte follows nucleus loss, and the hemocytoblast is the founding stem cell.","tags":["blood","hematopoiesis"],"gid":"g490","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c12","dok":1,"q":"What is the last immature stage before a fully mature erythrocyte?","a":"The reticulocyte.","rubric":["The reticulocyte"],"tags":["blood","hematopoiesis"],"gid":"g491","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c13","dok":1,"q":"What structural remnant remains inside a reticulocyte that a mature erythrocyte lacks?","a":"Ribosome remnants (giving a blue-gray, polychromatophilic cytoplasm).","rubric":["Ribosome remnants","Blue-gray (polychromatophilic) cytoplasm"],"tags":["blood","hematopoiesis"],"gid":"g492","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c14","dok":2,"q":"What percentage of circulating red blood cells are normally reticulocytes?","a":"About 1 to 2 percent.","rubric":["About 1 to 2 percent"],"tags":["blood","values"],"gid":"g493","unit":"m-blood","comp":"m-blood::values"},{"id":"c15","dok":2,"q":"Which erythropoiesis stage is the first that has fully ejected its nucleus?","a":"The reticulocyte.","options":["The reticulocyte","The normoblast","The proerythroblast","The erythroblast"],"correctIndex":0,"explanation":"The reticulocyte is the first stage after nucleus ejection, which happens at the normoblast stage. The normoblast is the stage doing the ejecting, and the proerythroblast and erythroblast are earlier nucleated stages.","tags":["blood","hematopoiesis"],"gid":"g494","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c16","dok":2,"q":"Which erythropoiesis stage comes directly between the proerythroblast and the normoblast?","a":"The erythroblast.","options":["The erythroblast","The reticulocyte","The hemocytoblast","The megakaryoblast"],"correctIndex":0,"explanation":"The erythroblast, in early, intermediate, and late forms, sits between the proerythroblast and the normoblast. The reticulocyte comes later, the hemocytoblast comes earlier, and the megakaryoblast is on the platelet line.","tags":["blood","hematopoiesis"],"gid":"g495","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c17","dok":2,"q":"The hormone that stimulates red blood cell production is named erythropoietin. Which organ is its main source?","a":"The kidney.","rubric":["The kidney"],"tags":["blood","hematopoiesis"],"gid":"g496","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c18","dok":1,"q":"Which marrow cell is the committed precursor that develops into platelets?","a":"The megakaryoblast (leading to the megakaryocyte).","rubric":["Megakaryoblast (to megakaryocyte)"],"tags":["blood","hematopoiesis"],"gid":"g497","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c19","dok":1,"q":"Which blast cell of the myeloid line develops into granulocytes?","a":"The myeloblast.","rubric":["The myeloblast"],"tags":["blood","hematopoiesis"],"gid":"g498","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c20","dok":1,"q":"Which blast cell develops into monocytes?","a":"The monoblast.","rubric":["The monoblast"],"tags":["blood","hematopoiesis"],"gid":"g499","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c21","dok":2,"q":"From which stem cell line does the lymphoblast, and therefore the B, T, and NK cells, arise?","a":"The lymphoid stem cell line.","options":["The lymphoid stem cell line","The myeloid stem cell line","The erythroid line","The megakaryocyte line"],"correctIndex":0,"explanation":"The lymphoblast and its B, T, and NK cell products arise from the lymphoid line. The myeloid, erythroid, and megakaryocyte lines produce the other formed elements, not lymphocytes.","tags":["blood","hematopoiesis"],"gid":"g500","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c22","dok":2,"q":"Which formed elements share the myeloid stem cell as a common ancestor?","a":"Erythrocytes, platelets, granulocytes, and monocytes (all but lymphocytes).","rubric":["Erythrocytes","Platelets","Granulocytes","Monocytes"],"tags":["blood","hematopoiesis"],"gid":"g501","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c23","dok":2,"q":"In the hierarchy, which cell is more primitive: the hemocytoblast or the myeloid stem cell?","a":"The hemocytoblast is more primitive; the myeloid stem cell descends from it.","options":["The hemocytoblast","The myeloid stem cell","They are the same cell","The reticulocyte"],"correctIndex":0,"explanation":"The hemocytoblast is the pluripotent ancestor; the myeloid stem cell is one of its committed descendants. They are not the same cell, and the reticulocyte is a late red-cell stage, not a stem cell.","tags":["blood","hematopoiesis"],"gid":"g502","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c24","dok":2,"q":"Place these three erythropoiesis stages in correct order: normoblast, proerythroblast, reticulocyte.","a":"Proerythroblast, then normoblast, then reticulocyte.","options":["Proerythroblast, normoblast, reticulocyte","Reticulocyte, normoblast, proerythroblast","Normoblast, proerythroblast, reticulocyte","Proerythroblast, reticulocyte, normoblast"],"correctIndex":0,"explanation":"The correct order is proerythroblast, then normoblast, then reticulocyte. Any order that puts the reticulocyte before the normoblast, or the normoblast before the proerythroblast, reverses the developmental sequence.","tags":["blood","hematopoiesis"],"gid":"g503","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c25","dok":2,"q":"Both the erythroid and granulocyte lineages branch from which shared stem cell?","a":"The myeloid stem cell.","options":["The myeloid stem cell","The lymphoid stem cell","The megakaryoblast","The proerythroblast"],"correctIndex":0,"explanation":"Both the erythroid and granulocyte lineages branch from the myeloid stem cell. The lymphoid stem cell yields lymphocytes only. The megakaryoblast and proerythroblast are downstream committed cells, not the shared branch point.","tags":["blood","hematopoiesis"],"gid":"g504","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c26","dok":3,"q":"A cell is described as the pluripotent stem cell in red bone marrow that can give rise to any formed element. Name it.","a":"The hemocytoblast.","options":["The hemocytoblast","The myeloid stem cell","The proerythroblast","The reticulocyte"],"correctIndex":0,"explanation":"A pluripotent marrow stem cell giving rise to any formed element is the hemocytoblast. The myeloid stem cell is already committed away from lymphocytes, the proerythroblast is committed to red cells, and the reticulocyte is a near-mature red cell.","tags":["blood","hematopoiesis"],"gid":"g505","unit":"m-blood","comp":"m-blood::hematopoiesis","assess":true},{"id":"c27","dok":3,"q":"A red-cell precursor is described as still having ribosome remnants and a blue-gray cytoplasm, but no nucleus, and it is the stage just before maturity. Name it.","a":"The reticulocyte.","options":["The reticulocyte","The normoblast","The proerythroblast","The erythroblast"],"correctIndex":0,"explanation":"A nucleus-free stage with ribosome remnants and blue-gray cytoplasm just before maturity is the reticulocyte. The normoblast still has or is ejecting its nucleus, and the proerythroblast and erythroblast are earlier nucleated stages.","tags":["blood","hematopoiesis"],"gid":"g506","unit":"m-blood","comp":"m-blood::hematopoiesis","assess":true},{"id":"c28","dok":3,"q":"A student must place a cell one step below the hemocytoblast that still cannot become a lymphocyte. Which cell fits?","a":"The myeloid stem cell.","options":["The myeloid stem cell","The lymphoid stem cell","The proerythroblast","The reticulocyte"],"correctIndex":0,"explanation":"One step below the hemocytoblast and unable to form lymphocytes is the myeloid stem cell. The lymphoid stem cell is the one that does form lymphocytes. The proerythroblast and reticulocyte are further down the red-cell line.","tags":["blood","hematopoiesis"],"gid":"g507","unit":"m-blood","comp":"m-blood::hematopoiesis","assess":true},{"id":"c29","dok":3,"q":"A student is told a red-cell stage has already ejected its nucleus and packed itself with hemoglobin but has NOT yet lost its ribosome remnants. Name the stage.","a":"The reticulocyte.","options":["The reticulocyte","The normoblast","The erythrocyte","The proerythroblast"],"correctIndex":0,"explanation":"A stage without a nucleus but still holding ribosome remnants is the reticulocyte. The normoblast is the stage that ejects the nucleus. A mature erythrocyte has lost the ribosome remnants, and the proerythroblast is still nucleated.","tags":["blood","hematopoiesis"],"gid":"g508","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c30","dok":3,"q":"Name the developmental process for white blood cells and for platelets.","a":"Leukopoiesis for white cells; thrombopoiesis for platelets.","rubric":["Leukopoiesis (white cells)","Thrombopoiesis (platelets)"],"tags":["blood","hematopoiesis"],"gid":"g509","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c31","dok":2,"q":"Which formed element line does NOT descend from the myeloid stem cell?","a":"The lymphocyte line.","options":["The lymphocyte line","The erythroid line","The megakaryocyte line","The granulocyte line"],"correctIndex":0,"explanation":"The lymphocyte line descends from the lymphoid stem cell, not the myeloid stem cell. The erythroid, megakaryocyte, and granulocyte lines all descend from the myeloid stem cell.","tags":["blood","hematopoiesis"],"gid":"g510","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c32","dok":1,"q":"Which cell in thrombopoiesis is the large polyploid cell whose cytoplasm fragments into platelets?","a":"The megakaryocyte.","options":["The megakaryocyte","The megakaryoblast","The monocyte","The reticulocyte"],"correctIndex":0,"explanation":"The megakaryocyte is the large polyploid cell that fragments into platelets. The megakaryoblast is its earlier precursor, the monocyte is a mature leukocyte, and the reticulocyte is a red-cell stage.","tags":["blood","hematopoiesis"],"gid":"g511","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c33","dok":2,"q":"A reticulocyte count that is elevated most directly reflects what marrow activity?","a":"Active erythropoiesis (increased red cell production).","options":["Active erythropoiesis","Marrow suppression","Increased plasma volume","Increased iron storage"],"correctIndex":0,"explanation":"A high reticulocyte count reflects active erythropoiesis. Marrow suppression would lower reticulocytes. Plasma volume and iron storage are not what the reticulocyte fraction directly reports.","tags":["blood","hematopoiesis"],"gid":"g512","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c34","dok":3,"q":"Which two lineages does the hematopoietic hierarchy split into at the very top, just below the hemocytoblast?","a":"The myeloid line and the lymphoid line.","options":["Myeloid and lymphoid","Erythroid and granulocyte","Granulocyte and monocyte","B cell and T cell"],"correctIndex":0,"explanation":"Just below the hemocytoblast, the hierarchy splits into the myeloid and lymphoid lines. Erythroid, granulocyte, and monocyte lines are sublines of the myeloid line, and B and T cells are downstream of the lymphoid line.","tags":["blood","hematopoiesis"],"gid":"g513","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c35","dok":3,"q":"Match the blast to its product: myeloblast, monoblast, megakaryoblast. Which set is correct?","a":"Myeloblast to granulocytes, monoblast to monocytes, megakaryoblast to platelets.","options":["Myeloblast to granulocytes, monoblast to monocytes, megakaryoblast to platelets","Myeloblast to monocytes, monoblast to platelets, megakaryoblast to granulocytes","Myeloblast to platelets, monoblast to granulocytes, megakaryoblast to monocytes","All three form lymphocytes"],"correctIndex":0,"explanation":"The myeloblast forms granulocytes, the monoblast forms monocytes, and the megakaryoblast forms platelets. The scrambled pairings misassign each blast, and none of these blasts forms lymphocytes, which come from the lymphoblast.","tags":["blood","hematopoiesis"],"gid":"g514","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c36","dok":3,"q":"A student traces a neutrophil back through its ancestry. Which sequence of ancestors is correct?","a":"Hemocytoblast, then myeloid stem cell, then myeloblast, then neutrophil.","options":["Hemocytoblast, myeloid stem cell, myeloblast, neutrophil","Hemocytoblast, lymphoid stem cell, myeloblast, neutrophil","Hemocytoblast, myeloid stem cell, proerythroblast, neutrophil","Hemocytoblast, lymphoblast, myeloblast, neutrophil"],"correctIndex":0,"explanation":"A neutrophil traces from hemocytoblast to myeloid stem cell to myeloblast to neutrophil. A neutrophil does not come from the lymphoid line or lymphoblast, and the proerythroblast is on the red-cell line, not the granulocyte line.","tags":["blood","hematopoiesis"],"gid":"g515","unit":"m-blood","comp":"m-blood::hematopoiesis"},{"id":"c1","dok":1,"q":"The two structural classes of leukocytes are based on what feature?","a":"The presence or absence of visible cytoplasmic granules (granulocytes versus agranulocytes).","rubric":["Presence or absence of cytoplasmic granules","Granulocytes versus agranulocytes"],"tags":["blood","granulocytes"],"gid":"g516","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c2","dok":1,"q":"To which class do neutrophils, eosinophils, and basophils belong?","a":"The granulocytes.","rubric":["The granulocytes"],"tags":["blood","granulocytes"],"gid":"g517","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c3","dok":1,"q":"Which two leukocytes are classified as agranulocytes?","a":"Lymphocytes and monocytes.","options":["Lymphocytes and monocytes","Neutrophils and basophils","Eosinophils and basophils","Neutrophils and eosinophils"],"correctIndex":0,"explanation":"Lymphocytes and monocytes lack visible granules, making them agranulocytes. Any pairing of neutrophils, eosinophils, or basophils names granulocytes instead.","tags":["blood","agranulocytes"],"gid":"g518","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c4","dok":1,"q":"Which leukocyte is the most numerous, at about 60 to 70 percent?","a":"The neutrophil.","tags":["blood","granulocytes"],"options":["The neutrophil","The lymphocyte","The monocyte","The eosinophil"],"correctIndex":0,"explanation":"Neutrophils are the most numerous leukocyte at 60 to 70 percent. Lymphocytes are next at 20 to 30 percent, and monocytes and eosinophils are far less numerous.","gid":"g519","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c5","dok":1,"q":"What is the approximate percentage of circulating leukocytes that are neutrophils?","a":"About 60 to 70 percent.","rubric":["About 60 to 70 percent"],"tags":["blood","granulocytes"],"gid":"g520","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c6","dok":2,"q":"What is the characteristic nuclear shape of a neutrophil?","a":"A nucleus with 3 to 5 lobes connected by thin strands.","options":["3 to 5 lobes connected by thin strands","A single round nucleus","A bilobed nucleus","A kidney-shaped nucleus"],"correctIndex":0,"explanation":"The neutrophil has a 3 to 5 lobed nucleus. A single round nucleus fits a lymphocyte, a bilobed nucleus fits an eosinophil, and a kidney-shaped nucleus fits a monocyte.","tags":["blood","granulocytes"],"gid":"g521","unit":"m-blood","comp":"m-blood::granulocytes","assess":true},{"id":"c7","dok":1,"q":"Because of its multi-lobed nucleus, the neutrophil is also called what?","a":"A polymorphonuclear cell.","rubric":["A polymorphonuclear cell"],"tags":["blood","granulocytes"],"gid":"g522","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c8","dok":1,"q":"What is the approximate percentage of circulating leukocytes that are eosinophils?","a":"About 2 to 4 percent.","options":["About 2 to 4 percent","About 60 to 70 percent","About 20 to 30 percent","About 2 to 8 percent"],"correctIndex":0,"explanation":"Eosinophils are about 2 to 4 percent of leukocytes. About 60 to 70 percent is neutrophils, 20 to 30 percent is lymphocytes, and 2 to 8 percent is monocytes.","tags":["blood","granulocytes"],"gid":"g523","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c9","dok":1,"q":"What is the characteristic nuclear shape of an eosinophil?","a":"A bilobed (two-lobed) nucleus.","rubric":["A bilobed (two-lobed) nucleus"],"tags":["blood","granulocytes"],"gid":"g524","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c10","dok":1,"q":"The eosinophil is known for large crystalline granules containing which named protein?","a":"Major basic protein (also eosinophil cationic protein and eosinophil peroxidase).","rubric":["Major basic protein","Eosinophil cationic protein","Eosinophil peroxidase"],"tags":["blood","granulocytes"],"gid":"g525","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c11","dok":2,"q":"Which leukocyte is the rarest, at less than 1 percent?","a":"The basophil.","tags":["blood","granulocytes"],"options":["The basophil","The eosinophil","The monocyte","The lymphocyte"],"correctIndex":0,"explanation":"Basophils are the rarest leukocyte at less than 1 percent. Eosinophils are about 2 to 4 percent, monocytes 2 to 8 percent, and lymphocytes 20 to 30 percent.","gid":"g526","unit":"m-blood","comp":"m-blood::granulocytes","assess":true},{"id":"c12","dok":2,"q":"Which two substances are found in the granules of a basophil?","a":"Histamine and heparin (also leukotrienes).","options":["Histamine and heparin","Major basic protein","Perforin and granzymes","Myeloperoxidase and defensins"],"correctIndex":0,"explanation":"Basophil granules contain histamine and heparin. Major basic protein is in eosinophils, perforin and granzymes are in NK and cytotoxic T cells, and myeloperoxidase and defensins are in neutrophil granules.","tags":["blood","granulocytes"],"gid":"g527","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c13","dok":2,"q":"In a basophil, the nucleus is often difficult to see. Why?","a":"It is obscured by the large, dark-staining granules.","options":["It is obscured by large dark granules","It has been ejected","It is very small and pale","It is bilobed and hidden by hemoglobin"],"correctIndex":0,"explanation":"The basophil nucleus is hidden by large dark granules. It is not ejected, since basophils are complete nucleated cells. It is not simply pale, and hemoglobin is a red-cell pigment, not a basophil feature.","tags":["blood","granulocytes"],"gid":"g528","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c14","dok":2,"q":"Which tissue-resident cell is structurally similar to the circulating basophil?","a":"The mast cell.","rubric":["The mast cell"],"tags":["blood","granulocytes"],"gid":"g529","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c15","dok":1,"q":"What is the approximate percentage of circulating leukocytes that are lymphocytes?","a":"About 20 to 30 percent.","rubric":["About 20 to 30 percent"],"tags":["blood","agranulocytes"],"gid":"g530","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c16","dok":1,"q":"What is the characteristic appearance of a lymphocyte's nucleus?","a":"A large round nucleus that fills almost the whole cell, leaving a thin rim of cytoplasm.","options":["A large round nucleus filling most of the cell","A 3 to 5 lobed nucleus","A bilobed nucleus","A kidney-shaped nucleus"],"correctIndex":0,"explanation":"The lymphocyte has a large round nucleus filling most of the cell. A 3 to 5 lobed nucleus fits a neutrophil, a bilobed nucleus fits an eosinophil, and a kidney-shaped nucleus fits a monocyte.","tags":["blood","agranulocytes"],"gid":"g531","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c17","dok":2,"q":"Name the three lymphocyte subtypes.","a":"B lymphocytes, T lymphocytes, and natural killer (NK) cells.","rubric":["B lymphocytes","T lymphocytes","Natural killer (NK) cells"],"tags":["blood","agranulocytes"],"gid":"g532","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c18","dok":1,"q":"When a B lymphocyte is activated, into what cell does it differentiate?","a":"A plasma cell.","options":["A plasma cell","A macrophage","A mast cell","A megakaryocyte"],"correctIndex":0,"explanation":"An activated B lymphocyte becomes a plasma cell. A macrophage comes from a monocyte, a mast cell is the tissue counterpart of a basophil, and a megakaryocyte is a platelet-forming marrow cell.","tags":["blood","agranulocytes"],"gid":"g533","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c19","dok":2,"q":"Which lymphocyte subtype uses perforin and granzymes stored in cytotoxic granules?","a":"Natural killer (NK) cells (and cytotoxic T cells).","options":["NK cells","B lymphocytes","Plasma cells","Monocytes"],"correctIndex":0,"explanation":"NK cells hold perforin and granzymes in cytotoxic granules. B lymphocytes and plasma cells produce antibodies rather than these cytotoxic granules, and monocytes are phagocytes, not granule-based killers of this type.","tags":["blood","agranulocytes"],"gid":"g534","unit":"m-blood","comp":"m-blood::agranulocytes","assess":true},{"id":"c20","dok":1,"q":"What is the approximate percentage of circulating leukocytes that are monocytes?","a":"About 2 to 8 percent.","rubric":["About 2 to 8 percent"],"tags":["blood","agranulocytes"],"gid":"g535","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c21","dok":2,"q":"What is the characteristic nuclear shape of a monocyte?","a":"A kidney-shaped (indented) nucleus.","rubric":["A kidney-shaped (indented) nucleus"],"tags":["blood","agranulocytes"],"gid":"g536","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c22","dok":1,"q":"Which leukocyte is the largest of the five?","a":"The monocyte.","tags":["blood","agranulocytes"],"options":["The monocyte","The lymphocyte","The neutrophil","The basophil"],"correctIndex":0,"explanation":"The monocyte is the largest leukocyte. The lymphocyte, neutrophil, and basophil are all smaller.","gid":"g537","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c23","dok":1,"q":"When a monocyte leaves the blood and enters tissue, into what cell does it mature?","a":"A macrophage.","rubric":["A macrophage"],"tags":["blood","agranulocytes"],"gid":"g538","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c24","dok":3,"q":"List the five leukocytes from most numerous to least numerous.","a":"Neutrophils, lymphocytes, monocytes, eosinophils, basophils.","rubric":["Neutrophils","Lymphocytes","Monocytes","Eosinophils","Basophils"],"tags":["blood","granulocytes"],"gid":"g539","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c25","dok":2,"q":"A leukocyte has fine pale granules and a 3 to 5 lobed nucleus and is the most numerous white cell. Which is it?","a":"The neutrophil.","options":["The neutrophil","The eosinophil","The basophil","The monocyte"],"correctIndex":0,"explanation":"Fine pale granules with a 3 to 5 lobed nucleus, plus being most numerous, identify the neutrophil. The eosinophil has coarse red-orange granules, the basophil has large dark granules, and the monocyte is an agranulocyte.","tags":["blood","granulocytes"],"gid":"g540","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c26","dok":2,"q":"A granulocyte has a bilobed nucleus and coarse red-orange granules with major basic protein. Which is it?","a":"The eosinophil.","options":["The eosinophil","The neutrophil","The basophil","The monocyte"],"correctIndex":0,"explanation":"A bilobed nucleus with coarse red-orange granules and major basic protein identifies the eosinophil. The neutrophil has a multi-lobed nucleus and pale granules, the basophil has dark granules, and the monocyte has no visible granules.","tags":["blood","granulocytes"],"gid":"g541","unit":"m-blood","comp":"m-blood::granulocytes"},{"id":"c27","dok":3,"q":"Which structural feature separates a lymphocyte from a monocyte on a smear?","a":"The lymphocyte has a large round nucleus with little cytoplasm; the monocyte is larger with an indented kidney-shaped nucleus.","rubric":["Lymphocyte: large round nucleus, little cytoplasm","Monocyte: larger, indented kidney-shaped nucleus"],"tags":["blood","agranulocytes"],"gid":"g542","unit":"m-blood","comp":"m-blood::agranulocytes"},{"id":"c28","dok":1,"q":"What is a platelet, in structural terms?","a":"A membrane-bound fragment of a megakaryocyte, not a complete cell.","options":["A fragment of a megakaryocyte","A complete nucleated cell","An immature red cell","A type of granulocyte"],"correctIndex":0,"explanation":"A platelet is a cytoplasmic fragment of a megakaryocyte. It is not a complete nucleated cell, not an immature red cell (a reticulocyte), and not a granulocyte.","tags":["blood","platelets"],"gid":"g543","unit":"m-blood","comp":"m-blood::platelets"},{"id":"c29","dok":1,"q":"From which giant marrow cell do platelets form?","a":"The megakaryocyte.","options":["The megakaryocyte","The hemocytoblast","The reticulocyte","The monocyte"],"correctIndex":0,"explanation":"Platelets form from the megakaryocyte by cytoplasmic fragmentation. The hemocytoblast is the founding stem cell, the reticulocyte is an immature red cell, and the monocyte is a leukocyte.","tags":["blood","platelets"],"gid":"g544","unit":"m-blood","comp":"m-blood::platelets"},{"id":"c30","dok":1,"q":"What is the approximate diameter of a platelet?","a":"About 2 to 4 um.","rubric":["About 2 to 4 um"],"tags":["blood","platelets"],"gid":"g545","unit":"m-blood","comp":"m-blood::platelets"},{"id":"c31","dok":1,"q":"What is the normal platelet count?","a":"About 150,000 to 400,000 per uL.","rubric":["About 150,000 to 400,000 per uL"],"tags":["blood","values"],"gid":"g546","unit":"m-blood","comp":"m-blood::values"},{"id":"c32","dok":2,"q":"Name the two types of platelet granules.","a":"Alpha granules and dense granules.","rubric":["Alpha granules","Dense granules"],"tags":["blood","platelets"],"gid":"g547","unit":"m-blood","comp":"m-blood::platelets"},{"id":"c33","dok":2,"q":"Which platelet granule type contains fibrinogen, von Willebrand factor, and platelet-derived growth factor?","a":"The alpha granules.","options":["The alpha granules","The dense granules","The primary neutrophil granules","The lysosomal granules"],"correctIndex":0,"explanation":"Alpha granules hold fibrinogen, von Willebrand factor, and PDGF. Dense granules hold ADP, ATP, serotonin, and calcium. Neutrophil primary granules and lysosomal granules belong to other cells.","tags":["blood","platelets"],"gid":"g548","unit":"m-blood","comp":"m-blood::platelets","assess":true},{"id":"c34","dok":2,"q":"Which platelet granule type contains ADP, ATP, serotonin, and calcium?","a":"The dense granules.","options":["The dense granules","The alpha granules","The specific granules","The azurophilic granules"],"correctIndex":0,"explanation":"Dense granules hold ADP, ATP, serotonin, and calcium. Alpha granules hold fibrinogen and von Willebrand factor. Specific and azurophilic granules are neutrophil features, not platelet granules.","tags":["blood","platelets"],"gid":"g549","unit":"m-blood","comp":"m-blood::platelets","assess":true},{"id":"c35","dok":2,"q":"What is the normal total leukocyte (WBC) count?","a":"About 4,000 to 11,000 per uL.","rubric":["About 4,000 to 11,000 per uL"],"tags":["blood","values"],"gid":"g550","unit":"m-blood","comp":"m-blood::values"},{"id":"c36","dok":3,"q":"A white cell has a lobed nucleus almost hidden by large dark granules of histamine and heparin, and it is the rarest leukocyte. Name it.","a":"The basophil.","options":["The basophil","The eosinophil","The neutrophil","The monocyte"],"correctIndex":0,"explanation":"Large dark histamine-and-heparin granules hiding the nucleus, plus rarity, identify the basophil. The eosinophil has coarse red-orange granules, the neutrophil has pale granules, and the monocyte is an agranulocyte.","tags":["blood","granulocytes"],"gid":"g551","unit":"m-blood","comp":"m-blood::granulocytes","assess":true},{"id":"c37","dok":3,"q":"A student is asked to name the leukocyte that is the largest, is an agranulocyte with a kidney-shaped nucleus, and matures into a macrophage. Name it.","a":"The monocyte.","options":["The monocyte","The lymphocyte","The neutrophil","The eosinophil"],"correctIndex":0,"explanation":"The largest agranulocyte with a kidney-shaped nucleus that becomes a macrophage is the monocyte. The lymphocyte is a smaller agranulocyte with a round nucleus, and the neutrophil and eosinophil are granulocytes.","tags":["blood","agranulocytes"],"gid":"g552","unit":"m-blood","comp":"m-blood::agranulocytes","assess":true},{"id":"c38","dok":3,"q":"A formed element is a small membrane-bound fragment, 2 to 4 um, budded from a megakaryocyte, holding alpha and dense granules, with a normal count of 150,000 to 400,000 per uL. Name it.","a":"The platelet.","options":["The platelet","The erythrocyte","The neutrophil","The reticulocyte"],"correctIndex":0,"explanation":"A 2 to 4 um fragment from a megakaryocyte with alpha and dense granules is a platelet. An erythrocyte is a whole biconcave cell, a neutrophil is a nucleated granulocyte, and a reticulocyte is an immature red cell.","tags":["blood","platelets"],"gid":"g553","unit":"m-blood","comp":"m-blood::platelets","assess":true},{"id":"c39","dok":3,"q":"Using the mnemonic order most to least numerous, which leukocyte sits in the middle position of the five?","a":"The monocyte.","options":["The monocyte","The neutrophil","The basophil","The lymphocyte"],"correctIndex":0,"explanation":"In the order neutrophils, lymphocytes, monocytes, eosinophils, basophils, the middle position is the monocyte. The neutrophil and lymphocyte are ahead of it, and the basophil is last, so none of those is the middle cell.","tags":["blood","agranulocytes"],"gid":"g554","unit":"m-blood","comp":"m-blood::agranulocytes","assess":true},{"id":"c1","dok":1,"q":"The ABO blood group is defined by antigens located where?","a":"On the surface of the erythrocytes.","rubric":["On the erythrocyte surface"],"tags":["blood","blood-groups"],"gid":"g555","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c2","dok":2,"q":"What is another name for the surface antigens of the ABO system?","a":"Agglutinogens.","options":["Agglutinogens","Agglutinins","Antibodies","Globulins"],"correctIndex":0,"explanation":"The ABO surface antigens are called agglutinogens. Agglutinins are the antibodies, not the antigens. Antibodies is the general term for agglutinins, and globulins are a plasma protein class.","tags":["blood","blood-groups"],"gid":"g556","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c3","dok":2,"q":"What is another name for the plasma antibodies of the ABO system?","a":"Agglutinins.","options":["Agglutinins","Agglutinogens","Antigens","Fibrinogen"],"correctIndex":0,"explanation":"The ABO antibodies are called agglutinins. Agglutinogens are the surface antigens, antigens is the general term for agglutinogens, and fibrinogen is a clotting protein.","tags":["blood","blood-groups"],"gid":"g557","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c4","dok":1,"q":"Which surface antigen(s) does a person with type A blood carry?","a":"The A antigen only.","tags":["blood","blood-groups"],"options":["The A antigen only","The B antigen only","Both A and B antigens","Neither antigen"],"correctIndex":0,"explanation":"Type A carries the A antigen only. The B antigen only is type B, both antigens is type AB, and neither antigen is type O.","gid":"g558","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c5","dok":1,"q":"Which surface antigens does a person with type AB blood carry?","a":"Both the A and B antigens.","rubric":["A antigen","B antigen"],"tags":["blood","blood-groups"],"gid":"g559","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c6","dok":1,"q":"Which surface antigens does a person with type O blood carry?","a":"Neither the A nor the B antigen.","options":["Neither A nor B","Both A and B","A only","B only"],"correctIndex":0,"explanation":"Type O carries neither antigen. Both antigens is type AB, A only is type A, and B only is type B.","tags":["blood","blood-groups"],"gid":"g560","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c7","dok":1,"q":"Which antibody is present in the plasma of a type A person?","a":"Anti-B antibody.","rubric":["Anti-B antibody"],"tags":["blood","blood-groups"],"gid":"g561","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c8","dok":1,"q":"Which antibody is present in the plasma of a type B person?","a":"Anti-A antibody.","options":["Anti-A antibody","Anti-B antibody","Both anti-A and anti-B","Neither antibody"],"correctIndex":0,"explanation":"Type B plasma carries anti-A antibody. Anti-B would attack the person's own B antigen. Both antibodies is type O, and neither antibody is type AB.","tags":["blood","blood-groups"],"gid":"g562","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c9","dok":1,"q":"Which antibodies are present in the plasma of a type O person?","a":"Both anti-A and anti-B antibodies.","options":["Both anti-A and anti-B","Anti-A only","Anti-B only","Neither antibody"],"correctIndex":0,"explanation":"Type O plasma carries both anti-A and anti-B antibodies. Anti-A only is type B, anti-B only is type A, and neither antibody is type AB.","tags":["blood","blood-groups"],"gid":"g563","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c10","dok":1,"q":"Which antibodies are present in the plasma of a type AB person?","a":"Neither anti-A nor anti-B antibodies.","options":["Neither antibody","Both antibodies","Anti-A only","Anti-B only"],"correctIndex":0,"explanation":"Type AB plasma carries neither antibody, since both antigens are self. Both antibodies is type O, anti-A only is type B, and anti-B only is type A.","tags":["blood","blood-groups"],"gid":"g564","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c11","dok":3,"q":"State the antibodies present in the plasma of each ABO type: A, B, AB, and O.","a":"Type A has anti-B; type B has anti-A; type AB has neither; type O has both anti-A and anti-B.","rubric":["Type A: anti-B","Type B: anti-A","Type AB: neither","Type O: anti-A and anti-B"],"tags":["blood","blood-groups"],"gid":"g565","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c12","dok":1,"q":"What molecule serves as the type A antigen?","a":"N-acetylgalactosamine.","rubric":["N-acetylgalactosamine"],"tags":["blood","blood-groups"],"gid":"g566","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c13","dok":1,"q":"What molecule serves as the type B antigen?","a":"Galactose.","rubric":["Galactose"],"tags":["blood","blood-groups"],"gid":"g567","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c14","dok":1,"q":"The Rh blood group is defined by the presence or absence of which antigen?","a":"The D antigen.","rubric":["The D antigen"],"tags":["blood","blood-groups"],"gid":"g568","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c15","dok":1,"q":"A person who is Rh positive has what, with respect to the D antigen?","a":"The D antigen is present on the erythrocytes.","options":["The D antigen is present","The D antigen is absent","Two D antigens replace A and B","The D antibody is present at birth"],"correctIndex":0,"explanation":"Rh positive means the D antigen is present. Rh negative is D absent. The D antigen does not replace A and B, and Rh antibodies are not naturally present at birth.","tags":["blood","blood-groups"],"gid":"g569","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c16","dok":2,"q":"Approximately what percentage of the population is Rh positive?","a":"About 85 percent.","options":["About 85 percent","About 15 percent","About 50 percent","About 4 percent"],"correctIndex":0,"explanation":"About 85 percent of people are Rh positive, leaving about 15 percent Rh negative. Fifty percent and 4 percent do not match the population split for the D antigen.","tags":["blood","blood-groups"],"gid":"g570","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c17","dok":2,"q":"How do Rh antibodies differ from ABO antibodies in when they appear?","a":"ABO antibodies develop naturally in infancy; Rh antibodies are not naturally occurring and require prior sensitization.","options":["Rh antibodies require prior sensitization; ABO antibodies form naturally","Both are present at birth","ABO antibodies require sensitization; Rh antibodies are natural","Neither type ever forms"],"correctIndex":0,"explanation":"ABO antibodies form naturally in infancy while Rh antibodies form only after sensitization. Neither is present at birth, the ABO and Rh roles are not reversed, and both types clearly can form.","tags":["blood","blood-groups"],"gid":"g571","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c18","dok":3,"q":"A blood sample has the A antigen on its red cells and anti-B antibody in its plasma. What ABO type is it?","a":"Type A.","options":["Type A","Type B","Type AB","Type O"],"correctIndex":0,"explanation":"The A antigen with anti-B antibody defines type A. Type B has the B antigen and anti-A. Type AB has both antigens and no antibody, and type O has neither antigen and both antibodies.","tags":["blood","blood-groups"],"gid":"g572","unit":"m-blood","comp":"m-blood::blood-groups","assess":true},{"id":"c19","dok":3,"q":"A blood sample has both anti-A and anti-B antibodies in the plasma and no A or B antigens on the red cells. What ABO type is it?","a":"Type O.","options":["Type O","Type A","Type B","Type AB"],"correctIndex":0,"explanation":"Both antibodies and no antigens define type O. Type A and type B each have one antigen and one antibody, and type AB has both antigens and no antibody.","tags":["blood","blood-groups"],"gid":"g573","unit":"m-blood","comp":"m-blood::blood-groups","assess":true},{"id":"c20","dok":3,"q":"A blood sample has both A and B antigens on the red cells and no anti-A or anti-B antibodies in the plasma. What ABO type is it?","a":"Type AB.","options":["Type AB","Type O","Type A","Type B"],"correctIndex":0,"explanation":"Both antigens and no antibodies define type AB. Type O has neither antigen and both antibodies, and types A and B each have one antigen and the opposing antibody.","tags":["blood","blood-groups"],"gid":"g574","unit":"m-blood","comp":"m-blood::blood-groups","assess":true},{"id":"c21","dok":3,"q":"A blood sample has the B antigen on its red cells and anti-A antibody in its plasma. What ABO type is it?","a":"Type B.","options":["Type B","Type A","Type AB","Type O"],"correctIndex":0,"explanation":"The B antigen with anti-A antibody defines type B. Type A has the A antigen and anti-B, type AB has both antigens and no antibody, and type O has neither antigen and both antibodies.","tags":["blood","blood-groups"],"gid":"g575","unit":"m-blood","comp":"m-blood::blood-groups"},{"id":"c22","dok":3,"q":"What is the structural definition of anemia?","a":"A decreased oxygen-carrying capacity of the blood, from too few red cells or too little hemoglobin.","rubric":["Decreased oxygen-carrying capacity","Too few red cells or too little hemoglobin"],"tags":["blood","disorders"],"gid":"g576","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c23","dok":2,"q":"Name the three morphological categories used to classify anemias.","a":"Microcytic, normocytic, and macrocytic.","rubric":["Microcytic","Normocytic","Macrocytic"],"tags":["blood","disorders"],"gid":"g577","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c24","dok":1,"q":"What does the term microcytic describe about the red cells?","a":"The red cells are abnormally small.","rubric":["Red cells abnormally small"],"tags":["blood","disorders"],"gid":"g578","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c25","dok":1,"q":"What does the term macrocytic describe about the red cells?","a":"The red cells are abnormally large.","rubric":["Red cells abnormally large"],"tags":["blood","disorders"],"gid":"g579","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c26","dok":2,"q":"Microcytic anemia (small red cells) is associated with which of these named conditions?","a":"Iron deficiency and thalassemia.","options":["Iron deficiency and thalassemia","B12 and folate deficiency","Acute hemorrhage only","Chronic disease only"],"correctIndex":0,"explanation":"Microcytic anemia is linked with iron deficiency and thalassemia. B12 and folate deficiency cause macrocytic anemia. Acute hemorrhage and chronic disease are typically normocytic.","tags":["blood","disorders"],"gid":"g580","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c27","dok":2,"q":"Macrocytic anemia (large red cells) is classically associated with a deficiency of which nutrients?","a":"Vitamin B12 and folate.","options":["B12 and folate","Iron","Vitamin C","Sodium"],"correctIndex":0,"explanation":"Macrocytic anemia is classically from B12 or folate deficiency. Iron deficiency causes microcytic anemia. Vitamin C and sodium are not the classic macrocytic causes.","tags":["blood","disorders"],"gid":"g581","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c28","dok":2,"q":"Normocytic anemia (normal-sized red cells) is associated with which situations?","a":"Chronic disease and blood loss.","options":["Chronic disease and blood loss","Iron deficiency","B12 deficiency","Folate deficiency"],"correctIndex":0,"explanation":"Normocytic anemia is linked with chronic disease and blood loss. Iron deficiency is microcytic, and B12 or folate deficiency is macrocytic.","tags":["blood","disorders"],"gid":"g582","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c29","dok":2,"q":"In sickle cell disease, which globin chain of hemoglobin carries the mutation?","a":"The beta-globin chain.","rubric":["The beta-globin chain"],"tags":["blood","disorders"],"gid":"g583","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c30","dok":2,"q":"The abnormal hemoglobin produced in sickle cell disease is given what name?","a":"Hemoglobin S (HbS).","rubric":["Hemoglobin S (HbS)"],"tags":["blood","disorders"],"gid":"g584","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c31","dok":2,"q":"What single amino acid substitution underlies sickle cell disease?","a":"Glutamic acid is replaced by valine in the beta-globin chain.","rubric":["Glutamic acid replaced by valine","In the beta-globin chain"],"tags":["blood","disorders"],"gid":"g585","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c32","dok":2,"q":"What structural change to erythrocytes gives sickle cell disease its name?","a":"The red cells take on a curved, sickle shape when hemoglobin S polymerizes on deoxygenation.","options":["The red cells become curved and sickle-shaped","The red cells become perfect spheres","The red cells lose all hemoglobin","The red cells gain a nucleus"],"correctIndex":0,"explanation":"Sickle cells become curved and crescent-shaped when HbS polymerizes. They do not become spheres, do not lose all hemoglobin, and mature red cells do not regain a nucleus.","tags":["blood","disorders"],"gid":"g586","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c33","dok":2,"q":"The lifespan of a sickled erythrocyte is shortened to approximately what?","a":"About 10 to 20 days (down from 120 days).","options":["About 10 to 20 days","About 120 days","About 60 days","About 1 year"],"correctIndex":0,"explanation":"Sickled cells last only about 10 to 20 days. About 120 days is the normal red-cell lifespan. Sixty days and one year do not match the shortened sickle-cell survival.","tags":["blood","disorders"],"gid":"g587","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c34","dok":1,"q":"What is the defining structural problem in the thalassemias?","a":"Reduced synthesis of a globin chain, causing imbalanced globin chains.","options":["Reduced globin chain synthesis","A single amino acid swap in beta-globin","Oxidized Fe3+ iron in heme","Too few heme groups per cell only"],"correctIndex":0,"explanation":"Thalassemias come from reduced synthesis of a globin chain, leaving chains imbalanced. A single amino acid swap in beta-globin defines sickle cell disease, oxidized Fe3+ defines methemoglobin, and the thalassemia defect is production, not a fixed heme count.","tags":["blood","disorders"],"gid":"g588","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c35","dok":1,"q":"In alpha-thalassemia, which globin chain is produced in reduced amounts?","a":"The alpha-globin chain.","rubric":["The alpha-globin chain"],"tags":["blood","disorders"],"gid":"g589","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c36","dok":1,"q":"In beta-thalassemia, which globin chain is produced in reduced amounts?","a":"The beta-globin chain.","rubric":["The beta-globin chain"],"tags":["blood","disorders"],"gid":"g590","unit":"m-blood","comp":"m-blood::disorders"},{"id":"c37","dok":3,"q":"A structural hemoglobin disorder is described as a single amino acid change in beta-globin that makes hemoglobin polymerize and distort red cells into a crescent shape. Name it.","a":"Sickle cell disease.","options":["Sickle cell disease","Beta-thalassemia","Iron-deficiency anemia","Methemoglobinemia"],"correctIndex":0,"explanation":"A single beta-globin amino acid change causing crescent-shaped cells is sickle cell disease. Beta-thalassemia is reduced beta-chain production, not a single amino acid swap. Iron-deficiency anemia and methemoglobinemia do not involve this sickling mutation.","tags":["blood","disorders"],"gid":"g591","unit":"m-blood","comp":"m-blood::disorders","assess":true},{"id":"c38","dok":3,"q":"A disorder is described as reduced production of the alpha-globin chain, leaving the globin chains imbalanced. Name it.","a":"Alpha-thalassemia.","options":["Alpha-thalassemia","Beta-thalassemia","Sickle cell disease","Macrocytic anemia"],"correctIndex":0,"explanation":"Reduced alpha-globin production is alpha-thalassemia. Beta-thalassemia reduces beta chains, sickle cell disease is a beta-chain amino acid swap, and macrocytic anemia is a size category, not a globin-synthesis defect.","tags":["blood","disorders"],"gid":"g592","unit":"m-blood","comp":"m-blood::disorders","assess":true},{"id":"c39","dok":3,"q":"A patient's red cells are described as abnormally large, and the cause is traced to a vitamin deficiency. Which morphological anemia category and which deficiency fit?","a":"Macrocytic anemia, from B12 or folate deficiency.","options":["Macrocytic anemia, B12 or folate deficiency","Microcytic anemia, iron deficiency","Normocytic anemia, blood loss","Macrocytic anemia, iron deficiency"],"correctIndex":0,"explanation":"Abnormally large cells from a vitamin deficiency is macrocytic anemia from B12 or folate. Microcytic anemia comes from iron deficiency with small cells, normocytic anemia comes from blood loss with normal cells, and iron deficiency does not cause macrocytosis.","tags":["blood","disorders"],"gid":"g593","unit":"m-blood","comp":"m-blood::disorders","assess":true},{"id":"c40","dok":3,"q":"A person's plasma will attack red cells carrying the B antigen but not those carrying only the A antigen. What ABO type is this person, and which antibody explains it?","a":"Type A, because type A plasma carries anti-B antibody.","options":["Type A, anti-B antibody","Type B, anti-A antibody","Type AB, no antibodies","Type O, both antibodies"],"correctIndex":0,"explanation":"Attacking B antigen but not A means the plasma holds anti-B, which is type A. Type B holds anti-A and would attack A antigen. Type AB holds no antibodies, and type O holds both and would attack A as well.","tags":["blood","blood-groups"],"gid":"g594","unit":"m-blood","comp":"m-blood::blood-groups"}]};
